import { Module, DynamicModule, Type } from '@nestjs/common';
import { ConfigModule, ConfigService } from '@nestjs/config';
import { ThrottlerModule, ThrottlerGuard } from '@nestjs/throttler';
import { APP_GUARD } from '@nestjs/core';
import { LoggerModule } from 'nestjs-pino';
import { buildLoggerConfig } from './config/logger.config';
import { CsrfGuard } from './common/guards/csrf.guard';
import { PrismaModule } from '@libs/database';
import { RedisModule } from '@libs/redis';
import { AuthModule } from './modules/auth/auth.module';
import { UsersModule } from './modules/users/users.module';
import { QuestionnaireModule } from './modules/questionnaire/questionnaire.module';
import { SessionModule } from './modules/session/session.module';
import { AdaptiveLogicModule } from './modules/adaptive-logic/adaptive-logic.module';
import { StandardsModule } from './modules/standards/standards.module';
import { AdminModule } from './modules/admin/admin.module';
import { DocumentGeneratorModule } from './modules/document-generator/document-generator.module';
import { ScoringEngineModule } from './modules/scoring-engine/scoring-engine.module';
import { HeatmapModule } from './modules/heatmap/heatmap.module';
import { NotificationModule } from './modules/notifications/notification.module';
import { PaymentModule } from './modules/payment/payment.module';
import { AdaptersModule } from './modules/adapters/adapters.module';
import { IdeaCaptureModule } from './modules/idea-capture/idea-capture.module';
import { AiGatewayModule } from './modules/ai-gateway/ai-gateway.module';
import { ChatEngineModule } from './modules/chat-engine/chat-engine.module';
import { FactExtractionModule } from './modules/fact-extraction/fact-extraction.module';
import { QualityScoringModule } from './modules/quality-scoring/quality-scoring.module';
import { HealthController } from './health.controller';
import configuration from './config/configuration';

/**
 * Conditionally load legacy modules behind feature flag.
 * Set ENABLE_LEGACY_MODULES=true to enable Evidence Registry, Decision Log, QPG, and Policy Pack.
 */
function getLegacyModules(): Array<Type | DynamicModule> {
  if (process.env.ENABLE_LEGACY_MODULES === 'true') {
    const {
      EvidenceRegistryModule,
    } = require('./modules/evidence-registry/evidence-registry.module');
    const { DecisionLogModule } = require('./modules/decision-log/decision-log.module');
    const { QpgModule } = require('./modules/qpg/qpg.module');
    const { PolicyPackModule } = require('./modules/policy-pack/policy-pack.module');

    return [EvidenceRegistryModule, DecisionLogModule, QpgModule, PolicyPackModule];
  }
  return [];
}

@Module({
  imports: [
    // Configuration
    ConfigModule.forRoot({
      isGlobal: true,
      load: [configuration],
      envFilePath: ['.env', '.env.local'],
    }),

    // Structured logging (Pino)
    LoggerModule.forRootAsync({
      inject: [ConfigService],
      useFactory: (config: ConfigService) => buildLoggerConfig(config),
    }),

    // Rate limiting
    ThrottlerModule.forRoot([
      {
        name: 'short',
        ttl: 1000,
        limit: 3,
      },
      {
        name: 'medium',
        ttl: 10000,
        limit: 20,
      },
      {
        name: 'long',
        ttl: 60000,
        limit: 100,
      },
    ]),

    // Database
    PrismaModule,

    // Cache
    RedisModule,

    // Core feature modules
    AuthModule,
    UsersModule,
    QuestionnaireModule,
    SessionModule,
    AdaptiveLogicModule,
    StandardsModule,
    AdminModule,
    DocumentGeneratorModule,
    ScoringEngineModule,
    HeatmapModule,
    NotificationModule,
    PaymentModule,
    AdaptersModule,
    IdeaCaptureModule,
    AiGatewayModule,
    ChatEngineModule,
    FactExtractionModule,
    QualityScoringModule,

    // Legacy modules (feature-flagged via ENABLE_LEGACY_MODULES env var)
    ...getLegacyModules(),
  ],
  controllers: [HealthController],
  providers: [
    {
      provide: APP_GUARD,
      useClass: ThrottlerGuard,
    },
    {
      provide: APP_GUARD,
      useClass: CsrfGuard,
    },
  ],
})
export class AppModule {}

import {
  Injectable,
  CanActivate,
  ExecutionContext,
  ForbiddenException,
  Logger,
} from '@nestjs/common';
import { Request } from 'express';
import * as crypto from 'crypto';
import { ConfigService } from '@nestjs/config';
import { Reflector } from '@nestjs/core';

export const CSRF_TOKEN_HEADER = 'x-csrf-token';
export const CSRF_TOKEN_COOKIE = 'csrf-token';
export const CSRF_SKIP_KEY = 'skipCsrf';

/**
 * Decorator to skip CSRF validation for specific routes
 * Use sparingly - only for webhooks or public endpoints
 */
export const SkipCsrf = () => {
  return (target: object, _propertyKey?: string, descriptor?: PropertyDescriptor) => {
    if (descriptor) {
      Reflect.defineMetadata(CSRF_SKIP_KEY, true, descriptor.value);
    } else {
      Reflect.defineMetadata(CSRF_SKIP_KEY, true, target);
    }
    return descriptor;
  };
};

/**
 * CSRF Guard implementing Double Submit Cookie pattern
 *
 * Protection mechanism:
 * 1. Server sets a CSRF token in a cookie (HttpOnly: false so JS can read it)
 * 2. Client must send the same token in the X-CSRF-Token header
 * 3. Guard validates that cookie value matches header value
 *
 * This works because:
 * - Attackers can trigger requests that include cookies automatically
 * - But they cannot read cookie values due to Same-Origin Policy
 * - So they cannot set the matching header value
 *
 * @see https://cheatsheetseries.owasp.org/cheatsheets/Cross-Site_Request_Forgery_Prevention_Cheat_Sheet.html
 */
@Injectable()
export class CsrfGuard implements CanActivate {
  private readonly logger = new Logger(CsrfGuard.name);
  private readonly csrfSecret: string;

  constructor(
    private readonly configService: ConfigService,
    private readonly reflector: Reflector,
  ) {
    const nodeEnv = this.configService.get<string>('NODE_ENV', 'development');
    const configuredSecret = this.configService.get<string>('CSRF_SECRET');

    if (nodeEnv === 'production' && !configuredSecret) {
      throw new Error('FATAL: CSRF_SECRET must be set in production');
    }

    this.csrfSecret = configuredSecret || 'quiz2biz-csrf-secret-change-in-production';
  }

  canActivate(context: ExecutionContext): boolean {
    // CSRF_DISABLED only allowed in non-production environments
    const nodeEnv = this.configService.get<string>('NODE_ENV', 'development');
    const csrfDisabled =
      this.configService.get<string>('CSRF_DISABLED', 'false').toLowerCase() === 'true';
    if (csrfDisabled) {
      if (nodeEnv === 'production') {
        this.logger.error('CSRF_DISABLED is set but ignored in production');
      } else {
        this.logger.warn('CSRF protection is DISABLED via CSRF_DISABLED environment variable');
        return true;
      }
    }

    const request = context.switchToHttp().getRequest<Request>();

    // Skip CSRF for safe methods (GET, HEAD, OPTIONS)
    const safeMethods = ['GET', 'HEAD', 'OPTIONS'];
    if (safeMethods.includes(request.method)) {
      return true;
    }

    // Check for @SkipCsrf decorator
    const skipCsrf = this.reflector.get<boolean>(CSRF_SKIP_KEY, context.getHandler());
    if (skipCsrf) {
      this.logger.debug(`CSRF check skipped for ${request.method} ${request.path}`);
      return true;
    }

    // Get token from header and cookie
    const headerToken = request.headers[CSRF_TOKEN_HEADER] as string;
    const cookieToken = request.cookies?.[CSRF_TOKEN_COOKIE] as string;

    // Validate presence of both tokens
    if (!headerToken || !cookieToken) {
      this.logger.warn(
        `CSRF validation failed: Missing token - Header: ${!!headerToken}, Cookie: ${!!cookieToken}`,
      );
      throw new ForbiddenException({
        statusCode: 403,
        message: 'CSRF token validation failed',
        error: 'Forbidden',
        code: 'CSRF_TOKEN_MISSING',
        hint: 'Include X-CSRF-Token header with the value from csrf-token cookie',
      });
    }

    // Validate tokens match (constant-time comparison to prevent timing attacks)
    // Check lengths first to avoid timingSafeEqual throwing on different lengths
    if (headerToken.length !== cookieToken.length) {
      this.logger.warn(`CSRF validation failed: Token length mismatch for ${request.path}`);
      throw new ForbiddenException({
        statusCode: 403,
        message: 'CSRF token validation failed',
        error: 'Forbidden',
        code: 'CSRF_TOKEN_MISMATCH',
      });
    }
    const tokensMatch = crypto.timingSafeEqual(Buffer.from(headerToken), Buffer.from(cookieToken));

    if (!tokensMatch) {
      this.logger.warn(`CSRF validation failed: Token mismatch for ${request.path}`);
      throw new ForbiddenException({
        statusCode: 403,
        message: 'CSRF token validation failed',
        error: 'Forbidden',
        code: 'CSRF_TOKEN_MISMATCH',
      });
    }

    // Validate token format/integrity (optional but adds defense in depth)
    if (!this.validateTokenFormat(cookieToken)) {
      this.logger.warn(`CSRF validation failed: Invalid token format`);
      throw new ForbiddenException({
        statusCode: 403,
        message: 'CSRF token validation failed',
        error: 'Forbidden',
        code: 'CSRF_TOKEN_INVALID',
      });
    }

    return true;
  }

  /**
   * Generate a new CSRF token
   * Token format: base64(timestamp.randomBytes.hmac)
   */
  static generateToken(secret: string): string {
    const timestamp = Date.now().toString();
    const randomBytes = crypto.randomBytes(16).toString('hex');
    const data = `${timestamp}.${randomBytes}`;
    const hmac = crypto.createHmac('sha256', secret).update(data).digest('hex');
    return Buffer.from(`${data}.${hmac}`).toString('base64');
  }

  /**
   * Validate token format and integrity
   */
  private validateTokenFormat(token: string): boolean {
    try {
      const decoded = Buffer.from(token, 'base64').toString('utf-8');
      const parts = decoded.split('.');

      if (parts.length !== 3) {
        return false;
      }

      const [timestamp, randomBytes, providedHmac] = parts;

      // Verify HMAC
      const data = `${timestamp}.${randomBytes}`;
      const expectedHmac = crypto.createHmac('sha256', this.csrfSecret).update(data).digest('hex');

      // Constant-time comparison
      if (providedHmac.length !== expectedHmac.length) {
        return false;
      }

      return crypto.timingSafeEqual(Buffer.from(providedHmac), Buffer.from(expectedHmac));
    } catch {
      return false;
    }
  }
}

/**
 * Service for generating CSRF tokens
 * Can be used in controllers to provide tokens to clients
 */
@Injectable()
export class CsrfService {
  private readonly csrfSecret: string;
  private readonly tokenMaxAge: number;

  constructor(private readonly configService: ConfigService) {
    const configuredSecret = this.configService.get<string>('CSRF_SECRET');
    const nodeEnv = this.configService.get<string>('NODE_ENV', 'development');

    if (nodeEnv === 'production' && !configuredSecret) {
      throw new Error('FATAL: CSRF_SECRET must be set in production');
    }

    this.csrfSecret = configuredSecret || 'quiz2biz-csrf-secret-change-in-production';
    // Token valid for 24 hours by default
    this.tokenMaxAge = this.configService.get<number>('CSRF_TOKEN_MAX_AGE', 86400000);
  }

  /**
   * Generate a new CSRF token
   */
  generateToken(): string {
    return CsrfGuard.generateToken(this.csrfSecret);
  }

  /**
   * Get cookie options for CSRF token
   */
  getCookieOptions(): {
    httpOnly: boolean;
    secure: boolean;
    sameSite: 'strict' | 'lax' | 'none';
    maxAge: number;
    path: string;
  } {
    const nodeEnv = this.configService.get<string>('NODE_ENV', 'development');

    return {
      httpOnly: false, // Must be false so JS can read the cookie
      secure: nodeEnv === 'production',
      sameSite: 'strict',
      maxAge: this.tokenMaxAge,
      path: '/',
    };
  }
}

import {
  Injectable,
  CanActivate,
  ExecutionContext,
  ForbiddenException,
  Inject,
  SetMetadata,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { SubscriptionService } from '../../modules/payment/subscription.service';
import { SUBSCRIPTION_TIERS, SubscriptionTier } from '../../modules/payment/payment.service';

// Metadata keys
export const REQUIRED_TIER_KEY = 'requiredTier';
export const FEATURE_CHECK_KEY = 'featureCheck';

// Types for feature checking
export type FeatureName = keyof typeof SUBSCRIPTION_TIERS.FREE.features;

export interface FeatureCheckConfig {
  feature: FeatureName;
  getUsage?: (request: Request) => Promise<number> | number;
}

// Decorators for route-level feature gating
export const RequireTier = (...tiers: SubscriptionTier[]) => SetMetadata(REQUIRED_TIER_KEY, tiers);

export const RequireFeature = (config: FeatureCheckConfig) =>
  SetMetadata(FEATURE_CHECK_KEY, config);

/**
 * SubscriptionGuard - Enforces subscription tier access at the route level
 *
 * Usage:
 * @RequireTier('PROFESSIONAL', 'ENTERPRISE')
 * @Get('premium-feature')
 * async getPremiumFeature() { ... }
 *
 * @RequireFeature({ feature: 'questionnaires', getUsage: async (req) => getCurrentCount(req) })
 * @Post('questionnaire')
 * async createQuestionnaire() { ... }
 */
@Injectable()
export class SubscriptionGuard implements CanActivate {
  constructor(
    private reflector: Reflector,
    @Inject(SubscriptionService)
    private subscriptionService: SubscriptionService,
  ) {}

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const request = context.switchToHttp().getRequest();
    const organizationId = this.extractOrganizationId(request);

    if (!organizationId) {
      throw new ForbiddenException('Organization context required for this operation');
    }

    // Check tier-based access
    const requiredTiers = this.reflector.getAllAndOverride<SubscriptionTier[]>(REQUIRED_TIER_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);

    if (requiredTiers && requiredTiers.length > 0) {
      await this.checkTierAccess(organizationId, requiredTiers);
    }

    // Check feature-based access
    const featureCheck = this.reflector.getAllAndOverride<FeatureCheckConfig>(FEATURE_CHECK_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);

    if (featureCheck) {
      await this.checkFeatureAccess(organizationId, featureCheck, request);
    }

    return true;
  }

  /**
   * Extract organization ID from request
   * Supports: JWT token, query param, header, body
   */
  private extractOrganizationId(request: any): string | null {
    // From JWT user context (set by auth guard)
    if (request.user?.organizationId) {
      return request.user.organizationId;
    }

    // From query parameter
    if (request.query?.organizationId) {
      return request.query.organizationId;
    }

    // From header
    if (request.headers['x-organization-id']) {
      return request.headers['x-organization-id'];
    }

    // From request body
    if (request.body?.organizationId) {
      return request.body.organizationId;
    }

    return null;
  }

  /**
   * Check if organization has one of the required tiers
   */
  private async checkTierAccess(
    organizationId: string,
    requiredTiers: SubscriptionTier[],
  ): Promise<void> {
    const subscription = await this.subscriptionService.getOrganizationSubscription(organizationId);
    const currentTier = subscription.tier as SubscriptionTier;

    if (!requiredTiers.includes(currentTier)) {
      throw new ForbiddenException({
        error: 'TIER_ACCESS_DENIED',
        message: `This feature requires ${requiredTiers.join(' or ')} tier`,
        currentTier,
        requiredTiers,
        upgradeUrl: '/billing/upgrade',
      });
    }
  }

  /**
   * Check if organization has feature capacity
   */
  private async checkFeatureAccess(
    organizationId: string,
    config: FeatureCheckConfig,
    request: any,
  ): Promise<void> {
    const currentUsage = config.getUsage ? await config.getUsage(request) : 0;

    const access = await this.subscriptionService.hasFeatureAccess(
      organizationId,
      config.feature,
      currentUsage,
    );

    if (!access.allowed) {
      throw new ForbiddenException({
        error: 'FEATURE_LIMIT_EXCEEDED',
        message: `You have reached your ${config.feature} limit`,
        feature: config.feature,
        limit: access.limit,
        currentUsage,
        remaining: access.remaining,
        upgradeUrl: '/billing/upgrade',
      });
    }
  }
}

/**
 * FeatureGatingMiddleware - Global middleware for tracking feature usage
 * Use for analytics and soft limits (warnings instead of blocks)
 */
@Injectable()
export class FeatureUsageMiddleware {
  constructor(
    @Inject(SubscriptionService)
    private subscriptionService: SubscriptionService,
  ) {}

  async use(request: any, response: any, next: () => void): Promise<void> {
    const organizationId =
      request.user?.organizationId ||
      request.query?.organizationId ||
      request.headers['x-organization-id'];

    if (organizationId) {
      try {
        const subscription =
          await this.subscriptionService.getOrganizationSubscription(organizationId);

        // Attach subscription info to request for downstream use
        request.subscription = subscription;

        // Add usage headers for client awareness
        response.setHeader('X-Subscription-Tier', subscription.tier);
        if (subscription.features.apiCalls !== -1) {
          response.setHeader('X-API-Limit', subscription.features.apiCalls);
        }
      } catch {
        // Don't block request on subscription lookup failure
      }
    }

    next();
  }
}

/**
 * API Rate limiting by tier
 */
export const TIER_RATE_LIMITS: Record<SubscriptionTier, { windowMs: number; max: number }> = {
  FREE: {
    windowMs: 60 * 1000, // 1 minute
    max: 30, // 30 requests per minute
  },
  PROFESSIONAL: {
    windowMs: 60 * 1000,
    max: 300, // 300 requests per minute
  },
  ENTERPRISE: {
    windowMs: 60 * 1000,
    max: 1000, // 1000 requests per minute
  },
};

/**
 * Feature-specific limits by tier
 */
export const FEATURE_TIER_MATRIX = {
  questionnaires: { FREE: 1, PROFESSIONAL: 10, ENTERPRISE: -1 },
  responses: { FREE: 100, PROFESSIONAL: 5000, ENTERPRISE: -1 },
  documents: { FREE: 3, PROFESSIONAL: 50, ENTERPRISE: -1 },
  apiCalls: { FREE: 1000, PROFESSIONAL: 50000, ENTERPRISE: -1 },
  teamMembers: { FREE: 2, PROFESSIONAL: 10, ENTERPRISE: -1 },
  dimensions: { FREE: 3, PROFESSIONAL: 11, ENTERPRISE: 11 },
  exportFormats: {
    FREE: ['PDF'],
    PROFESSIONAL: ['PDF', 'DOCX'],
    ENTERPRISE: ['PDF', 'DOCX', 'JSON', 'XML'],
  },
  customBranding: { FREE: false, PROFESSIONAL: false, ENTERPRISE: true },
  ssoIntegration: { FREE: false, PROFESSIONAL: false, ENTERPRISE: true },
  prioritySupport: { FREE: false, PROFESSIONAL: true, ENTERPRISE: true },
  auditLogs: { FREE: false, PROFESSIONAL: true, ENTERPRISE: true },
  apiAccess: { FREE: false, PROFESSIONAL: true, ENTERPRISE: true },
} as const;

/**
 * Helper to check if a feature is available for a tier
 */
export function isFeatureAvailable(
  tier: SubscriptionTier,
  feature: keyof typeof FEATURE_TIER_MATRIX,
): boolean {
  const featureConfig = FEATURE_TIER_MATRIX[feature];
  const value = featureConfig[tier] as number | boolean | readonly string[];

  if (typeof value === 'boolean') {
    return value;
  }
  if (typeof value === 'number') {
    return value > 0 || value === -1;
  }
  if (Array.isArray(value)) {
    return value.length > 0;
  }

  return true;
}

/**
 * Helper to get feature limit for a tier
 */
export function getFeatureLimit(
  tier: SubscriptionTier,
  feature: keyof typeof FEATURE_TIER_MATRIX,
): number | boolean | readonly string[] {
  return FEATURE_TIER_MATRIX[feature][tier];
}

import { Injectable, NestInterceptor, ExecutionContext, CallHandler } from '@nestjs/common';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';

export interface ApiResponse<T> {
  success: boolean;
  data: T;
  meta?: {
    timestamp: string;
    requestId?: string;
  };
}

@Injectable()
export class TransformInterceptor<T> implements NestInterceptor<T, ApiResponse<T>> {
  intercept(context: ExecutionContext, next: CallHandler): Observable<ApiResponse<T>> {
    const request = context.switchToHttp().getRequest();
    const requestId = request.headers['x-request-id'] as string | undefined;

    return next.handle().pipe(
      map((data: T) => ({
        success: true,
        data,
        meta: {
          timestamp: new Date().toISOString(),
          requestId,
        },
      })),
    );
  }
}

/**
 * Code Hygiene Validation Tests
 *
 * Validates code quality standards:
 * - Clean Code principles (functions Ôëñ30 lines, files Ôëñ400 lines)
 * - SOLID principles compliance
 * - DRY principle adherence
 * - Cyclomatic complexity (Ôëñ15 per function)
 * - Naming conventions
 * - Comment quality
 *
 * @see ISO/IEC 5055 Source Code Quality
 * @see ISO/IEC 25010 Maintainability
 */

import * as fs from 'fs';
import * as path from 'path';

describe('Code Hygiene Validation', () => {
  const srcDir = path.join(__dirname, '../../../../');

  function getAllTsFiles(dir: string, files: string[] = []): string[] {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (
        entry.isDirectory() &&
        !entry.name.includes('node_modules') &&
        !entry.name.includes('dist') &&
        !entry.name.includes('coverage')
      ) {
        getAllTsFiles(fullPath, files);
      } else if (
        entry.isFile() &&
        entry.name.endsWith('.ts') &&
        !entry.name.includes('.spec.') &&
        !entry.name.includes('.test.')
      ) {
        files.push(fullPath);
      }
    }
    return files;
  }

  describe('File Size Limits', () => {
    it('should have files under 400 lines', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const lineCount = content.split('\n').length;

        if (lineCount > 400) {
          violations.push(`${path.relative(srcDir, file)}: ${lineCount} lines (max 400)`);
        }
      }

      if (violations.length > 0) {
        console.warn('Files exceeding 400 lines:\n' + violations.join('\n'));
      }
      // Allow some violations but flag them
      expect(violations.length).toBeLessThan(50);
    });
  });

  describe('Function Length', () => {
    it('should have functions under 30 lines', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const lines = content.split('\n');

        let inFunction = false;
        let functionStart = 0;
        let braceCount = 0;
        let currentFunctionName = '';

        for (let i = 0; i < lines.length; i++) {
          const line = lines[i];

          // Detect function start
          const funcMatch = line.match(
            /(?:async\s+)?(?:function|(?:private|public|protected)?\s*(?:static)?\s*(?:async)?\s*\w+)\s*\([^)]*\)\s*(?::\s*[^{]+)?\s*\{/,
          );
          const arrowMatch = line.match(
            /(?:const|let|var)\s+(\w+)\s*=\s*(?:async\s*)?\([^)]*\)\s*(?::\s*[^=]+)?\s*=>\s*\{/,
          );

          if (funcMatch || arrowMatch) {
            if (!inFunction) {
              inFunction = true;
              functionStart = i;
              currentFunctionName = arrowMatch
                ? arrowMatch[1]
                : line.match(/(\w+)\s*\(/)?.[1] || 'anonymous';
              braceCount = (line.match(/\{/g) || []).length - (line.match(/\}/g) || []).length;
            }
          }

          if (inFunction) {
            braceCount += (line.match(/\{/g) || []).length;
            braceCount -= (line.match(/\}/g) || []).length;

            if (braceCount === 0) {
              const functionLength = i - functionStart + 1;
              if (functionLength > 30) {
                violations.push(
                  `${path.relative(srcDir, file)}:${functionStart + 1} ${currentFunctionName}(): ${functionLength} lines`,
                );
              }
              inFunction = false;
            }
          }
        }
      }

      if (violations.length > 0) {
        console.warn('Functions exceeding 30 lines:\n' + violations.slice(0, 10).join('\n'));
      }
      // Allow some violations but flag them
      expect(violations.length).toBeLessThan(100);
    });
  });

  describe('Naming Conventions', () => {
    it('should use PascalCase for classes', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const classMatches = content.match(/class\s+([a-zA-Z_][a-zA-Z0-9_]*)/g);

        if (classMatches) {
          for (const match of classMatches) {
            const className = match.replace('class ', '');
            if (!/^[A-Z][a-zA-Z0-9]*$/.test(className)) {
              violations.push(`Non-PascalCase class: ${className} in ${path.basename(file)}`);
            }
          }
        }
      }

      expect(violations).toEqual([]);
    });

    it('should use camelCase for functions and variables', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        // Check function names (excluding class methods)
        const funcMatches = content.match(/function\s+([a-zA-Z_][a-zA-Z0-9_]*)/g);
        if (funcMatches) {
          for (const match of funcMatches) {
            const funcName = match.replace('function ', '');
            if (!/^[a-z][a-zA-Z0-9]*$/.test(funcName) && funcName !== '_') {
              violations.push(`Non-camelCase function: ${funcName} in ${path.basename(file)}`);
            }
          }
        }
      }

      // Allow some violations (decorators, etc.)
      expect(violations.length).toBeLessThan(10);
    });

    it('should use UPPER_SNAKE_CASE for constants', () => {
      const files = getAllTsFiles(srcDir);
      let hasProperConstants = true;

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        // Check for const with all uppercase names
        const constMatches = content.match(/const\s+([A-Z][A-Z0-9_]*)\s*=/g);
        if (constMatches) {
          for (const match of constMatches) {
            const constName = match.match(/const\s+([A-Z][A-Z0-9_]*)/)?.[1];
            if (constName && !/^[A-Z][A-Z0-9_]*$/.test(constName)) {
              hasProperConstants = false;
            }
          }
        }
      }

      expect(hasProperConstants).toBe(true);
    });
  });

  describe('Code Duplication (DRY)', () => {
    it('should not have excessive code duplication', () => {
      const files = getAllTsFiles(srcDir);
      const codeBlocks: Map<string, string[]> = new Map();

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const lines = content.split('\n');

        // Check for 5+ line blocks that might be duplicated
        for (let i = 0; i < lines.length - 5; i++) {
          const block = lines
            .slice(i, i + 5)
            .join('\n')
            .trim();
          if (block.length > 50) {
            const normalized = block.replace(/\s+/g, ' ');
            const existing = codeBlocks.get(normalized) || [];
            existing.push(`${path.basename(file)}:${i + 1}`);
            codeBlocks.set(normalized, existing);
          }
        }
      }

      const duplicates: string[] = [];
      for (const [block, locations] of codeBlocks) {
        if (locations.length > 2) {
          duplicates.push(
            `Block duplicated ${locations.length} times: ${locations.slice(0, 3).join(', ')}`,
          );
        }
      }

      if (duplicates.length > 0) {
        console.warn('Potential code duplication found:\n' + duplicates.slice(0, 5).join('\n'));
      }
      // Some duplication is acceptable in a growing codebase
      expect(duplicates.length).toBeLessThan(500);
    });
  });

  describe('Dead Code Detection', () => {
    it('should not have commented-out code blocks', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const lines = content.split('\n');

        let consecutiveCommentedCode = 0;
        for (const line of lines) {
          // Detect commented-out code (not JSDoc or regular comments)
          if (line.match(/^\s*\/\/\s*(const|let|var|function|if|for|while|return|import|export)/)) {
            consecutiveCommentedCode++;
          } else {
            if (consecutiveCommentedCode >= 3) {
              violations.push(`Commented-out code block in ${path.basename(file)}`);
            }
            consecutiveCommentedCode = 0;
          }
        }
      }

      expect(violations.length).toBeLessThan(10);
    });

    it('should not have unused imports', () => {
      // This is usually handled by ESLint, but we can do a basic check
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        // Extract imported names
        const importMatches = content.match(/import\s+\{([^}]+)\}/g);
        if (importMatches) {
          for (const match of importMatches) {
            const imports =
              match
                .match(/\{([^}]+)\}/)?.[1]
                .split(',')
                .map((s) => s.trim().split(' ')[0]) || [];
            for (const imp of imports) {
              if (imp && !imp.includes('type')) {
                const usageCount = (content.match(new RegExp(`\\b${imp}\\b`, 'g')) || []).length;
                // Should appear more than once (the import itself)
                if (usageCount === 1) {
                  violations.push(`Potentially unused import: ${imp} in ${path.basename(file)}`);
                }
              }
            }
          }
        }
      }

      // Allow some - this is a heuristic check
      expect(violations.length).toBeLessThan(20);
    });
  });

  describe('Comment Quality', () => {
    it('should have JSDoc for public methods in services', () => {
      const serviceFiles = getAllTsFiles(srcDir).filter((f) => f.includes('.service.ts'));
      let hasJsDoc = false;

      for (const file of serviceFiles) {
        const content = fs.readFileSync(file, 'utf-8');

        if (content.includes('/**') && content.includes('*/')) {
          hasJsDoc = true;
          break;
        }
      }

      expect(hasJsDoc).toBe(true);
    });

    it('should not have TODO comments older than sprint', () => {
      const files = getAllTsFiles(srcDir);
      const todos: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const todoMatches = content.match(/\/\/\s*TODO[:\s].*$/gm);

        if (todoMatches) {
          for (const todo of todoMatches) {
            todos.push(`${path.basename(file)}: ${todo.substring(0, 50)}...`);
          }
        }
      }

      if (todos.length > 10) {
        console.warn(`Found ${todos.length} TODO comments - consider addressing them`);
      }
      // TODOs are allowed but flagged
      expect(todos.length).toBeLessThan(50);
    });
  });

  describe('Async/Await Usage', () => {
    it('should use async/await instead of .then()', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        // Count .then() usage vs async/await
        const thenCount = (content.match(/\.then\s*\(/g) || []).length;
        const asyncCount = (content.match(/async\s+/g) || []).length;

        // If file uses promises, should prefer async/await
        if (thenCount > 5 && thenCount > asyncCount) {
          violations.push(
            `${path.basename(file)}: ${thenCount} .then() calls (prefer async/await)`,
          );
        }
      }

      expect(violations.length).toBeLessThan(5);
    });
  });

  describe('Error Handling', () => {
    it('should have try-catch blocks for async operations', () => {
      const files = getAllTsFiles(srcDir);
      let hasTryCatch = false;

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        if (content.includes('try {') && content.includes('catch')) {
          hasTryCatch = true;
          break;
        }
      }

      expect(hasTryCatch).toBe(true);
    });

    it('should not have empty catch blocks', () => {
      const files = getAllTsFiles(srcDir);
      const violations: string[] = [];

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        // Find empty catch blocks
        const emptyCatch = content.match(/catch\s*\([^)]*\)\s*\{\s*\}/g);
        if (emptyCatch) {
          violations.push(`Empty catch block in ${path.basename(file)}`);
        }
      }

      expect(violations).toEqual([]);
    });
  });

  describe('Type Safety', () => {
    it('should minimize use of "any" type', () => {
      const files = getAllTsFiles(srcDir);
      let anyCount = 0;

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');
        const matches = content.match(/:\s*any\b/g);
        if (matches) {
          anyCount += matches.length;
        }
      }

      if (anyCount > 50) {
        console.warn(`Found ${anyCount} uses of 'any' type - consider using specific types`);
      }
      expect(anyCount).toBeLessThan(150);
    });

    it('should use strict null checks patterns', () => {
      const files = getAllTsFiles(srcDir);
      let hasNullChecks = false;

      for (const file of files) {
        const content = fs.readFileSync(file, 'utf-8');

        if (
          content.includes('??') ||
          content.includes('?.') ||
          content.includes('!== null') ||
          content.includes('!== undefined')
        ) {
          hasNullChecks = true;
          break;
        }
      }

      expect(hasNullChecks).toBe(true);
    });
  });

  describe('Module Organization', () => {
    it('should have index.ts barrel files for modules', () => {
      const modulesDir = path.join(srcDir, 'modules');
      if (!fs.existsSync(modulesDir)) {
        // Skip if modules directory doesn't exist at expected path
        expect(true).toBe(true);
        return;
      }

      const moduleDirs = fs
        .readdirSync(modulesDir, { withFileTypes: true })
        .filter((d) => d.isDirectory());

      let hasBarrelFiles = 0;
      for (const dir of moduleDirs) {
        const indexPath = path.join(modulesDir, dir.name, 'index.ts');
        if (fs.existsSync(indexPath)) {
          hasBarrelFiles++;
        }
      }

      // At least half should have index files
      expect(hasBarrelFiles).toBeGreaterThan(moduleDirs.length / 2);
    });
  });
});

/**
 * Azure Application Insights Configuration
 *
 * Provides Application Performance Monitoring (APM) for production environments.
 * Tracks requests, dependencies, exceptions, and custom metrics.
 */
import * as appInsights from 'applicationinsights';
import { Logger } from '@nestjs/common';

const logger = new Logger('AppInsights');

// =============================================================================
// Configuration Interface
// =============================================================================

export interface AppInsightsConfig {
  connectionString: string;
  instrumentationKey?: string;
  cloudRole: string;
  cloudRoleInstance: string;
  samplingPercentage: number;
  enableAutoCollect: {
    requests: boolean;
    performance: boolean;
    exceptions: boolean;
    dependencies: boolean;
    console: boolean;
  };
}

// =============================================================================
// Configuration Factory
// =============================================================================

export function getAppInsightsConfig(): AppInsightsConfig {
  const isProd = process.env.NODE_ENV === 'production';

  return {
    connectionString: process.env.APPLICATIONINSIGHTS_CONNECTION_STRING || '',
    instrumentationKey: process.env.APPINSIGHTS_INSTRUMENTATIONKEY || '',
    cloudRole: process.env.AZURE_CLOUD_ROLE || 'quiz-to-build-api',
    cloudRoleInstance: process.env.HOSTNAME || 'local-dev',
    samplingPercentage: isProd ? 75 : 50, // 75% in prod for cost optimization (GAP-P5)
    enableAutoCollect: {
      requests: true,
      performance: true,
      exceptions: true,
      dependencies: true,
      console: !isProd, // Only collect console logs in dev
    },
  };
}

// =============================================================================
// Initialization
// =============================================================================

let isInitialized = false;
let client: appInsights.TelemetryClient | null = null;

/**
 * Initialize Azure Application Insights
 * Must be called before any other imports to properly instrument the app
 */
export function initializeAppInsights(): void {
  const config = getAppInsightsConfig();

  // Skip if already initialized or no connection string
  if (isInitialized) {
    logger.log('Application Insights already initialized');
    return;
  }

  if (!config.connectionString && !config.instrumentationKey) {
    logger.warn(
      'Application Insights not configured (no connection string or instrumentation key)',
    );
    return;
  }

  try {
    // Initialize with connection string (preferred) or instrumentation key
    if (config.connectionString) {
      appInsights.setup(config.connectionString);
    } else if (config.instrumentationKey) {
      appInsights.setup(config.instrumentationKey);
    }

    // Configure auto-collection
    appInsights.defaultClient.config.samplingPercentage = config.samplingPercentage;

    // Set cloud role for application map
    appInsights.defaultClient.context.tags[appInsights.defaultClient.context.keys.cloudRole] =
      config.cloudRole;
    appInsights.defaultClient.context.tags[
      appInsights.defaultClient.context.keys.cloudRoleInstance
    ] = config.cloudRoleInstance;

    // Configure auto-collection features
    appInsights.defaultClient.config.samplingPercentage = config.samplingPercentage;

    // Start the SDK
    appInsights.start();

    client = appInsights.defaultClient;
    isInitialized = true;

    logger.log(
      `Application Insights initialized: role=${config.cloudRole}, instance=${config.cloudRoleInstance}`,
    );
  } catch (error) {
    logger.error('Failed to initialize Application Insights:', error instanceof Error ? error.stack : String(error));
  }
}

/**
 * Get the Application Insights telemetry client
 */
export function getClient(): appInsights.TelemetryClient | null {
  return client;
}

// =============================================================================
// Custom Metrics
// =============================================================================

export interface CustomMetricOptions {
  name: string;
  value: number;
  properties?: Record<string, string>;
  count?: number;
  min?: number;
  max?: number;
  stdDev?: number;
}

/**
 * Track a custom metric
 */
export function trackMetric(options: CustomMetricOptions): void {
  if (!client) {
    return;
  }

  client.trackMetric({
    name: options.name,
    value: options.value,
    properties: options.properties,
    count: options.count,
    min: options.min,
    max: options.max,
    stdDev: options.stdDev,
  });
}

/**
 * Track response time for an operation
 */
export function trackResponseTime(
  operationName: string,
  durationMs: number,
  success: boolean,
  properties?: Record<string, string>,
): void {
  trackMetric({
    name: `${operationName}_response_time`,
    value: durationMs,
    properties: {
      success: success.toString(),
      ...properties,
    },
  });
}

/**
 * Track questionnaire completion metrics
 */
export function trackQuestionnaireMetrics(
  sessionId: string,
  metrics: {
    questionsAnswered: number;
    totalQuestions: number;
    completionPercentage: number;
    timeSpentSeconds: number;
  },
): void {
  if (!client) {
    return;
  }

  trackMetric({
    name: 'questionnaire_completion_percentage',
    value: metrics.completionPercentage,
    properties: { sessionId },
  });

  trackMetric({
    name: 'questionnaire_questions_answered',
    value: metrics.questionsAnswered,
    properties: { sessionId },
  });

  trackMetric({
    name: 'questionnaire_time_spent_seconds',
    value: metrics.timeSpentSeconds,
    properties: { sessionId },
  });
}

/**
 * Track readiness score calculation
 */
export function trackReadinessScore(
  sessionId: string,
  score: number,
  dimensionScores: Record<string, number>,
): void {
  if (!client) {
    return;
  }

  trackMetric({
    name: 'readiness_score_overall',
    value: score,
    properties: { sessionId },
  });

  // Track individual dimension scores
  for (const [dimension, dimensionScore] of Object.entries(dimensionScores)) {
    trackMetric({
      name: `readiness_score_${dimension.toLowerCase().replace(/\s+/g, '_')}`,
      value: dimensionScore,
      properties: { sessionId },
    });
  }
}

// =============================================================================
// Custom Events
// =============================================================================

export interface CustomEventOptions {
  name: string;
  properties?: Record<string, string>;
  measurements?: Record<string, number>;
}

/**
 * Track a custom event
 */
export function trackEvent(options: CustomEventOptions): void {
  if (!client) {
    return;
  }

  client.trackEvent({
    name: options.name,
    properties: options.properties,
    measurements: options.measurements,
  });
}

/**
 * Track user authentication events
 */
export function trackAuthEvent(
  eventType: 'login' | 'logout' | 'register' | 'password_reset',
  userId?: string,
  method?: string,
): void {
  trackEvent({
    name: `auth_${eventType}`,
    properties: {
      userId: userId || 'anonymous',
      method: method || 'email',
    },
  });
}

/**
 * Track document generation events
 */
export function trackDocumentGeneration(
  documentType: string,
  sessionId: string,
  success: boolean,
  durationMs: number,
): void {
  trackEvent({
    name: 'document_generated',
    properties: {
      documentType,
      sessionId,
      success: success.toString(),
    },
    measurements: {
      durationMs,
    },
  });
}

/**
 * Track API endpoint usage
 */
export function trackEndpointUsage(
  endpoint: string,
  method: string,
  statusCode: number,
  durationMs: number,
  userId?: string,
): void {
  trackEvent({
    name: 'api_request',
    properties: {
      endpoint,
      method,
      statusCode: statusCode.toString(),
      userId: userId || 'anonymous',
    },
    measurements: {
      durationMs,
    },
  });
}

// =============================================================================
// Exception Tracking
// =============================================================================

/**
 * Track an exception
 */
export function trackException(
  error: Error,
  properties?: Record<string, string>,
  measurements?: Record<string, number>,
): void {
  if (!client) {
    return;
  }

  client.trackException({
    exception: error,
    properties,
    measurements,
  });
}

/**
 * Track a handled exception (non-fatal)
 */
export function trackHandledException(error: Error, context: string, userId?: string): void {
  trackException(error, {
    context,
    userId: userId || 'anonymous',
    severity: 'warning',
  });
}

/**
 * Track a critical exception (requires immediate attention)
 */
export function trackCriticalException(
  error: Error,
  context: string,
  additionalData?: Record<string, string>,
): void {
  trackException(error, {
    context,
    severity: 'critical',
    ...additionalData,
  });
}

// =============================================================================
// Dependency Tracking
// =============================================================================

/**
 * Track an external dependency call (database, API, etc.)
 */
export function trackDependency(options: {
  name: string;
  data: string;
  dependencyTypeName: string;
  target: string;
  duration: number;
  success: boolean;
  resultCode?: string;
  properties?: Record<string, string>;
}): void {
  if (!client) {
    return;
  }

  client.trackDependency({
    name: options.name,
    data: options.data,
    dependencyTypeName: options.dependencyTypeName,
    target: options.target,
    duration: options.duration,
    success: options.success,
    resultCode: options.resultCode || (options.success ? '200' : '500'),
    properties: options.properties,
  });
}

/**
 * Track database query performance
 */
export function trackDatabaseQuery(
  queryName: string,
  durationMs: number,
  success: boolean,
  tableName?: string,
): void {
  trackDependency({
    name: queryName,
    data: queryName,
    dependencyTypeName: 'PostgreSQL',
    target: process.env.DATABASE_HOST || 'localhost',
    duration: durationMs,
    success,
    properties: tableName ? { tableName } : undefined,
  });
}

/**
 * Track external API call
 */
export function trackExternalApiCall(
  apiName: string,
  endpoint: string,
  durationMs: number,
  statusCode: number,
): void {
  trackDependency({
    name: apiName,
    data: endpoint,
    dependencyTypeName: 'HTTP',
    target: apiName,
    duration: durationMs,
    success: statusCode >= 200 && statusCode < 400,
    resultCode: statusCode.toString(),
  });
}

// =============================================================================
// Performance Counters
// =============================================================================

/**
 * Pre-defined performance metrics
 */
export const PerformanceMetrics = {
  // API Latency
  API_RESPONSE_TIME: 'api_response_time_ms',
  DATABASE_QUERY_TIME: 'database_query_time_ms',
  EXTERNAL_API_TIME: 'external_api_time_ms',

  // Throughput
  REQUESTS_PER_SECOND: 'requests_per_second',
  CONCURRENT_USERS: 'concurrent_users',

  // Questionnaire
  QUESTIONS_ANSWERED: 'questions_answered_total',
  SESSIONS_ACTIVE: 'sessions_active',
  COMPLETION_RATE: 'questionnaire_completion_rate',

  // Scoring
  SCORE_CALCULATION_TIME: 'score_calculation_time_ms',
  AVERAGE_READINESS_SCORE: 'average_readiness_score',

  // Document Generation
  DOCUMENT_GENERATION_TIME: 'document_generation_time_ms',
  DOCUMENTS_GENERATED: 'documents_generated_total',
};

/**
 * Track standard performance metric
 */
export function trackPerformance(
  metricName: keyof typeof PerformanceMetrics,
  value: number,
  properties?: Record<string, string>,
): void {
  trackMetric({
    name: PerformanceMetrics[metricName],
    value,
    properties,
  });
}

// =============================================================================
// Availability Tracking
// =============================================================================

/**
 * Track an availability test result (health check)
 */
export function trackAvailability(
  testName: string,
  success: boolean,
  durationMs: number,
  runLocation?: string,
  message?: string,
): void {
  if (!client) {
    return;
  }

  client.trackAvailability({
    id: `${testName}-${Date.now()}`,
    name: testName,
    success,
    duration: durationMs,
    runLocation: runLocation || 'Azure',
    message: message || (success ? 'Available' : 'Unavailable'),
  });
}

// =============================================================================
// Flush & Shutdown
// =============================================================================

/**
 * Flush all pending telemetry
 */
export function flush(): void {
  if (client) {
    void client.flush();
  }
}

/**
 * Gracefully shutdown Application Insights
 */
export async function shutdown(): Promise<void> {
  if (client) {
    void client.flush();
    // Give time for telemetry to be sent
    await new Promise((resolve) => setTimeout(resolve, 2000));
    logger.log('Application Insights telemetry flushed');
  }
}

// =============================================================================
// NestJS Middleware Helper
// =============================================================================

/**
 * Create a request tracking middleware for NestJS
 */
export function createRequestTrackingMiddleware() {
  return (req: any, res: any, next: () => void) => {
    const startTime = Date.now();

    res.on('finish', () => {
      const durationMs = Date.now() - startTime;
      const userId = req.user?.id;

      trackEndpointUsage(req.path, req.method, res.statusCode, durationMs, userId);

      // Track slow requests (>500ms)
      if (durationMs > 500) {
        trackEvent({
          name: 'slow_request',
          properties: {
            endpoint: req.path,
            method: req.method,
          },
          measurements: {
            durationMs,
          },
        });
      }
    });

    next();
  };
}

/**
 * Chaos Engineering Configuration
 *
 * Defines chaos experiments for resilience testing using Azure Chaos Studio
 * and Chaos Mesh for Kubernetes environments.
 *
 * Purpose:
 * - Test system resilience under failure conditions
 * - Validate graceful degradation mechanisms
 * - Verify recovery procedures
 * - Ensure SLA targets during failures
 */

// =============================================================================
// CHAOS CONFIGURATION TYPES
// =============================================================================

export interface ChaosExperimentConfig {
  id: string;
  name: string;
  description: string;
  type: ChaosExperimentType;
  target: ChaosTarget;
  parameters: ChaosParameters;
  schedule: ChaosSchedule;
  rollback: RollbackConfig;
  monitoring: MonitoringConfig;
  enabled: boolean;
}

export type ChaosExperimentType =
  | 'network-latency'
  | 'network-partition'
  | 'cpu-pressure'
  | 'memory-pressure'
  | 'disk-pressure'
  | 'pod-kill'
  | 'pod-failure'
  | 'container-kill'
  | 'dns-chaos'
  | 'http-chaos'
  | 'io-chaos'
  | 'time-chaos'
  | 'jvm-chaos'
  | 'kernel-chaos'
  | 'stress-ng';

export interface ChaosTarget {
  resourceType:
    | 'container-app'
    | 'kubernetes-pod'
    | 'virtual-machine'
    | 'database'
    | 'storage'
    | 'network';
  resourceGroup?: string;
  namespace?: string;
  selector?: Record<string, string>;
  names?: string[];
  percentage?: number;
}

export interface ChaosParameters {
  duration: string;
  intensity?: number;
  latencyMs?: number;
  jitterMs?: number;
  packetLossPercent?: number;
  bandwidthLimit?: string;
  cpuPercent?: number;
  memoryBytes?: string;
  diskFillPercent?: number;
  errorRate?: number;
  httpStatusCode?: number;
  targetPort?: number;
}

export interface ChaosSchedule {
  type: 'manual' | 'scheduled' | 'continuous';
  cron?: string;
  timezone?: string;
  maxOccurrences?: number;
  gameDay?: boolean;
}

export interface RollbackConfig {
  automatic: boolean;
  triggerConditions: RollbackTrigger[];
  timeoutSeconds: number;
}

export interface RollbackTrigger {
  metric: string;
  operator: 'gt' | 'lt' | 'eq' | 'gte' | 'lte';
  threshold: number;
  evaluationWindow: string;
}

export interface MonitoringConfig {
  alertsEnabled: boolean;
  dashboardUrl?: string;
  metricsToWatch: string[];
  notificationChannels: string[];
}

// =============================================================================
// AZURE CHAOS STUDIO CONFIGURATION
// =============================================================================

export interface AzureChaosStudioConfig {
  subscriptionId: string;
  resourceGroup: string;
  location: string;
  managedIdentityId: string;
  targetResourceIds: string[];
  experiments: AzureChaosExperiment[];
}

export interface AzureChaosExperiment {
  name: string;
  identity: {
    type: 'SystemAssigned' | 'UserAssigned';
    userAssignedIdentities?: Record<string, object>;
  };
  properties: {
    selectors: AzureChaosSelector[];
    steps: AzureChaosStep[];
  };
}

export interface AzureChaosSelector {
  type: 'List' | 'Query';
  id: string;
  targets: AzureChaosTargetReference[];
}

export interface AzureChaosTargetReference {
  type: string;
  id: string;
}

export interface AzureChaosStep {
  name: string;
  branches: AzureChaosBranch[];
}

export interface AzureChaosBranch {
  name: string;
  actions: AzureChaosAction[];
}

export interface AzureChaosAction {
  type: 'continuous' | 'discrete' | 'delay';
  name: string;
  selectorId?: string;
  duration?: string;
  parameters?: AzureChaosActionParameter[];
}

export interface AzureChaosActionParameter {
  key: string;
  value: string;
}

// =============================================================================
// CHAOS MESH CONFIGURATION (Kubernetes)
// =============================================================================

export interface ChaosMeshConfig {
  version: string;
  namespace: string;
  dashboard: {
    enabled: boolean;
    port: number;
    ingress?: {
      enabled: boolean;
      host: string;
    };
  };
  experiments: ChaosMeshExperiment[];
}

export interface ChaosMeshExperiment {
  apiVersion: string;
  kind: ChaosMeshKind;
  metadata: {
    name: string;
    namespace: string;
    labels?: Record<string, string>;
    annotations?: Record<string, string>;
  };
  spec: ChaosMeshSpec;
}

export type ChaosMeshKind =
  | 'PodChaos'
  | 'NetworkChaos'
  | 'IOChaos'
  | 'TimeChaos'
  | 'StressChaos'
  | 'DNSChaos'
  | 'HTTPChaos'
  | 'KernelChaos'
  | 'JVMChaos'
  | 'AWSChaos'
  | 'AzureChaos'
  | 'GCPChaos';

export interface ChaosMeshSpec {
  mode: 'one' | 'all' | 'fixed' | 'fixed-percent' | 'random-max-percent';
  value?: string;
  selector: ChaosMeshSelector;
  duration?: string;
  scheduler?: ChaosMeshScheduler;
  // Specific chaos parameters
  action?: string;
  delay?: ChaosMeshDelay;
  loss?: ChaosMeshLoss;
  duplicate?: ChaosMeshDuplicate;
  corrupt?: ChaosMeshCorrupt;
  bandwidth?: ChaosMeshBandwidth;
  stressors?: ChaosMeshStressors;
}

export interface ChaosMeshSelector {
  namespaces?: string[];
  labelSelectors?: Record<string, string>;
  expressionSelectors?: ChaosMeshExpressionSelector[];
  fieldSelectors?: Record<string, string>;
  pods?: Record<string, string[]>;
}

export interface ChaosMeshExpressionSelector {
  key: string;
  operator: 'In' | 'NotIn' | 'Exists' | 'DoesNotExist';
  values?: string[];
}

export interface ChaosMeshScheduler {
  cron: string;
  duration?: string;
}

export interface ChaosMeshDelay {
  latency: string;
  correlation?: string;
  jitter?: string;
}

export interface ChaosMeshLoss {
  loss: string;
  correlation?: string;
}

export interface ChaosMeshDuplicate {
  duplicate: string;
  correlation?: string;
}

export interface ChaosMeshCorrupt {
  corrupt: string;
  correlation?: string;
}

export interface ChaosMeshBandwidth {
  rate: string;
  limit: number;
  buffer: number;
}

export interface ChaosMeshStressors {
  memory?: {
    workers: number;
    size?: string;
  };
  cpu?: {
    workers: number;
    load?: number;
  };
}

