/**
 * Failure Injection Scenarios
 *
 * Comprehensive chaos experiment definitions for testing system resilience
 * under various failure conditions.
 */

import {
  ChaosMeshExperiment,
  ChaosMeshKind,
  ExperimentResult,
} from './chaos-engineering.config';

// =============================================================================
// FAILURE INJECTION TYPES
// =============================================================================

export interface FailureScenario {
  id: string;
  name: string;
  category: FailureCategory;
  description: string;
  impact: ImpactLevel;
  targetService: string;
  injectionType: InjectionType;
  parameters: FailureParameters;
  expectedBehavior: ExpectedBehavior;
  validation: ValidationChecks;
  rollbackTriggers: RollbackTrigger[];
}

export type FailureCategory =
  | 'database'
  | 'network'
  | 'compute'
  | 'storage'
  | 'external-service'
  | 'application'
  | 'infrastructure';

export type ImpactLevel = 'low' | 'medium' | 'high' | 'critical';

export type InjectionType =
  | 'latency'
  | 'timeout'
  | 'connection-failure'
  | 'data-corruption'
  | 'resource-exhaustion'
  | 'crash'
  | 'partition'
  | 'dns-failure'
  | 'certificate-failure';

export interface FailureParameters {
  duration: string;
  intensity?: number;
  targetPercentage?: number;
  delayMs?: number;
  errorCode?: number;
  errorMessage?: string;
  affectedEndpoints?: string[];
}

export interface ExpectedBehavior {
  description: string;
  maxResponseTimeMs: number;
  maxErrorRate: number;
  acceptableDataLoss: boolean;
  recoveryTimeSeconds: number;
  fallbackMechanism?: string;
}

export interface ValidationChecks {
  healthCheck: boolean;
  dataIntegrity: boolean;
  circuitBreakerActivation?: boolean;
  fallbackActivation?: boolean;
  alertTriggered?: boolean;
  logsGenerated?: boolean;
}

export interface RollbackTrigger {
  metric: string;
  threshold: number;
  operator: 'gt' | 'lt' | 'eq' | 'gte' | 'lte';
  action: 'stop' | 'pause' | 'notify';
}

