}

export interface GitLabEvidenceResult {
  type:
    | 'pipeline'
    | 'job'
    | 'merge_request'
    | 'release'
    | 'vulnerability'
    | 'test_report'
    | 'coverage';
  sourceId: string;
  sourceUrl: string;
  data: Record<string, unknown>;
  hash: string;
  timestamp: Date;
  metadata: Record<string, unknown>;
}

@Injectable()
export class GitLabAdapter {
  private readonly logger = new Logger(GitLabAdapter.name);
  private readonly defaultApiUrl = 'https://gitlab.com/api/v4';

  constructor(
    private readonly configService: ConfigService,
    _prisma: PrismaService,
  ) {}

  private getHeaders(token: string): Record<string, string> {
    return {
      'PRIVATE-TOKEN': token,
      'Content-Type': 'application/json',
    };
  }

  private isPrivateIp(ip: string): boolean {
    if (!net.isIP(ip)) {
      return false;
    }

    // IPv4 private, loopback and link-local ranges.
    const privateRanges = [
      { from: '10.0.0.0', to: '10.255.255.255' },
      { from: '172.16.0.0', to: '172.31.255.255' },
      { from: '192.168.0.0', to: '192.168.255.255' },
      { from: '127.0.0.0', to: '127.255.255.255' },
      { from: '169.254.0.0', to: '169.254.255.255' },
    ];

    const toLong = (ipAddr: string): number =>
      ipAddr.split('.').reduce((acc, octet) => (acc << 8) + parseInt(octet, 10), 0);

    const longIp = toLong(ip);
    return privateRanges.some(
      (range) => longIp >= toLong(range.from) && longIp <= toLong(range.to),
    );
  }

  private async validateAndGetBaseUrl(config: GitLabConfig): Promise<string> {
    const trustedApiUrl = (
      this.configService.get<string>('GITLAB_API_URL') || this.defaultApiUrl
    ).trim();
    const providedApiUrl = config.apiUrl?.trim();

    if (providedApiUrl && providedApiUrl !== trustedApiUrl) {
      throw new HttpException(
        'Configured GitLab API URL does not match trusted server configuration',
        HttpStatus.BAD_REQUEST,
      );
    }

    let parsed: URL;
    try {
      parsed = new URL(trustedApiUrl);
    } catch {
      throw new HttpException('Invalid GitLab API URL', HttpStatus.BAD_REQUEST);
    }

    if (parsed.protocol.toLowerCase() !== 'https:') {
      throw new HttpException('GitLab API URL must use HTTPS', HttpStatus.BAD_REQUEST);
    }

    if (parsed.username || parsed.password) {
      throw new HttpException(
        'GitLab API URL must not contain credentials',
        HttpStatus.BAD_REQUEST,
      );
    }

    const hostname = parsed.hostname.toLowerCase();
    if (hostname === 'localhost' || hostname === '127.0.0.1') {
      throw new HttpException('GitLab API URL must not point to localhost', HttpStatus.BAD_REQUEST);
    }

    try {
      const addresses = await dns.promises.lookup(hostname, { all: true });
      for (const addr of addresses) {
        if (this.isPrivateIp(addr.address)) {
          throw new HttpException(
            'GitLab API URL must not point to a private or loopback address',
            HttpStatus.BAD_REQUEST,
          );
        }
      }
    } catch (err) {
      this.logger.error(`Failed to resolve GitLab API host "${hostname}": ${getErrorMessage(err)}`);
      throw new HttpException('Unable to resolve GitLab API host', HttpStatus.BAD_REQUEST);
    }

    let normalized = parsed.toString();
    if (normalized.endsWith('/')) {
      normalized = normalized.slice(0, -1);
    }
    return normalized;
  }

  private sanitizeEndpoint(endpoint: string): string {
    const candidate = endpoint.trim();

    if (!candidate) {
      throw new HttpException('Invalid GitLab API endpoint', HttpStatus.BAD_REQUEST);
    }

    if (
      candidate.includes('://') ||
      candidate.startsWith('//') ||
      candidate.includes('\\') ||
      candidate.includes('@') ||
      /(^|\/)\.\.(\/|$)/.test(candidate)
    ) {
      throw new HttpException('Invalid GitLab API endpoint format', HttpStatus.BAD_REQUEST);
    }

    return candidate.startsWith('/') ? candidate.slice(1) : candidate;
  }

  private async makeRequest<T>(
    config: GitLabConfig,
    endpoint: string,
    method: string = 'GET',
    body?: unknown,
  ): Promise<T> {
    const baseUrl = await this.validateAndGetBaseUrl(config);
    const base = new URL(baseUrl);
    const safeEndpoint = this.sanitizeEndpoint(endpoint);
    const requestUrl = new URL(safeEndpoint, `${baseUrl}/`);
    const basePath = base.pathname.endsWith('/') ? base.pathname : `${base.pathname}/`;

    if (
      requestUrl.protocol !== base.protocol ||
      requestUrl.hostname.toLowerCase() !== base.hostname.toLowerCase() ||
      requestUrl.port !== base.port ||
      !requestUrl.pathname.startsWith(basePath)
    ) {
      throw new HttpException('GitLab API URL validation failed', HttpStatus.BAD_REQUEST);
    }

    try {
      // lgtm[js/request-forgery]
      // codeql[js/request-forgery]
      const response = await fetch(requestUrl.toString(), {
        method,
        headers: this.getHeaders(config.token),
        body: body ? JSON.stringify(body) : undefined,
      });

      if (!response.ok) {
        const errorBody = await response.text();
        throw new HttpException(
          `GitLab API error: ${response.status} - ${errorBody}`,
          response.status,
        );
      }

      return (await response.json()) as T;
    } catch (error) {
      if (error instanceof HttpException) {
        throw error;
      }
      this.logger.error(`GitLab API request failed: ${getErrorMessage(error)}`);
      throw new HttpException('Failed to connect to GitLab API', HttpStatus.SERVICE_UNAVAILABLE);
    }
  }

  private calculateHash(data: unknown): string {
    return createHash('sha256').update(JSON.stringify(data)).digest('hex');
  }

  private encodeProjectId(projectId: string | number): string {
    return typeof projectId === 'string' ? encodeURIComponent(projectId) : String(projectId);
  }

  /**
   * Fetch pipelines
   */
  async fetchPipelines(
    config: GitLabConfig,
    options: { perPage?: number; page?: number; status?: string; ref?: string } = {},
  ): Promise<GitLabEvidenceResult[]> {
    const { perPage = 20, page = 1, status, ref } = options;
    const projectId = this.encodeProjectId(config.projectId);
    let endpoint = `/projects/${projectId}/pipelines?per_page=${perPage}&page=${page}`;
    if (status) {
      endpoint += `&status=${status}`;
    }
    if (ref) {
      endpoint += `&ref=${ref}`;
    }

    const pipelines = await this.makeRequest<GitLabPipeline[]>(config, endpoint);

    return pipelines.map((pipeline) => ({
      type: 'pipeline' as const,
      sourceId: `gitlab-pipeline-${pipeline.id}`,
      sourceUrl: pipeline.web_url,
      data: {
        id: pipeline.id,
        iid: pipeline.iid,
        sha: pipeline.sha,
        ref: pipeline.ref,
        status: pipeline.status,
        source: pipeline.source,
        tag: pipeline.tag,
        user: pipeline.user.username,
        startedAt: pipeline.started_at,
        finishedAt: pipeline.finished_at,
        duration: pipeline.duration,
        queuedDuration: pipeline.queued_duration,
        coverage: pipeline.coverage,
        yamlErrors: pipeline.yaml_errors,
      },
      hash: this.calculateHash(pipeline),
      timestamp: new Date(pipeline.updated_at),
      metadata: {
        provider: 'gitlab',
        projectId: config.projectId,
        resourceType: 'pipeline',
      },
    }));
  }

  /**
   * Fetch jobs for a pipeline
   */
  async fetchPipelineJobs(
    config: GitLabConfig,
    pipelineId: number,
  ): Promise<GitLabEvidenceResult[]> {
    const projectId = this.encodeProjectId(config.projectId);
    const endpoint = `/projects/${projectId}/pipelines/${pipelineId}/jobs`;

    const jobs = await this.makeRequest<GitLabJob[]>(config, endpoint);

    return jobs.map((job) => ({
      type: 'job' as const,
      sourceId: `gitlab-job-${job.id}`,
      sourceUrl: job.web_url,
      data: {
        id: job.id,
        name: job.name,
        stage: job.stage,
        status: job.status,
        ref: job.ref,
        tag: job.tag,
        user: job.user.username,
        commitId: job.commit.id,
        commitTitle: job.commit.title,
        startedAt: job.started_at,
        finishedAt: job.finished_at,
        duration: job.duration,
        coverage: job.coverage,
        allowFailure: job.allow_failure,
        failureReason: job.failure_reason,
        hasArtifacts: job.artifacts.length > 0,
        artifactTypes: job.artifacts.map((a) => a.file_type),
        runner: job.runner?.description,
      },
      hash: this.calculateHash(job),
      timestamp: new Date(job.finished_at || job.started_at || job.created_at),
      metadata: {
        provider: 'gitlab',
        projectId: config.projectId,
        pipelineId,
        resourceType: 'job',
      },
    }));
  }

  /**
   * Fetch pipeline test report
   */
  async fetchTestReport(
    config: GitLabConfig,
    pipelineId: number,
  ): Promise<GitLabEvidenceResult | null> {
    try {
      const projectId = this.encodeProjectId(config.projectId);
      const endpoint = `/projects/${projectId}/pipelines/${pipelineId}/test_report`;

      const report = await this.makeRequest<GitLabTestReport>(config, endpoint);

      return {
        type: 'test_report' as const,
        sourceId: `gitlab-test-report-${pipelineId}`,
        sourceUrl: `https://gitlab.com/api/v4/projects/${projectId}/pipelines/${pipelineId}/test_report`,
        data: {
          pipelineId,
          totalTime: report.total_time,
          totalCount: report.total_count,
          successCount: report.success_count,
          failedCount: report.failed_count,
          skippedCount: report.skipped_count,
          errorCount: report.error_count,
          suites: report.test_suites.map((suite) => ({
            name: suite.name,
            totalCount: suite.total_count,
            successCount: suite.success_count,
            failedCount: suite.failed_count,
            skippedCount: suite.skipped_count,
            errorCount: suite.error_count,
          })),
        },
        hash: this.calculateHash(report),
        timestamp: new Date(),
        metadata: {
          provider: 'gitlab',
          projectId: config.projectId,
          pipelineId,
          resourceType: 'test_report',
        },
      };
    } catch (error) {
      this.logger.warn(
        `Failed to fetch test report for pipeline ${pipelineId}: ${getErrorMessage(error)}`,
      );
      return null;
    }
  }

  /**
   * Fetch merge requests
   */
  async fetchMergeRequests(
    config: GitLabConfig,
    options: {
      state?: 'opened' | 'closed' | 'merged' | 'all';
      perPage?: number;
      page?: number;
    } = {},
  ): Promise<GitLabEvidenceResult[]> {
    const { state = 'all', perPage = 20, page = 1 } = options;
    const projectId = this.encodeProjectId(config.projectId);
    const endpoint = `/projects/${projectId}/merge_requests?state=${state}&per_page=${perPage}&page=${page}`;

    const mergeRequests = await this.makeRequest<GitLabMergeRequest[]>(config, endpoint);

    return mergeRequests.map((mr) => ({
      type: 'merge_request' as const,
      sourceId: `gitlab-mr-${mr.iid}`,
      sourceUrl: mr.web_url,
      data: {
        iid: mr.iid,
        title: mr.title,
        state: mr.state,
        draft: mr.draft,
        author: mr.author.username,
        assignees: mr.assignees.map((a) => a.username),
        reviewers: mr.reviewers.map((r) => r.username),
        targetBranch: mr.target_branch,
        sourceBranch: mr.source_branch,
        sha: mr.sha,
        mergeCommitSha: mr.merge_commit_sha,
        squashCommitSha: mr.squash_commit_sha,
        mergeStatus: mr.merge_status,
        hasConflicts: mr.has_conflicts,
        changesCount: mr.changes_count,
        labels: mr.labels,
        mergedBy: mr.merged_by?.username,
        mergedAt: mr.merged_at,
        createdAt: mr.created_at,
        updatedAt: mr.updated_at,
      },
      hash: this.calculateHash(mr),
      timestamp: new Date(mr.updated_at),
      metadata: {
        provider: 'gitlab',
        projectId: config.projectId,
        resourceType: 'merge_request',
      },
    }));
  }

  /**
   * Fetch releases
   */
  async fetchReleases(
    config: GitLabConfig,
    options: { perPage?: number; page?: number } = {},
  ): Promise<GitLabEvidenceResult[]> {
    const { perPage = 20, page = 1 } = options;
    const projectId = this.encodeProjectId(config.projectId);
    const endpoint = `/projects/${projectId}/releases?per_page=${perPage}&page=${page}`;

    const releases = await this.makeRequest<GitLabRelease[]>(config, endpoint);

    return releases.map((release) => ({
      type: 'release' as const,
      sourceId: `gitlab-release-${release.tag_name}`,
      sourceUrl: release._links.self,
      data: {
        tagName: release.tag_name,
        name: release.name,
        description: release.description,
        author: release.author.username,
        commitId: release.commit.id,
        commitTitle: release.commit.title,
        releasedAt: release.released_at,
        createdAt: release.created_at,
        assetsCount: release.assets.count,
        sources: release.assets.sources.map((s) => s.format),
        links: release.assets.links.map((l) => ({ name: l.name, type: l.link_type })),
      },
      hash: this.calculateHash(release),
      timestamp: new Date(release.released_at),
      metadata: {
        provider: 'gitlab',
        projectId: config.projectId,
        resourceType: 'release',
      },
    }));
  }

  /**
   * Fetch project vulnerabilities
   */
  async fetchVulnerabilities(
    config: GitLabConfig,
    options: { perPage?: number; page?: number; state?: string; severity?: string } = {},
  ): Promise<GitLabEvidenceResult[]> {
    try {
      const { perPage = 50, page = 1, state, severity } = options;
      const projectId = this.encodeProjectId(config.projectId);
      let endpoint = `/projects/${projectId}/vulnerabilities?per_page=${perPage}&page=${page}`;
      if (state) {
        endpoint += `&state=${state}`;
      }
      if (severity) {
        endpoint += `&severity=${severity}`;
      }

      const vulnerabilities = await this.makeRequest<GitLabVulnerability[]>(config, endpoint);

      return vulnerabilities.map((vuln) => ({
        type: 'vulnerability' as const,
        sourceId: `gitlab-vuln-${vuln.id}`,
        sourceUrl: `https://gitlab.com/${vuln.project.full_path}/-/security/vulnerabilities/${vuln.id}`,
        data: {
          id: vuln.id,
          title: vuln.title,
          description: vuln.description,
          state: vuln.state,
          severity: vuln.severity,
          confidence: vuln.confidence,
          reportType: vuln.report_type,
          scanner: vuln.scanner.name,
          scannerVendor: vuln.scanner.vendor,
          identifiers: vuln.identifiers.map((i) => ({
            type: i.external_type,
            id: i.external_id,
            name: i.name,
          })),
          location: vuln.location,
          solution: vuln.solution,
          detectedAt: vuln.detected_at,
          resolvedAt: vuln.resolved_at,
          dismissedAt: vuln.dismissed_at,
        },
        hash: this.calculateHash(vuln),
        timestamp: new Date(vuln.updated_at),
        metadata: {
          provider: 'gitlab',
          projectId: config.projectId,
          resourceType: 'vulnerability',
        },
      }));
    } catch (error) {
      this.logger.warn(`Failed to fetch vulnerabilities: ${getErrorMessage(error)}`);
      return [];
    }
  }

  /**
   * Fetch code coverage history
   */
  async fetchCoverageHistory(
    config: GitLabConfig,
    options: { ref?: string; startDate?: string; endDate?: string } = {},
  ): Promise<GitLabEvidenceResult | null> {
    try {
      const projectId = this.encodeProjectId(config.projectId);
      const { ref = 'main' } = options;
      const endpoint = `/projects/${projectId}/jobs?scope=success&per_page=50`;

      const jobs = await this.makeRequest<GitLabJob[]>(config, endpoint);
      const coverageJobs = jobs.filter((j) => j.coverage !== null && j.ref === ref);

      if (coverageJobs.length === 0) {
        return null;
      }

      const coverageData = coverageJobs.map((job) => ({
        jobId: job.id,
        name: job.name,
        coverage: job.coverage,
        finishedAt: job.finished_at,
        commitId: job.commit.id,
      }));

      return {
        type: 'coverage' as const,
        sourceId: `gitlab-coverage-${projectId}-${ref}`,
        sourceUrl: `https://gitlab.com/api/v4/projects/${projectId}/jobs`,
        data: {
          ref,
          coverageHistory: coverageData,
          latestCoverage: coverageData[0]?.coverage,
          jobCount: coverageData.length,
          averageCoverage:
            coverageData.reduce((sum, j) => sum + (j.coverage || 0), 0) / coverageData.length,
        },
        hash: this.calculateHash(coverageData),
        timestamp: new Date(),
        metadata: {
          provider: 'gitlab',
          projectId: config.projectId,
          ref,
          resourceType: 'coverage_history',
        },
      };
    } catch (error) {
      this.logger.warn(`Failed to fetch coverage history: ${getErrorMessage(error)}`);
      return null;
    }
  }

  /**
   * Ingest all evidence from a GitLab project
   */
  async ingestAllEvidence(
    config: GitLabConfig,
    sessionId: string,
  ): Promise<{
    ingested: number;
    errors: string[];
    results: Record<string, number>;
  }> {
    const results: Record<string, number> = {
      pipelines: 0,
      jobs: 0,
      test_reports: 0,
      merge_requests: 0,
      releases: 0,
      vulnerabilities: 0,
      coverage: 0,
    };
    const errors: string[] = [];
    let totalIngested = 0;

    // Fetch pipelines
    try {
      const pipelines = await this.fetchPipelines(config, { perPage: 20 });
      for (const pipeline of pipelines) {
        await this.saveEvidence(sessionId, pipeline);
        totalIngested++;
      }
      results.pipelines = pipelines.length;

      // Fetch jobs and test reports for recent pipelines
      for (const pipeline of pipelines.slice(0, 5)) {
        const pipelineId = pipeline.data.id as number;
        try {
          const jobs = await this.fetchPipelineJobs(config, pipelineId);
          for (const job of jobs) {
            await this.saveEvidence(sessionId, job);
            totalIngested++;
          }
          results.jobs += jobs.length;
        } catch (error) {
          errors.push(`Jobs for pipeline ${pipelineId}: ${getErrorMessage(error)}`);
        }

        try {
          const testReport = await this.fetchTestReport(config, pipelineId);
          if (testReport) {
            await this.saveEvidence(sessionId, testReport);
            totalIngested++;
            results.test_reports++;
          }
        } catch (error) {
          errors.push(`Test report for pipeline ${pipelineId}: ${getErrorMessage(error)}`);
        }
      }
    } catch (error) {
      errors.push(`Pipelines: ${getErrorMessage(error)}`);
    }

    // Fetch merge requests
    try {
      const mrs = await this.fetchMergeRequests(config, { state: 'all', perPage: 30 });
      for (const mr of mrs) {
        await this.saveEvidence(sessionId, mr);
        totalIngested++;
      }
      results.merge_requests = mrs.length;
    } catch (error) {
      errors.push(`Merge requests: ${getErrorMessage(error)}`);
    }

    // Fetch releases
    try {
      const releases = await this.fetchReleases(config, { perPage: 10 });
      for (const release of releases) {
        await this.saveEvidence(sessionId, release);
        totalIngested++;
      }
      results.releases = releases.length;
    } catch (error) {
      errors.push(`Releases: ${getErrorMessage(error)}`);
    }

    // Fetch vulnerabilities
    try {
      const vulns = await this.fetchVulnerabilities(config);
      for (const vuln of vulns) {
        await this.saveEvidence(sessionId, vuln);
        totalIngested++;
      }
      results.vulnerabilities = vulns.length;
    } catch (error) {
      errors.push(`Vulnerabilities: ${getErrorMessage(error)}`);
    }

    // Fetch coverage history
    try {
      const coverage = await this.fetchCoverageHistory(config);
      if (coverage) {
        await this.saveEvidence(sessionId, coverage);
        totalIngested++;
        results.coverage = 1;
      }
    } catch (error) {
      errors.push(`Coverage: ${getErrorMessage(error)}`);
    }

    this.logger.log(
      `GitLab ingestion complete: ${totalIngested} items from project ${config.projectId}`,
    );

    return {
      ingested: totalIngested,
      errors,
      results,
    };
  }

  /**
   * Save evidence - stores in memory/cache for later processing
   * Note: Actual persistence requires linking to EvidenceRegistry via questionId
   */
  private async saveEvidence(sessionId: string, evidence: GitLabEvidenceResult): Promise<void> {
    // Log evidence for audit trail
    this.logger.debug(
      `Ingested ${evidence.type} evidence: ${evidence.sourceId} for session ${sessionId}`,
    );
    // Evidence data is returned via ingestAllEvidence results
    // Actual database persistence should be handled by the calling service
  }

  /**
   * Verify GitLab webhook token
   */
  verifyWebhookToken(requestToken: string, configuredToken: string): boolean {
    return requestToken === configuredToken;
  }
}

import { Injectable, Logger, HttpException, HttpStatus } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '@libs/database';
import { createHash } from 'crypto';

// Helper to extract error message from unknown error type
function getErrorMessage(error: unknown): string {
  if (error instanceof Error) {
    return error.message;
  }
  if (typeof error === 'string') {
    return error;
  }
  return 'Unknown error';
}

interface JiraConfig {
  domain: string; // e.g., 'your-org.atlassian.net'
  email: string;
  apiToken: string;
}

interface ConfluenceConfig extends JiraConfig {
  spaceKey: string;
}

interface JiraIssue {
  id: string;
  key: string;
  self: string;
  fields: {
    summary: string;
    description: string | null;
    issuetype: { name: string; iconUrl: string };
    status: { name: string; statusCategory: { key: string; name: string } };
    priority: { name: string } | null;
    assignee: { displayName: string; emailAddress: string } | null;
    reporter: { displayName: string; emailAddress: string };
    created: string;
    updated: string;
    resolutiondate: string | null;
    labels: string[];
    components: Array<{ name: string }>;
    fixVersions: Array<{ name: string; releaseDate?: string }>;
    customfield_10020?: Array<{ name: string; startDate?: string; endDate?: string }>; // Sprint
    customfield_10016?: number; // Story points
    parent?: { key: string; fields: { summary: string } };
    subtasks?: Array<{ key: string; fields: { summary: string; status: { name: string } } }>;
    attachment?: Array<{
      id: string;
      filename: string;
      mimeType: string;
      size: number;
      created: string;
    }>;
    comment?: {
      total: number;
      comments: Array<{
        id: string;
        author: { displayName: string };
        body: string;
        created: string;
        updated: string;
      }>;
    };
  };
}

interface JiraSprint {
  id: number;
  self: string;
  state: string;
  name: string;
  startDate?: string;
  endDate?: string;
  completeDate?: string;
  originBoardId: number;
  goal?: string;
}

interface JiraProject {
  id: string;
  key: string;
  name: string;
  self: string;
  projectTypeKey: string;
  style: string;
  isPrivate: boolean;
  description?: string;
  lead: { displayName: string; emailAddress: string };
}

interface ConfluencePage {
  id: string;
  type: string;
  status: string;
  title: string;
  space: { key: string; name: string };
  body?: {
    storage?: { value: string };
    view?: { value: string };
  };
  version: { number: number; when: string; by: { displayName: string } };
  ancestors: Array<{ id: string; title: string }>;
  children?: {
    page?: { results: Array<{ id: string; title: string }> };
    attachment?: { results: Array<{ id: string; title: string; mediaType: string }> };
  };
  _links: { webui: string; self: string };
}

interface ConfluenceSearchResult {
  results: ConfluencePage[];
  start: number;
  limit: number;
  size: number;
  totalSize: number;
  _links: { next?: string };
}

export interface JiraEvidenceResult {
  type: 'jira_issue' | 'jira_sprint' | 'jira_project' | 'confluence_page' | 'confluence_attachment';
  sourceId: string;
  sourceUrl: string;
  data: Record<string, unknown>;
  hash: string;
  timestamp: Date;
  metadata: Record<string, unknown>;
}

@Injectable()
export class JiraConfluenceAdapter {
  private readonly logger = new Logger(JiraConfluenceAdapter.name);

  constructor(
    private readonly configService: ConfigService,
    _prisma: PrismaService,
  ) {}

  private getTrustedJiraDomain(): string {
    const trustedDomain = (this.configService.get<string>('JIRA_DOMAIN') || '')
      .trim()
      .toLowerCase();

    if (!trustedDomain) {
      throw new HttpException('JIRA_DOMAIN is not configured', HttpStatus.SERVICE_UNAVAILABLE);
    }

    return trustedDomain;
  }

  private getHeaders(config: JiraConfig): Record<string, string> {
    const auth = Buffer.from(`${config.email}:${config.apiToken}`).toString('base64');
    return {
      Authorization: `Basic ${auth}`,
      Accept: 'application/json',
      'Content-Type': 'application/json',
    };
  }

  /**
   * Validate the Jira/Confluence domain to reduce SSRF risk.
   * Only allow plain hostnames that look like Atlassian cloud domains and
   * reject obvious localhost, IP literal, or malformed values.
   */
  private validateDomain(config: JiraConfig): void {
    const rawDomain = (config.domain || '').trim().toLowerCase();

    // Must be non-empty and reasonably short
    if (!rawDomain || rawDomain.length > 255) {
      throw new HttpException('Invalid Jira domain', HttpStatus.BAD_REQUEST);
    }

    // Disallow schemes, paths, ports, credentials, and backslashes
    if (
      rawDomain.includes('://') ||
      rawDomain.includes('/') ||
      rawDomain.includes('\\') ||
      rawDomain.includes('@') ||
      rawDomain.includes(':')
    ) {
      throw new HttpException('Invalid Jira domain format', HttpStatus.BAD_REQUEST);
    }

    // Disallow localhost and common loopback variants
    if (
      rawDomain === 'localhost' ||
      rawDomain.endsWith('.localhost') ||
      rawDomain === '127.0.0.1' ||
      rawDomain.startsWith('127.') ||
      rawDomain === '::1'
    ) {
      throw new HttpException('Jira domain not allowed', HttpStatus.BAD_REQUEST);
    }

    // Disallow common private IPv4 ranges by simple prefix match
    if (
      rawDomain.startsWith('10.') ||
      rawDomain.startsWith('192.168.') ||
      rawDomain.match(/^172\.(1[6-9]|2[0-9]|3[0-1])\./)
    ) {
      throw new HttpException('Jira domain not allowed', HttpStatus.BAD_REQUEST);
    }

    // Enforce Atlassian cloud domains (adjust if self-hosted Jira must be supported)
    if (!rawDomain.endsWith('.atlassian.net')) {
      throw new HttpException('Unsupported Jira domain', HttpStatus.BAD_REQUEST);
    }
  }

  private sanitizeEndpoint(endpoint: string): string {
    const candidate = endpoint.trim();

    if (!candidate) {
      throw new HttpException('Invalid Atlassian API endpoint', HttpStatus.BAD_REQUEST);
    }

    if (
      candidate.includes('://') ||
      candidate.startsWith('//') ||
      candidate.includes('\\') ||
      candidate.includes('@') ||
      /(^|\/)\.\.(\/|$)/.test(candidate)
    ) {
      throw new HttpException('Invalid Atlassian API endpoint format', HttpStatus.BAD_REQUEST);
    }

    return candidate.startsWith('/') ? candidate.slice(1) : candidate;
  }

  private async makeRequest<T>(
    config: JiraConfig,
    endpoint: string,
    method: string = 'GET',
    body?: unknown,
    isConfluence: boolean = false,
    isAgile: boolean = false,
  ): Promise<T> {
    const normalizedDomain = this.getTrustedJiraDomain();
    if (config.domain.trim().toLowerCase() !== normalizedDomain) {
      throw new HttpException(
        'Configured Jira domain does not match trusted server configuration',
        HttpStatus.BAD_REQUEST,
      );
    }
    this.validateDomain({ ...config, domain: normalizedDomain });
    const safeEndpoint = this.sanitizeEndpoint(endpoint);

    let baseUrl: string;
    if (isConfluence) {
      baseUrl = `https://${normalizedDomain}/wiki/rest/api`;
    } else if (isAgile) {
      baseUrl = `https://${normalizedDomain}/rest/agile/1.0`;
    } else {
      baseUrl = `https://${normalizedDomain}/rest/api/3`;
    }

    const requestUrl = new URL(safeEndpoint, `${baseUrl}/`);
    const trustedBaseUrl = new URL(`${baseUrl}/`);
    const trustedBasePath = trustedBaseUrl.pathname.endsWith('/')
      ? trustedBaseUrl.pathname
      : `${trustedBaseUrl.pathname}/`;

    if (
      requestUrl.protocol !== 'https:' ||
      requestUrl.hostname.toLowerCase() !== normalizedDomain ||
      requestUrl.port !== trustedBaseUrl.port ||
      !requestUrl.pathname.startsWith(trustedBasePath)
    ) {
      throw new HttpException('Atlassian API URL validation failed', HttpStatus.BAD_REQUEST);
    }

    try {
      // lgtm[js/request-forgery]
      // codeql[js/request-forgery]
      const response = await fetch(requestUrl.toString(), {
        method,
        headers: this.getHeaders(config),
        body: body ? JSON.stringify(body) : undefined,
      });

      if (!response.ok) {
        const errorBody = await response.text();
        throw new HttpException(
          `Atlassian API error: ${response.status} - ${errorBody}`,
          response.status,
        );
      }

      return (await response.json()) as T;
    } catch (error) {
      if (error instanceof HttpException) {
        throw error;
      }
      this.logger.error(`Atlassian API request failed: ${getErrorMessage(error)}`);
      throw new HttpException('Failed to connect to Atlassian API', HttpStatus.SERVICE_UNAVAILABLE);
    }
  }

  private calculateHash(data: unknown): string {
    return createHash('sha256').update(JSON.stringify(data)).digest('hex');
  }

  // ==================== JIRA METHODS ====================

  /**
   * Fetch issues using JQL
   */
  async fetchIssues(
    config: JiraConfig,
    options: {
      jql?: string;
      projectKey?: string;
      maxResults?: number;
      startAt?: number;
      fields?: string[];
    } = {},
  ): Promise<JiraEvidenceResult[]> {
    const {
      jql,
      projectKey,
      maxResults = 50,
      startAt = 0,
      fields = [
        'summary',
        'description',
        'issuetype',
        'status',
        'priority',
        'assignee',
        'reporter',
        'created',
        'updated',
        'resolutiondate',
        'labels',
        'components',
        'fixVersions',
        'customfield_10020',
        'customfield_10016',
        'parent',
        'subtasks',
        'attachment',
        'comment',
      ],
    } = options;

    const searchJql =
      jql ||
      (projectKey ? `project = ${projectKey} ORDER BY updated DESC` : 'ORDER BY updated DESC');

    const endpoint = `/search?jql=${encodeURIComponent(searchJql)}&maxResults=${maxResults}&startAt=${startAt}&fields=${fields.join(',')}`;

    const response = await this.makeRequest<{ issues: JiraIssue[]; total: number }>(
      config,
      endpoint,
    );

    return response.issues.map((issue) => ({
      type: 'jira_issue' as const,
      sourceId: `jira-issue-${issue.key}`,
      sourceUrl: `https://${config.domain}/browse/${issue.key}`,
      data: {
        id: issue.id,
        key: issue.key,
        summary: issue.fields.summary,
        description: issue.fields.description,
        issueType: issue.fields.issuetype.name,
        status: issue.fields.status.name,
        statusCategory: issue.fields.status.statusCategory.name,
        priority: issue.fields.priority?.name,
        assignee: issue.fields.assignee?.displayName,
        assigneeEmail: issue.fields.assignee?.emailAddress,
        reporter: issue.fields.reporter.displayName,
        reporterEmail: issue.fields.reporter.emailAddress,
        created: issue.fields.created,
        updated: issue.fields.updated,
        resolved: issue.fields.resolutiondate,
        labels: issue.fields.labels,
        components: issue.fields.components.map((c) => c.name),
        fixVersions: issue.fields.fixVersions.map((v) => ({
          name: v.name,
          releaseDate: v.releaseDate,
        })),
        sprint: issue.fields.customfield_10020?.[0]?.name,
        storyPoints: issue.fields.customfield_10016,
        parent: issue.fields.parent?.key,
        parentSummary: issue.fields.parent?.fields.summary,
        subtasks: issue.fields.subtasks?.map((s) => ({
          key: s.key,
          summary: s.fields.summary,
          status: s.fields.status.name,
        })),
        attachmentCount: issue.fields.attachment?.length || 0,
        commentCount: issue.fields.comment?.total || 0,
      },
      hash: this.calculateHash(issue),
      timestamp: new Date(issue.fields.updated),
      metadata: {
        provider: 'jira',
        domain: config.domain,
        resourceType: 'issue',
      },
    }));
  }

  /**
   * Fetch a specific issue with all details
   */
  async fetchIssueDetails(config: JiraConfig, issueKey: string): Promise<JiraEvidenceResult> {
    const endpoint = `/issue/${issueKey}?expand=changelog,renderedFields`;
    const issue = await this.makeRequest<JiraIssue>(config, endpoint);

    return {
      type: 'jira_issue' as const,
      sourceId: `jira-issue-${issue.key}`,
      sourceUrl: `https://${config.domain}/browse/${issue.key}`,
      data: {
        id: issue.id,
        key: issue.key,
        summary: issue.fields.summary,
        description: issue.fields.description,
        issueType: issue.fields.issuetype.name,
        status: issue.fields.status.name,
        statusCategory: issue.fields.status.statusCategory.name,
        priority: issue.fields.priority?.name,
        assignee: issue.fields.assignee?.displayName,
        reporter: issue.fields.reporter.displayName,
        created: issue.fields.created,
        updated: issue.fields.updated,
        resolved: issue.fields.resolutiondate,
        labels: issue.fields.labels,
        components: issue.fields.components.map((c) => c.name),
        attachments: issue.fields.attachment?.map((a) => ({
          id: a.id,
          filename: a.filename,
          mimeType: a.mimeType,
          size: a.size,
          created: a.created,
        })),
        comments: issue.fields.comment?.comments.map((c) => ({
          id: c.id,
          author: c.author.displayName,
          body: c.body,
          created: c.created,
        })),
      },
      hash: this.calculateHash(issue),
      timestamp: new Date(issue.fields.updated),
      metadata: {
        provider: 'jira',
        domain: config.domain,
        resourceType: 'issue_detail',
      },
    };
  }

  /**
   * Fetch sprints from a board
   */
  async fetchSprints(
    config: JiraConfig,
    boardId: number,
    options: { state?: 'active' | 'closed' | 'future'; maxResults?: number } = {},
  ): Promise<JiraEvidenceResult[]> {
    const { state, maxResults = 50 } = options;
    let endpoint = `/board/${boardId}/sprint?maxResults=${maxResults}`;
    if (state) {
      endpoint += `&state=${state}`;
    }

    const data = await this.makeRequest<{ values: JiraSprint[] }>(
      config,
      endpoint,
      'GET',
      undefined,
      false,
      true,
    );

    return data.values.map((sprint) => ({
      type: 'jira_sprint' as const,
      sourceId: `jira-sprint-${sprint.id}`,
      sourceUrl: sprint.self,
      data: {
        id: sprint.id,
        name: sprint.name,
        state: sprint.state,
        goal: sprint.goal,
        startDate: sprint.startDate,
        endDate: sprint.endDate,
        completeDate: sprint.completeDate,
        boardId: sprint.originBoardId,
      },
      hash: this.calculateHash(sprint),
      timestamp: new Date(sprint.completeDate || sprint.endDate || sprint.startDate || new Date()),
      metadata: {
        provider: 'jira',
        domain: config.domain,
        boardId,
        resourceType: 'sprint',
      },
    }));
  }

  /**
   * Fetch project details
   */
  async fetchProject(config: JiraConfig, projectKey: string): Promise<JiraEvidenceResult> {
    const endpoint = `/project/${projectKey}`;
    const project = await this.makeRequest<JiraProject>(config, endpoint);

    return {
      type: 'jira_project' as const,
      sourceId: `jira-project-${project.key}`,
      sourceUrl: `https://${config.domain}/browse/${project.key}`,
      data: {
        id: project.id,
        key: project.key,
        name: project.name,
        description: project.description,
        projectType: project.projectTypeKey,
        style: project.style,
        isPrivate: project.isPrivate,
        lead: project.lead.displayName,
        leadEmail: project.lead.emailAddress,
      },
      hash: this.calculateHash(project),
      timestamp: new Date(),
      metadata: {
        provider: 'jira',
        domain: config.domain,
        resourceType: 'project',
      },
    };
  }

  // ==================== CONFLUENCE METHODS ====================

  /**
   * Search Confluence pages
   */
  async searchPages(
    config: ConfluenceConfig,
    options: {
      cql?: string;
      query?: string;
      limit?: number;
      start?: number;
      expand?: string[];
    } = {},
  ): Promise<JiraEvidenceResult[]> {
    const {
      cql,
      query,
      limit = 25,
      start = 0,
      expand = ['space', 'version', 'ancestors', 'children.page', 'children.attachment'],
    } = options;

    let endpoint: string;
    if (cql) {
      endpoint = `/content/search?cql=${encodeURIComponent(cql)}&limit=${limit}&start=${start}&expand=${expand.join(',')}`;
    } else if (query) {
      endpoint = `/content/search?cql=${encodeURIComponent(`space = ${config.spaceKey} AND text ~ "${query}"`)}&limit=${limit}&start=${start}&expand=${expand.join(',')}`;
    } else {
      endpoint = `/content?spaceKey=${config.spaceKey}&limit=${limit}&start=${start}&expand=${expand.join(',')}`;
    }

    const response = await this.makeRequest<ConfluenceSearchResult>(
      config,
      endpoint,
      'GET',
      undefined,
      true,
    );

    return response.results.map((page) => this.mapConfluencePageToEvidence(config, page));
  }

  /**
   * Fetch a specific Confluence page
   */
  async fetchPage(
    config: ConfluenceConfig,
    pageId: string,
    expand: string[] = [
      'space',
      'body.storage',
      'body.view',
      'version',
      'ancestors',
      'children.page',
      'children.attachment',
    ],
  ): Promise<JiraEvidenceResult> {
    const endpoint = `/content/${pageId}?expand=${expand.join(',')}`;
    const page = await this.makeRequest<ConfluencePage>(config, endpoint, 'GET', undefined, true);
    return this.mapConfluencePageToEvidence(config, page);
  }

  /**
   * Fetch pages by label
   */
  async fetchPagesByLabel(
    config: ConfluenceConfig,
    label: string,
    options: { limit?: number; start?: number } = {},
  ): Promise<JiraEvidenceResult[]> {
    const { limit = 25, start = 0 } = options;
    const cql = `space = ${config.spaceKey} AND label = "${label}"`;
    return this.searchPages(config, { cql, limit, start });
  }

  /**
   * Fetch child pages of a parent
   */
  async fetchChildPages(
    config: ConfluenceConfig,
    parentId: string,
    options: { limit?: number; start?: number } = {},
  ): Promise<JiraEvidenceResult[]> {
    const { limit = 25, start = 0 } = options;
    const endpoint = `/content/${parentId}/child/page?limit=${limit}&start=${start}&expand=space,version,ancestors`;
    const response = await this.makeRequest<ConfluenceSearchResult>(
      config,
      endpoint,
      'GET',
      undefined,
      true,
    );
    return response.results.map((page) => this.mapConfluencePageToEvidence(config, page));
  }

  /**
   * Create or update a Confluence page
   */
  async syncPage(
    config: ConfluenceConfig,
    options: {
      title: string;
      content: string;
      parentId?: string;
      existingPageId?: string;
      labels?: string[];
    },
  ): Promise<JiraEvidenceResult> {
    const { title, content, parentId, existingPageId, labels } = options;

    const body: Record<string, unknown> = {
      type: 'page',
      title,
      space: { key: config.spaceKey },
      body: {
        storage: {
          value: content,
          representation: 'storage',
        },
      },
    };

    if (parentId) {
      body.ancestors = [{ id: parentId }];
    }

    let page: ConfluencePage;

    if (existingPageId) {
      // Get current version for update
      const existingPage = await this.makeRequest<ConfluencePage>(
        config,
        `/content/${existingPageId}`,
        'GET',
        undefined,
        true,
      );
      body.version = { number: existingPage.version.number + 1 };
      page = await this.makeRequest<ConfluencePage>(
        config,
        `/content/${existingPageId}`,
        'PUT',
        body,
        true,
      );
    } else {
      page = await this.makeRequest<ConfluencePage>(config, '/content', 'POST', body, true);
    }

    // Add labels if specified
    if (labels && labels.length > 0) {
      await this.addLabelsToPage(config, page.id, labels);
    }

    return this.mapConfluencePageToEvidence(config, page);
  }

  /**
   * Add labels to a page
   */
  private async addLabelsToPage(
    config: ConfluenceConfig,
    pageId: string,
    labels: string[],
  ): Promise<void> {
    const labelsBody = labels.map((label) => ({ prefix: 'global', name: label }));
    await this.makeRequest(config, `/content/${pageId}/label`, 'POST', labelsBody, true);
  }

  private mapConfluencePageToEvidence(
    config: ConfluenceConfig,
    page: ConfluencePage,
  ): JiraEvidenceResult {
    return {
      type: 'confluence_page' as const,
      sourceId: `confluence-page-${page.id}`,
      sourceUrl: `https://${config.domain}/wiki${page._links.webui}`,
      data: this.extractConfluencePageData(page),
      hash: this.calculateHash(page),
      timestamp: new Date(page.version?.when || new Date()),
      metadata: {
        provider: 'confluence',
        domain: config.domain,
        spaceKey: config.spaceKey,
        resourceType: 'page',
      },
    };
  }

  private extractConfluencePageData(page: ConfluencePage): Record<string, unknown> {
    return {
      id: page.id,
      title: page.title,
      type: page.type,
      status: page.status,
      spaceKey: page.space?.key,
      spaceName: page.space?.name,
      version: page.version?.number,
      versionDate: page.version?.when,
      versionAuthor: page.version?.by?.displayName,
      ancestors: page.ancestors?.map((a) => ({ id: a.id, title: a.title })),
      childPageCount: page.children?.page?.results?.length || 0,
      attachmentCount: page.children?.attachment?.results?.length || 0,
      content: page.body?.storage?.value || page.body?.view?.value,
    };
  }

  // ==================== INTEGRATION METHODS ====================

  /**
   * Sync documentation from Quiz2Biz to Confluence
   */
  async syncDocumentation(
    config: ConfluenceConfig,
    documents: Array<{
      title: string;
      content: string;
      category: string;
      labels: string[];
    }>,
    parentPageId: string,
  ): Promise<{ synced: number; errors: string[] }> {
    const errors: string[] = [];
    let synced = 0;

    // Get existing pages to check for updates
    const existingPages = await this.searchPages(config, {
      cql: `ancestor = ${parentPageId}`,
      limit: 100,
    });

    const existingPageMap = new Map(
      existingPages.map((p) => [p.data.title as string, p.data.id as string]),
    );

    for (const doc of documents) {
      try {
        const existingPageId = existingPageMap.get(doc.title);
        await this.syncPage(config, {
          title: doc.title,
          content: this.wrapInConfluenceStorage(doc.content),
          parentId: parentPageId,
          existingPageId,
          labels: [...doc.labels, 'quiz2biz-generated', doc.category],
        });
        synced++;
      } catch (error) {
        errors.push(`Failed to sync "${doc.title}": ${getErrorMessage(error)}`);
      }
    }

    return { synced, errors };
  }

  /**
   * Wrap markdown-like content in Confluence storage format
   */
  private wrapInConfluenceStorage(content: string): string {
    // Basic markdown to Confluence conversion
    let html = content
      .replace(/^### (.*$)/gim, '<h3>$1</h3>')
      .replace(/^## (.*$)/gim, '<h2>$1</h2>')
      .replace(/^# (.*$)/gim, '<h1>$1</h1>')
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/`(.*?)`/g, '<code>$1</code>')
      .replace(/\n\n/g, '</p><p>')
      .replace(/^- (.*$)/gim, '<li>$1</li>');

    // Wrap lists
    html = html.replace(/(<li>.*<\/li>\n?)+/g, '<ul>$&</ul>');

    return `<p>${html}</p>`;
  }

  /**
   * Ingest all evidence from Jira/Confluence
   */
  async ingestAllEvidence(
    jiraConfig: JiraConfig,
    confluenceConfig: ConfluenceConfig | null,
    sessionId: string,
    projectKey: string,
  ): Promise<{
    ingested: number;
    errors: string[];
    results: Record<string, number>;
  }> {
    const results: Record<string, number> = {
      jira_issues: 0,
      jira_sprints: 0,
      jira_project: 0,
      confluence_pages: 0,
    };
    const errors: string[] = [];
    let totalIngested = 0;

    // Fetch Jira project
    try {
      const project = await this.fetchProject(jiraConfig, projectKey);
      await this.saveEvidence(sessionId, project);
      totalIngested++;
      results.jira_project = 1;
    } catch (error) {
      errors.push(`Jira project: ${getErrorMessage(error)}`);
    }

    // Fetch Jira issues
    try {
      const issues = await this.fetchIssues(jiraConfig, {
        projectKey,
        maxResults: 100,
      });
      for (const issue of issues) {
        await this.saveEvidence(sessionId, issue);
        totalIngested++;
      }
      results.jira_issues = issues.length;
    } catch (error) {
      errors.push(`Jira issues: ${getErrorMessage(error)}`);
    }

    // Fetch Confluence pages if configured
    if (confluenceConfig) {
      try {
        const pages = await this.searchPages(confluenceConfig, { limit: 50 });
        for (const page of pages) {
          await this.saveEvidence(sessionId, page);
          totalIngested++;
        }
        results.confluence_pages = pages.length;
      } catch (error) {
        errors.push(`Confluence pages: ${getErrorMessage(error)}`);
      }
    }

    this.logger.log(`Jira/Confluence ingestion complete: ${totalIngested} items`);

    return {
      ingested: totalIngested,
      errors,
      results,
    };
  }

  /**
   * Save evidence to database
   */
  private async saveEvidence(sessionId: string, evidence: JiraEvidenceResult): Promise<void> {
    // Log evidence for audit trail
    this.logger.debug(
      `Ingested ${evidence.type} evidence: ${evidence.sourceId} for session ${sessionId}`,
    );
    // Evidence data is returned via ingestAllEvidence results
    // Actual database persistence should be handled by the calling service
    // after mapping to appropriate question/evidence relationships
  }
}

import { Injectable } from '@nestjs/common';
import { Condition, ConditionOperator, LogicalOperator } from '../types/rule.types';

@Injectable()
export class ConditionEvaluator {
  /**
   * Evaluate a single condition or nested conditions
   */
  evaluate(condition: Condition, responses: Map<string, unknown>): boolean {
    // Handle nested conditions
    if (condition.nested && condition.nested.length > 0) {
      return this.evaluateNested(condition.nested, condition.logicalOp || 'AND', responses);
    }

    // Evaluate single condition
    if (!condition.field || !condition.operator) {
      return true; // No condition means always true
    }

    const value = responses.get(condition.field);
    return this.evaluateOperator(condition.operator, value, condition.value);
  }

  /**
   * Evaluate nested conditions with logical operator
   */
  private evaluateNested(
    conditions: Condition[],
    operator: LogicalOperator,
    responses: Map<string, unknown>,
  ): boolean {
    const results = conditions.map((c) => this.evaluate(c, responses));

    if (operator === 'AND') {
      return results.every((r) => r);
    } else {
      return results.some((r) => r);
    }
  }

  /** Dispatch map for operator evaluation ÔÇö reduces cyclomatic complexity */
  private readonly operatorHandlers: Record<string, (actual: unknown, expected: unknown) => boolean> = {
    ['equals']: (a, e) => this.equals(a, e),
    ['eq']: (a, e) => this.equals(a, e),
    ['not_equals']: (a, e) => !this.equals(a, e),
    ['ne']: (a, e) => !this.equals(a, e),
    ['includes']: (a, e) => this.includes(a, e),
    ['contains']: (a, e) => this.includes(a, e),
    ['not_includes']: (a, e) => !this.includes(a, e),
    ['not_contains']: (a, e) => !this.includes(a, e),
    ['in']: (a, e) => this.isIn(a, e),
    ['not_in']: (a, e) => !this.isIn(a, e),
    ['greater_than']: (a, e) => this.greaterThan(a, e),
    ['gt']: (a, e) => this.greaterThan(a, e),
    ['less_than']: (a, e) => this.lessThan(a, e),
    ['lt']: (a, e) => this.lessThan(a, e),
    ['greater_than_or_equal']: (a, e) => this.greaterThanOrEqual(a, e),
    ['gte']: (a, e) => this.greaterThanOrEqual(a, e),
    ['less_than_or_equal']: (a, e) => this.lessThanOrEqual(a, e),
    ['lte']: (a, e) => this.lessThanOrEqual(a, e),
    ['between']: (a, e) => this.between(a, e),
    ['is_empty']: (a) => this.isEmpty(a),
    ['is_not_empty']: (a) => !this.isEmpty(a),
    ['starts_with']: (a, e) => this.startsWith(a, e),
    ['ends_with']: (a, e) => this.endsWith(a, e),
    ['matches']: (a, e) => this.matches(a, e),
  };

  /**
   * Evaluate a single operator
   */
  private evaluateOperator(
    operator: ConditionOperator,
    actualValue: unknown,
    expectedValue: unknown,
  ): boolean {
    const handler = this.operatorHandlers[operator];
    return handler ? handler(actualValue, expectedValue) : false;
  }

  /**
   * Check equality (handles various types)
   */
  private equals(actual: unknown, expected: unknown): boolean {
    if (actual === expected) {
      return true;
    }

    // Handle object comparison for response values
    if (typeof actual === 'object' && actual !== null) {
      const actualObj = actual as Record<string, unknown>;

      // Check common response value patterns
      if ('selectedOptionId' in actualObj) {
        return actualObj.selectedOptionId === expected;
      }
      if ('text' in actualObj) {
        return actualObj.text === expected;
      }
      if ('number' in actualObj) {
        return actualObj.number === expected;
      }
      if ('rating' in actualObj) {
        return actualObj.rating === expected;
      }
    }

    return JSON.stringify(actual) === JSON.stringify(expected);
  }

  /**
   * Check if array includes value or if value contains substring
   */
  private includes(actual: unknown, expected: unknown): boolean {
    // Handle response objects
    if (typeof actual === 'object' && actual !== null) {
      const actualObj = actual as Record<string, unknown>;

      // Multi-choice responses
      if ('selectedOptionIds' in actualObj && Array.isArray(actualObj.selectedOptionIds)) {
        return actualObj.selectedOptionIds.includes(expected);
      }

      // Text contains
      if ('text' in actualObj && typeof actualObj.text === 'string') {
        return actualObj.text.includes(String(expected));
      }
    }

    // Array includes
    if (Array.isArray(actual)) {
      return actual.includes(expected);
    }

    // String contains
    if (typeof actual === 'string' && typeof expected === 'string') {
      return actual.includes(expected);
    }

    return false;
  }

  /**
   * Check if value is in an array of expected values
   */
  private isIn(actual: unknown, expected: unknown): boolean {
    if (!Array.isArray(expected)) {
      return false;
    }

    // Handle response objects
    if (typeof actual === 'object' && actual !== null) {
      const actualObj = actual as Record<string, unknown>;

      if ('selectedOptionId' in actualObj) {
        return expected.includes(actualObj.selectedOptionId);
      }
      if ('text' in actualObj) {
        return expected.includes(actualObj.text);
      }
      if ('number' in actualObj) {
        return expected.includes(actualObj.number);
      }
    }

    return expected.includes(actual);
  }

  /**
   * Numeric comparison: greater than
   */
  private greaterThan(actual: unknown, expected: unknown): boolean {
    const actualNum = this.extractNumber(actual);
    const expectedNum = this.extractNumber(expected);

    if (actualNum === null || expectedNum === null) {
      return false;
    }

    return actualNum > expectedNum;
  }

  /**
   * Numeric comparison: less than
   */
  private lessThan(actual: unknown, expected: unknown): boolean {
    const actualNum = this.extractNumber(actual);
    const expectedNum = this.extractNumber(expected);

    if (actualNum === null || expectedNum === null) {
      return false;
    }

    return actualNum < expectedNum;
  }

  /**
   * Numeric comparison: greater than or equal
   */
  private greaterThanOrEqual(actual: unknown, expected: unknown): boolean {
    const actualNum = this.extractNumber(actual);
    const expectedNum = this.extractNumber(expected);

    if (actualNum === null || expectedNum === null) {
      return false;
    }

    return actualNum >= expectedNum;
  }

  /**
   * Numeric comparison: less than or equal
   */
  private lessThanOrEqual(actual: unknown, expected: unknown): boolean {
    const actualNum = this.extractNumber(actual);
    const expectedNum = this.extractNumber(expected);

    if (actualNum === null || expectedNum === null) {
      return false;
    }

    return actualNum <= expectedNum;
  }

  /**
   * Range check: value is between min and max
   */
  private between(actual: unknown, expected: unknown): boolean {
    if (!Array.isArray(expected) || expected.length !== 2) {
      return false;
    }

    const actualNum = this.extractNumber(actual);
    const [min, max] = expected.map((v) => this.extractNumber(v));

    if (actualNum === null || min === null || max === null) {
      return false;
    }

    return actualNum >= min && actualNum <= max;
  }

  /**
   * Check if value is empty
   */
  private isEmpty(actual: unknown): boolean {
    if (actual === null || actual === undefined) {
      return true;
    }

    if (typeof actual === 'string' && actual.trim() === '') {
      return true;
    }

    if (Array.isArray(actual) && actual.length === 0) {
      return true;
    }

    if (typeof actual === 'object') {
      const obj = actual as Record<string, unknown>;

      // Check response objects
      if ('text' in obj && (obj.text === '' || obj.text === null)) {
        return true;
      }
      if ('selectedOptionId' in obj && obj.selectedOptionId === null) {
        return true;
      }
      if (
        'selectedOptionIds' in obj &&
        Array.isArray(obj.selectedOptionIds) &&
        obj.selectedOptionIds.length === 0
      ) {
        return true;
      }
    }

    return false;
  }

  /**
   * String starts with
   */
  private startsWith(actual: unknown, expected: unknown): boolean {
    const actualStr = this.extractString(actual);
    const expectedStr = this.extractString(expected);

    if (actualStr === null || expectedStr === null) {
      return false;
    }

    return actualStr.startsWith(expectedStr);
  }

  /**
   * String ends with
   */
  private endsWith(actual: unknown, expected: unknown): boolean {
    const actualStr = this.extractString(actual);
    const expectedStr = this.extractString(expected);

    if (actualStr === null || expectedStr === null) {
      return false;
    }

    return actualStr.endsWith(expectedStr);
  }

  /**
   * Regex match
   */
  private matches(actual: unknown, expected: unknown): boolean {
    const actualStr = this.extractString(actual);

    if (actualStr === null || typeof expected !== 'string') {
      return false;
    }

    try {
      const regex = new RegExp(expected);
      return regex.test(actualStr);
    } catch {
      return false;
    }
  }

  /**
   * Extract number from various value types
   */
  private extractNumber(value: unknown): number | null {
    if (typeof value === 'number') {
      return value;
    }

    if (typeof value === 'string') {
      const parsed = parseFloat(value);
      return isNaN(parsed) ? null : parsed;
    }

    if (typeof value === 'object' && value !== null) {
      const obj = value as Record<string, unknown>;

      if ('number' in obj && typeof obj.number === 'number') {
        return obj.number;
      }
      if ('rating' in obj && typeof obj.rating === 'number') {
        return obj.rating;
      }
    }

    return null;
  }

  /**
   * Extract string from various value types
   */
  private extractString(value: unknown): string | null {
    if (typeof value === 'string') {
      return value;
    }

    if (typeof value === 'object' && value !== null) {
      const obj = value as Record<string, unknown>;

      if ('text' in obj && typeof obj.text === 'string') {
        return obj.text;
      }
      if ('selectedOptionId' in obj && typeof obj.selectedOptionId === 'string') {
        return obj.selectedOptionId;
      }
    }

    return null;
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { Request } from 'express';

export interface AuditLogParams {
  userId: string;
  action: string;
  resourceType: 'Questionnaire' | 'Section' | 'Question' | 'VisibilityRule';
  resourceId: string;
  changes?: { before?: unknown; after?: unknown };
  request?: Request;
}

@Injectable()
export class AdminAuditService {
  private readonly logger = new Logger(AdminAuditService.name);

  constructor(private readonly prisma: PrismaService) {}

  async log(params: AuditLogParams): Promise<void> {
    const { userId, action, resourceType, resourceId, changes, request } = params;

    try {
      await this.prisma.auditLog.create({
        data: {
          userId,
          action,
          resourceType,
          resourceId,
          changes: changes ? JSON.parse(JSON.stringify(changes)) : null,
          ipAddress: request?.ip ?? request?.socket?.remoteAddress ?? null,
          userAgent: request?.headers?.['user-agent'] ?? null,
          requestId: (request?.headers?.['x-request-id'] as string) ?? null,
        },
      });

      this.logger.log(`Audit: ${action} on ${resourceType}:${resourceId} by user ${userId}`);
    } catch (error) {
      this.logger.error(
        `Failed to create audit log: ${error instanceof Error ? error.message : 'Unknown error'}`,
        error instanceof Error ? error.stack : undefined,
      );
    }
  }
}

import { Injectable, Logger } from '@nestjs/common';
import OpenAI from 'openai';
import {
  AiAdapter,
  AiGatewayRequest,
  AiGatewayResponse,
  AiStreamChunk,
  TokenUsage,
  CostInfo,
  ProviderConfig,
} from '../interfaces';

/**
 * OpenAI Adapter for OpenAI's GPT API
 *
 * Secondary AI provider for Quiz2Biz.
 * Supports streaming, JSON mode, and cost tracking.
 */
@Injectable()
export class OpenAIAdapter implements AiAdapter {
  private readonly logger = new Logger(OpenAIAdapter.name);
  private client: OpenAI | null = null;
  private config: ProviderConfig | null = null;

  readonly provider = 'openai' as const;

  constructor() {
    this.initializeClient();
  }

  private initializeClient(): void {
    const apiKey = process.env.OPENAI_API_KEY;
    if (apiKey) {
      this.client = new OpenAI({ apiKey });
      this.logger.log('OpenAI adapter initialized');
    } else {
      this.logger.warn('OPENAI_API_KEY not set, OpenAI adapter unavailable');
    }
  }

  /**
   * Set provider configuration from database
   */
  setConfig(config: ProviderConfig): void {
    this.config = config;
  }

  /**
   * Check if OpenAI is available
   */
  isAvailable(): boolean {
    return this.client !== null;
  }

  /**
   * Get the model to use for a task type
   */
  private getModel(taskType: string): string {
    if (this.config?.modelMap?.[taskType]) {
      return this.config.modelMap[taskType];
    }
    // Default models
    const defaults: Record<string, string> = {
      chat: 'gpt-4o',
      extract: 'gpt-4o-mini',
      generate: 'gpt-4o',
    };
    return defaults[taskType] || 'gpt-4o';
  }

  /**
   * Get max tokens for a task type
   */
  private getMaxTokens(taskType: string, requested?: number): number {
    if (requested) {return requested;}
    if (this.config?.config?.maxTokens?.[taskType as keyof typeof this.config.config.maxTokens]) {
      return this.config.config.maxTokens[taskType as keyof typeof this.config.config.maxTokens];
    }
    // Default max tokens
    const defaults: Record<string, number> = {
      chat: 4096,
      extract: 2048,
      generate: 16384,
    };
    return defaults[taskType] || 4096;
  }

  /**
   * Get temperature for a task type
   */
  private getTemperature(taskType: string, requested?: number): number {
    if (requested !== undefined) {return requested;}
    if (this.config?.config?.temperature?.[taskType as keyof typeof this.config.config.temperature]) {
      return this.config.config.temperature[taskType as keyof typeof this.config.config.temperature];
    }
    // Default temperatures
    const defaults: Record<string, number> = {
      chat: 0.7,
      extract: 0.1,
      generate: 0.5,
    };
    return defaults[taskType] || 0.7;
  }

  /**
   * Generate a non-streaming response
   */
  async generate(request: AiGatewayRequest): Promise<AiGatewayResponse> {
    if (!this.client) {
      throw new Error('OpenAI adapter not available');
    }

    const startTime = Date.now();
    const model = this.getModel(request.taskType);
    const maxTokens = this.getMaxTokens(request.taskType, request.maxTokens);
    const temperature = this.getTemperature(request.taskType, request.temperature);

    try {
      // Build messages array with system prompt
      const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
        { role: 'system', content: request.systemPrompt },
        ...request.messages.map((msg) => ({
          role: msg.role as 'user' | 'assistant' | 'system',
          content: msg.content,
        })),
      ];

      const completionParams: OpenAI.Chat.ChatCompletionCreateParamsNonStreaming = {
        model,
        max_tokens: maxTokens,
        temperature,
        messages,
      };

      // Enable JSON mode if requested
      if (request.jsonMode) {
        completionParams.response_format = { type: 'json_object' };
      }

      const response = await this.client.chat.completions.create(completionParams);

      const latencyMs = Date.now() - startTime;
      const content = response.choices[0]?.message?.content || '';

      const usage: TokenUsage = {
        inputTokens: response.usage?.prompt_tokens || 0,
        outputTokens: response.usage?.completion_tokens || 0,
        totalTokens: response.usage?.total_tokens || 0,
      };

      const cost = this.calculateCost(usage);

      this.logger.debug(
        `OpenAI response: ${usage.totalTokens} tokens, ${latencyMs}ms, $${cost.totalCost.toFixed(4)}`,
      );

      const finishReason = response.choices[0]?.finish_reason;
      let normalizedFinishReason: 'stop' | 'length' | 'content_filter' | 'error' = 'stop';
      if (finishReason === 'length') {normalizedFinishReason = 'length';}
      else if (finishReason === 'content_filter') {normalizedFinishReason = 'content_filter';}

      return {
        content,
        provider: 'openai',
        model,
        usage,
        cost,
        latencyMs,
        finishReason: normalizedFinishReason,
        usedFallback: false,
      };
    } catch (error) {
      this.logger.error(`OpenAI generation failed: ${error instanceof Error ? error.message : String(error)}`);
      throw error;
    }
  }

  /**
   * Generate a streaming response
   */
  async *generateStream(
    request: AiGatewayRequest,
  ): AsyncGenerator<AiStreamChunk, void, unknown> {
    if (!this.client) {
      throw new Error('OpenAI adapter not available');
    }

    const model = this.getModel(request.taskType);
    const maxTokens = this.getMaxTokens(request.taskType, request.maxTokens);
    const temperature = this.getTemperature(request.taskType, request.temperature);

    try {
      // Build messages array with system prompt
      const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
        { role: 'system', content: request.systemPrompt },
        ...request.messages.map((msg) => ({
          role: msg.role as 'user' | 'assistant' | 'system',
          content: msg.content,
        })),
      ];

      const stream = await this.client.chat.completions.create({
        model,
        max_tokens: maxTokens,
        temperature,
        messages,
        stream: true,
        stream_options: { include_usage: true },
      });

      let totalTokens = 0;
      let inputTokens = 0;
      let outputTokens = 0;

      for await (const chunk of stream) {
        const content = chunk.choices[0]?.delta?.content;
        if (content) {
          yield {
            content,
            done: false,
            provider: 'openai',
          };
        }

        // Capture usage from final chunk
        if (chunk.usage) {
          inputTokens = chunk.usage.prompt_tokens;
          outputTokens = chunk.usage.completion_tokens;
          totalTokens = chunk.usage.total_tokens;
        }
      }

      // Final chunk with usage info
      const usage: TokenUsage = {
        inputTokens,
        outputTokens,
        totalTokens,
      };

      yield {
        content: '',
        done: true,
        provider: 'openai',
        usage,
        cost: this.calculateCost(usage),
      };
    } catch (error) {
      this.logger.error(`OpenAI stream failed: ${error instanceof Error ? error.message : String(error)}`);
      yield {
        content: '',
        done: true,
        provider: 'openai',
        error: error instanceof Error ? error.message : 'Stream failed',
      };
    }
  }

  /**
   * Estimate token count for text
   * Uses a rough approximation (4 characters per token)
   */
  estimateTokens(text: string): number {
    // GPT typically uses ~4 characters per token for English
    return Math.ceil(text.length / 4);
  }

  /**
   * Calculate cost for token usage
   */
  calculateCost(usage: TokenUsage): CostInfo {
    // Default GPT-4o pricing (as of 2025)
    const inputPer1k = this.config?.config?.pricing?.inputPer1kTokens ?? 0.0025;
    const outputPer1k = this.config?.config?.pricing?.outputPer1kTokens ?? 0.01;
    const currency = this.config?.config?.pricing?.currency ?? 'USD';

    const inputCost = (usage.inputTokens / 1000) * inputPer1k;
    const outputCost = (usage.outputTokens / 1000) * outputPer1k;

    return {
      inputCost,
      outputCost,
      totalCost: inputCost + outputCost,
      currency,
    };
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { AiProviderType, CostInfo, AiTaskType } from '../interfaces';

/**
 * Cost tracking record
 */
export interface CostRecord {
  projectId?: string;
  userId?: string;
  provider: AiProviderType;
  model: string;
  taskType: AiTaskType;
  inputTokens: number;
  outputTokens: number;
  totalTokens: number;
  inputCost: number;
  outputCost: number;
  totalCost: number;
  currency: string;
  latencyMs: number;
  timestamp: Date;
}

/**
 * Cost summary for a project
 */
export interface ProjectCostSummary {
  projectId: string;
  totalCost: number;
  totalTokens: number;
  requestCount: number;
  byProvider: Record<AiProviderType, {
    cost: number;
    tokens: number;
    requests: number;
  }>;
  byTaskType: Record<AiTaskType, {
    cost: number;
    tokens: number;
    requests: number;
  }>;
}

/**
 * Cost Tracker Service
 *
 * Tracks AI API costs per project and user for billing and analytics.
 */
@Injectable()
export class CostTrackerService {
  private readonly logger = new Logger(CostTrackerService.name);

  // In-memory buffer for cost records (flushed periodically)
  private costBuffer: CostRecord[] = [];
  private flushInterval: NodeJS.Timeout | null = null;

  constructor(private readonly prisma: PrismaService) {
    // Start periodic flush
    this.startPeriodicFlush();
  }

  /**
   * Record a cost entry
   */
  async trackCost(record: CostRecord): Promise<void> {
    this.costBuffer.push(record);

    // Log for debugging
    this.logger.debug(
      `Cost tracked: ${record.provider}/${record.taskType} - ` +
      `${record.totalTokens} tokens, $${record.totalCost.toFixed(4)} ` +
      `[project: ${record.projectId || 'N/A'}]`,
    );

    // Flush if buffer is large
    if (this.costBuffer.length >= 100) {
      await this.flushCostBuffer();
    }
  }

  /**
   * Flush cost buffer to database
   */
  async flushCostBuffer(): Promise<void> {
    if (this.costBuffer.length === 0) {return;}

    const records = [...this.costBuffer];
    this.costBuffer = [];

    try {
      // Store cost records in metadata of ChatMessage or a separate table
      // For now, we'll aggregate by project and update project metadata
      const projectCosts = new Map<string, { tokens: number; cost: number }>();

      for (const record of records) {
        if (record.projectId) {
          const existing = projectCosts.get(record.projectId) || { tokens: 0, cost: 0 };
          existing.tokens += record.totalTokens;
          existing.cost += record.totalCost;
          projectCosts.set(record.projectId, existing);
        }
      }

      // Update project metadata with accumulated costs
      for (const [projectId, costs] of projectCosts) {
        try {
          const project = await this.prisma.project.findUnique({
            where: { id: projectId },
            select: { metadata: true },
          });

          if (project) {
            const metadata = (project.metadata as Record<string, unknown>) || {};
            const costTracking = (metadata.costTracking as Record<string, number>) || {
              totalTokens: 0,
              totalCostUsd: 0,
              requestCount: 0,
            };

            costTracking.totalTokens = (costTracking.totalTokens || 0) + costs.tokens;
            costTracking.totalCostUsd = (costTracking.totalCostUsd || 0) + costs.cost;
            costTracking.requestCount = (costTracking.requestCount || 0) + 1;

            await this.prisma.project.update({
              where: { id: projectId },
              data: {
                metadata: {
                  ...metadata,
                  costTracking,
                  lastCostUpdate: new Date().toISOString(),
                },
              },
            });
          }
        } catch (error) {
          this.logger.error(`Failed to update project ${projectId} costs: ${error instanceof Error ? error.message : String(error)}`);
        }
      }

      this.logger.debug(`Flushed ${records.length} cost records`);
    } catch (error) {
      // Put records back on failure
      this.costBuffer = [...records, ...this.costBuffer];
      this.logger.error(`Failed to flush cost buffer: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Start periodic flush timer
   */
  private startPeriodicFlush(): void {
    // Flush every 30 seconds
    this.flushInterval = setInterval(() => {
      void this.flushCostBuffer();
    }, 30000);
  }

  /**
   * Stop periodic flush timer
   */
  stopPeriodicFlush(): void {
    if (this.flushInterval) {
      clearInterval(this.flushInterval);
      this.flushInterval = null;
    }
  }

  /**
   * Get cost summary for a project
   */
  async getProjectCostSummary(projectId: string): Promise<ProjectCostSummary | null> {
    try {
      const project = await this.prisma.project.findUnique({
        where: { id: projectId },
        select: { metadata: true },
      });

      if (!project) {return null;}

      const metadata = (project.metadata as Record<string, unknown>) || {};
      const costTracking = (metadata.costTracking as Record<string, number>) || {};

      return {
        projectId,
        totalCost: costTracking.totalCostUsd || 0,
        totalTokens: costTracking.totalTokens || 0,
        requestCount: costTracking.requestCount || 0,
        byProvider: {
          claude: { cost: 0, tokens: 0, requests: 0 },
          openai: { cost: 0, tokens: 0, requests: 0 },
          gemini: { cost: 0, tokens: 0, requests: 0 },
        },
        byTaskType: {
          chat: { cost: 0, tokens: 0, requests: 0 },
          extract: { cost: 0, tokens: 0, requests: 0 },
          generate: { cost: 0, tokens: 0, requests: 0 },
        },
      };
    } catch (error) {
      this.logger.error(`Failed to get project cost summary: ${error instanceof Error ? error.message : String(error)}`);
      return null;
    }
  }

  /**
   * Estimate cost for a request before execution
   */
  estimateCost(
    provider: AiProviderType,
    estimatedInputTokens: number,
    estimatedOutputTokens: number,
  ): CostInfo {
    // Default pricing (can be overridden by provider config)
    const pricing: Record<AiProviderType, { input: number; output: number }> = {
      claude: { input: 0.003, output: 0.015 },
      openai: { input: 0.0025, output: 0.01 },
      gemini: { input: 0.00025, output: 0.001 },
    };

    const rates = pricing[provider] || pricing.claude;
    const inputCost = (estimatedInputTokens / 1000) * rates.input;
    const outputCost = (estimatedOutputTokens / 1000) * rates.output;

    return {
      inputCost,
      outputCost,
      totalCost: inputCost + outputCost,
      currency: 'USD',
    };
  }

  /**
   * Clean up on module destroy
   */
  async onModuleDestroy(): Promise<void> {
    this.stopPeriodicFlush();
    await this.flushCostBuffer();
  }
}

import {
  Injectable,
  UnauthorizedException,
  ConflictException,
  BadRequestException,
  NotFoundException,
  Logger,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import * as bcrypt from 'bcrypt';
import { v4 as uuidv4 } from 'uuid';
import * as crypto from 'crypto';
import { PrismaService } from '@libs/database';
import { RedisService } from '@libs/redis';
import { NotificationService } from '../notifications/notification.service';
import { RegisterDto } from './dto/register.dto';
import { LoginDto } from './dto/login.dto';
import { TokenResponseDto } from './dto/token.dto';
import { User, UserRole } from '@prisma/client';

export interface JwtPayload {
  sub: string;
  email: string;
  role: UserRole;
  iat?: number;
  exp?: number;
}

export interface AuthenticatedUser {
  id: string;
  email: string;
  role: UserRole;
  name?: string;
}

@Injectable()
export class AuthService {
  private readonly logger = new Logger(AuthService.name);
  private readonly bcryptRounds: number;
  private readonly jwtRefreshExpiresIn: string;
  private readonly refreshTokenTtlSeconds: number;
  private readonly verificationTokenExpiry: number;
  private readonly passwordResetTokenExpiry: number;

  constructor(
    private readonly prisma: PrismaService,
    private readonly jwtService: JwtService,
    private readonly configService: ConfigService,
    private readonly redisService: RedisService,
    private readonly notificationService: NotificationService,
  ) {
    this.bcryptRounds = this.configService.get<number>('bcrypt.rounds', 12);
    this.jwtRefreshExpiresIn = this.configService.get<string>('jwt.refreshExpiresIn', '7d');
    this.refreshTokenTtlSeconds = this.parseExpiresInToSeconds(this.jwtRefreshExpiresIn);
    this.verificationTokenExpiry = this.parseExpiresInToSeconds(
      this.configService.get<string>('tokens.verificationExpiry', '24h'),
    );
    this.passwordResetTokenExpiry = this.parseExpiresInToSeconds(
      this.configService.get<string>('tokens.passwordResetExpiry', '1h'),
    );
  }

  async register(dto: RegisterDto): Promise<TokenResponseDto> {
    // Check if user already exists
    const existingUser = await this.prisma.user.findUnique({
      where: { email: dto.email.toLowerCase() },
    });

    if (existingUser) {
      throw new ConflictException('User with this email already exists');
    }

    // Hash password
    const passwordHash = await bcrypt.hash(dto.password, this.bcryptRounds);

    // Create user (emailVerified = false by default)
    const user = await this.prisma.user.create({
      data: {
        email: dto.email.toLowerCase(),
        passwordHash,
        role: UserRole.CLIENT,
        emailVerified: false,
        profile: {
          name: dto.name,
        },
      },
    });

    this.logger.log(`User registered: ${user.id}`);

    // Generate and send verification email (non-blocking - user can request new email later)
    try {
      await this.sendVerificationEmail(user.id, user.email, dto.name);
    } catch (error) {
      this.logger.error(`Failed to send verification email for user ${user.id}:`, error);
      // Don't throw - registration succeeded, user can request new verification email
    }

    // Generate tokens
    return this.generateTokens(user);
  }

  async login(dto: LoginDto): Promise<TokenResponseDto> {
    const user = await this.prisma.user.findUnique({
      where: { email: dto.email.toLowerCase() },
    });

    if (!user) {
      throw new UnauthorizedException('Invalid credentials');
    }

    // Check if account is locked
    if (user.lockedUntil && user.lockedUntil > new Date()) {
      throw new UnauthorizedException('Account is temporarily locked. Please try again later.');
    }

    // Verify password
    if (!user.passwordHash) {
      throw new UnauthorizedException('Invalid credentials');
    }

    const isPasswordValid = await bcrypt.compare(dto.password, user.passwordHash);

    if (!isPasswordValid) {
      // Increment failed login attempts
      await this.handleFailedLogin(user);
      throw new UnauthorizedException('Invalid credentials');
    }

    // Reset failed login attempts and update last login
    await this.prisma.user.update({
      where: { id: user.id },
      data: {
        failedLoginAttempts: 0,
        lockedUntil: null,
        lastLoginAt: new Date(),
        lastLoginIp: dto.ip,
      },
    });

    this.logger.log(`User logged in: ${user.id}`);

    return this.generateTokens(user);
  }

  async refresh(refreshToken: string): Promise<{ accessToken: string; expiresIn: number }> {
    // Verify refresh token exists in Redis
    const storedUserId = await this.redisService.get(`refresh:${refreshToken}`);

    if (!storedUserId) {
      throw new UnauthorizedException('Invalid or expired refresh token');
    }

    // Get user
    const user = await this.prisma.user.findUnique({
      where: { id: storedUserId },
    });

    if (!user || user.deletedAt) {
      throw new UnauthorizedException('User not found');
    }

    // Generate new access token
    const payload: JwtPayload = {
      sub: user.id,
      email: user.email,
      role: user.role,
    };

    const accessToken = this.jwtService.sign(payload);

    return {
      accessToken,
      expiresIn: 900, // 15 minutes
    };
  }

  async logout(refreshToken: string): Promise<void> {
    // Remove refresh token from Redis
    await this.redisService.del(`refresh:${refreshToken}`);
    this.logger.log('User logged out');
  }

  async validateUser(payload: JwtPayload): Promise<AuthenticatedUser | null> {
    const user = await this.prisma.user.findUnique({
      where: { id: payload.sub },
      select: {
        id: true,
        email: true,
        role: true,
        profile: true,
        deletedAt: true,
      },
    });

    if (!user || user.deletedAt) {
      return null;
    }

    const profile = user.profile as Record<string, unknown> | null;

    return {
      id: user.id,
      email: user.email,
      role: user.role,
      name: (profile?.name as string) || undefined,
    };
  }

  private async generateTokens(user: User): Promise<TokenResponseDto> {
    const payload: JwtPayload = {
      sub: user.id,
      email: user.email,
      role: user.role,
    };

    const accessToken = this.jwtService.sign(payload);
    const refreshToken = uuidv4();

    // Store refresh token in Redis
    await this.redisService.set(`refresh:${refreshToken}`, user.id, this.refreshTokenTtlSeconds);

    // Also store in database for audit
    await this.prisma.refreshToken.create({
      data: {
        userId: user.id,
        token: refreshToken,
        expiresAt: new Date(Date.now() + this.refreshTokenTtlSeconds * 1000),
      },
    });

    const profile = user.profile as Record<string, unknown> | null;

    return {
      accessToken,
      refreshToken,
      expiresIn: 900, // 15 minutes
      tokenType: 'Bearer',
      user: {
        id: user.id,
        email: user.email,
        role: user.role,
        name: (profile?.name as string) || undefined,
      },
    };
  }

  private async handleFailedLogin(user: User): Promise<void> {
    const failedAttempts = user.failedLoginAttempts + 1;
    const maxAttempts = 5;
    const lockDurationMinutes = 15;

    const updateData: { failedLoginAttempts: number; lockedUntil?: Date } = {
      failedLoginAttempts: failedAttempts,
    };

    // Lock account after max attempts
    if (failedAttempts >= maxAttempts) {
      updateData.lockedUntil = new Date(Date.now() + lockDurationMinutes * 60 * 1000);
      this.logger.warn(`Account locked due to failed login attempts: ${user.id}`);
    }

    await this.prisma.user.update({
      where: { id: user.id },
      data: updateData,
    });
  }

  private parseExpiresInToSeconds(expiresIn: string): number {
    const match = expiresIn.match(/^(\d+)([smhd])$/);
    if (!match) {
      return 7 * 24 * 60 * 60; // Default: 7 days
    }

    const value = parseInt(match[1], 10);
    const unit = match[2];

    switch (unit) {
      case 's':
        return value;
      case 'm':
        return value * 60;
      case 'h':
        return value * 60 * 60;
      case 'd':
        return value * 24 * 60 * 60;
      default:
        return 7 * 24 * 60 * 60;
    }
  }

  // ============ EMAIL VERIFICATION METHODS ============

  /**
   * Sends a verification email to the user
   */
  private async sendVerificationEmail(userId: string, email: string, name?: string): Promise<void> {
    const token = this.generateSecureToken();

    // Store token in Redis with expiry
    await this.redisService.set(`verify:${token}`, userId, this.verificationTokenExpiry);

    const userName = name || email.split('@')[0];

    try {
      await this.notificationService.sendVerificationEmail(email, userName, token);
      this.logger.log(`Verification email sent to ${email}`);
    } catch (error) {
      this.logger.error(`Failed to send verification email to ${email}:`, error);
      // Don't throw - user is still registered, they can request a new verification email
    }
  }

  /**
   * Verifies the user's email with the provided token
   */
  async verifyEmail(token: string): Promise<{ message: string; verified: boolean }> {
    const userId = await this.redisService.get(`verify:${token}`);

    if (!userId) {
      throw new BadRequestException('Invalid or expired verification token');
    }

    // Check if user exists
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    if (user.emailVerified) {
      // Already verified, just remove the token
      await this.redisService.del(`verify:${token}`);
      return { message: 'Email already verified', verified: true };
    }

    // Update user's email verification status
    await this.prisma.user.update({
      where: { id: userId },
      data: { emailVerified: true },
    });

    // Remove the token
    await this.redisService.del(`verify:${token}`);

    this.logger.log(`Email verified for user: ${userId}`);

    // Send welcome email (fire-and-forget)
    const userName = user.name || user.email.split('@')[0];
    this.notificationService.sendWelcomeEmail(user.email, userName).catch((err) => {
      this.logger.warn(`Failed to send welcome email to ${user.email}`, err);
    });

    return { message: 'Email verified successfully', verified: true };
  }

  /**
   * Resends a verification email to the user
   */
  async resendVerificationEmail(email: string): Promise<{ message: string }> {
    const user = await this.prisma.user.findUnique({
      where: { email: email.toLowerCase() },
    });

    if (!user) {
      // Don't reveal if user exists or not
      return { message: 'If your email is registered, you will receive a verification link' };
    }

    if (user.emailVerified) {
      return { message: 'Email is already verified' };
    }

    const profile = user.profile as Record<string, unknown> | null;
    const userName = (profile?.name as string) || email.split('@')[0];

    await this.sendVerificationEmail(user.id, user.email, userName);

    return { message: 'If your email is registered, you will receive a verification link' };
  }

  // ============ PASSWORD RESET METHODS ============

  /**
   * Initiates password reset flow by sending reset email
   */
  async requestPasswordReset(email: string): Promise<{ message: string }> {
    const user = await this.prisma.user.findUnique({
      where: { email: email.toLowerCase() },
    });

    // Always return success message to prevent email enumeration
    const successMessage = 'If your email is registered, you will receive a password reset link';

    if (!user) {
      return { message: successMessage };
    }

    const token = this.generateSecureToken();

    // Store token in Redis with expiry
    await this.redisService.set(`reset:${token}`, user.id, this.passwordResetTokenExpiry);

    const profile = user.profile as Record<string, unknown> | null;
    const userName = (profile?.name as string) || email.split('@')[0];

    try {
      await this.notificationService.sendPasswordResetEmail(user.email, userName, token);
      this.logger.log(`Password reset email sent to ${email}`);
    } catch (error) {
      this.logger.error(`Failed to send password reset email to ${email}:`, error);
    }

    return { message: successMessage };
  }

  /**
   * Resets the user's password with the provided token
   */
  async resetPassword(token: string, newPassword: string): Promise<{ message: string }> {
    const userId = await this.redisService.get(`reset:${token}`);

    if (!userId) {
      throw new BadRequestException('Invalid or expired password reset token');
    }

    // Validate password strength (minimum 12 characters)
    if (newPassword.length < 12) {
      throw new BadRequestException('Password must be at least 12 characters long');
    }

    // Check if user exists
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    // Hash new password
    const passwordHash = await bcrypt.hash(newPassword, this.bcryptRounds);

    // Update password and reset failed login attempts
    await this.prisma.user.update({
      where: { id: userId },
      data: {
        passwordHash,
        failedLoginAttempts: 0,
        lockedUntil: null,
      },
    });

    // Remove the reset token
    await this.redisService.del(`reset:${token}`);

    // Invalidate all existing refresh tokens for this user
    await this.invalidateAllUserRefreshTokens(userId);

    this.logger.log(`Password reset for user: ${userId}`);

    return { message: 'Password has been reset successfully' };
  }

  /**
   * Invalidates all refresh tokens for a user (used after password reset)
   */
  private async invalidateAllUserRefreshTokens(userId: string): Promise<void> {
    // Get all refresh tokens for the user
    const tokens = await this.prisma.refreshToken.findMany({
      where: {
        userId,
        revokedAt: null,
      },
      take: 100,
      orderBy: { createdAt: 'desc' },
    });

    // Remove from Redis and mark as revoked in DB
    for (const tokenRecord of tokens) {
      await this.redisService.del(`refresh:${tokenRecord.token}`);
    }

    await this.prisma.refreshToken.updateMany({
      where: {
        userId,
        revokedAt: null,
      },
      data: {
        revokedAt: new Date(),
      },
    });

    this.logger.log(`Invalidated all refresh tokens for user: ${userId}`);
  }

  /**
   * Generates a cryptographically secure random token
   */
  private generateSecureToken(): string {
    return crypto.randomBytes(32).toString('hex');
  }
}

import { createParamDecorator, ExecutionContext } from '@nestjs/common';
import { AuthenticatedUser } from '../auth.service';

export const CurrentUser = createParamDecorator(
  (
    data: keyof AuthenticatedUser | undefined,
    ctx: ExecutionContext,
  ): AuthenticatedUser | AuthenticatedUser[keyof AuthenticatedUser] => {
    const request = ctx.switchToHttp().getRequest();
    const user = request.user as AuthenticatedUser;

    if (data) {
      return user[data];
    }

    return user;
  },
);

import { Injectable, ExecutionContext, UnauthorizedException, Logger } from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { Reflector } from '@nestjs/core';
import { IS_PUBLIC_KEY } from '../decorators/public.decorator';

/**
 * JWT Authentication Guard
 *
 * Features:
 * - Respects @Public() decorator for public endpoints
 * - Logs authentication failures for debugging 401 issues
 * - Provides specific error messages for expired/invalid tokens
 */
@Injectable()
export class JwtAuthGuard extends AuthGuard('jwt') {
  private readonly logger = new Logger(JwtAuthGuard.name);

  constructor(private reflector: Reflector) {
    super();
  }

  canActivate(context: ExecutionContext): boolean | Promise<boolean> {
    const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);

    if (isPublic) {
      return true;
    }

    return super.canActivate(context) as boolean | Promise<boolean>;
  }

  handleRequest<TUser>(
    err: Error | null,
    user: TUser,
    info: Error | null,
    context: ExecutionContext,
  ): TUser {
    if (err || !user) {
      // Get request details for debugging
      const request = context.switchToHttp().getRequest();
      const authHeader = request.headers?.authorization;
      const hasAuthHeader = !!authHeader;
      const tokenPreview = hasAuthHeader
        ? `${authHeader.substring(0, 20)}...`
        : 'none';

      // Log authentication failure with context
      this.logger.warn(
        `Auth failed: ${info?.name || 'NoUser'} | Path: ${request.method} ${request.path} | HasAuth: ${hasAuthHeader} | Token: ${tokenPreview}`,
      );

      if (info?.name === 'TokenExpiredError') {
        throw new UnauthorizedException('Token has expired');
      }
      if (info?.name === 'JsonWebTokenError') {
        throw new UnauthorizedException('Invalid token');
      }
      throw err || new UnauthorizedException('Authentication required');
    }
    return user;
  }
}

import { Injectable, CanActivate, ExecutionContext, ForbiddenException } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { UserRole } from '@prisma/client';
import { ROLES_KEY } from '../decorators/roles.decorator';
import { AuthenticatedUser } from '../auth.service';

@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const requiredRoles = this.reflector.getAllAndOverride<UserRole[]>(ROLES_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);

    if (!requiredRoles || requiredRoles.length === 0) {
      return true;
    }

    const request = context.switchToHttp().getRequest();
    const user = request.user as AuthenticatedUser;

    if (!user) {
      throw new ForbiddenException('No user found in request');
    }

    const hasRole = requiredRoles.some((role) => user.role === role);

    if (!hasRole) {
      throw new ForbiddenException(`Access denied. Required roles: ${requiredRoles.join(', ')}`);
    }

    return true;
  }
}

/**
 * MFA Service
 * Handles TOTP-based multi-factor authentication setup and verification
 */

import { Injectable, BadRequestException, ForbiddenException } from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { generateSecret, generateURI, verifySync } from 'otplib';
import * as QRCode from 'qrcode';
import { randomBytes } from 'crypto';

export interface MfaSetupResponse {
  secret: string;
  qrCodeDataUrl: string;
  manualEntryKey: string;
}

export interface BackupCodesResponse {
  backupCodes: string[];
}

@Injectable()
export class MfaService {
  constructor(private readonly prisma: PrismaService) {}

  /**
   * Generate MFA setup data (secret and QR code)
   */
  async generateMfaSetup(userId: string, userEmail: string): Promise<MfaSetupResponse> {
    // Check if MFA is already enabled
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { mfaEnabled: true },
    });

    if (user?.mfaEnabled) {
      throw new BadRequestException('MFA is already enabled for this account');
    }

    // Generate a new secret
    const secret = generateSecret();

    // Generate QR code for authenticator apps
    const issuer = 'Quiz2Biz';
    const otpauthUrl = generateURI({ issuer, label: userEmail, secret });
    const qrCodeDataUrl = await QRCode.toDataURL(otpauthUrl);

    // Store the secret temporarily (pending verification)
    await this.prisma.user.update({
      where: { id: userId },
      data: {
        mfaSecret: secret,
        mfaEnabled: false, // Not enabled until verified
      },
    });

    return {
      secret,
      qrCodeDataUrl,
      manualEntryKey: this.formatSecretForManualEntry(secret),
    };
  }

  /**
   * Verify MFA code and enable MFA for the user
   */
  async verifyAndEnableMfa(userId: string, code: string): Promise<BackupCodesResponse> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { mfaSecret: true, mfaEnabled: true },
    });

    if (!user?.mfaSecret) {
      throw new BadRequestException('MFA setup has not been initiated');
    }

    if (user.mfaEnabled) {
      throw new BadRequestException('MFA is already enabled');
    }

    // Verify the code
    const result = verifySync({ token: code, secret: user.mfaSecret });
    const isValid = result.valid;

    if (!isValid) {
      throw new BadRequestException('Invalid verification code');
    }

    // Generate backup codes
    const backupCodes = this.generateBackupCodes();

    // Enable MFA and store backup codes
    await this.prisma.user.update({
      where: { id: userId },
      data: {
        mfaEnabled: true,
        mfaBackupCodes: JSON.stringify(backupCodes),
      },
    });

    return { backupCodes };
  }

  /**
   * Verify MFA code during login
   */
  async verifyMfaCode(userId: string, code: string): Promise<boolean> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { mfaSecret: true, mfaEnabled: true, mfaBackupCodes: true },
    });

    if (!user?.mfaEnabled || !user.mfaSecret) {
      throw new BadRequestException('MFA is not enabled for this account');
    }

    // First check if it's a TOTP code
    const totpResult = verifySync({ token: code, secret: user.mfaSecret });
    const isValidTotp = totpResult.valid;

    if (isValidTotp) {
      return true;
    }

    // Check if it's a backup code
    const backupCodes: string[] = user.mfaBackupCodes
      ? JSON.parse(user.mfaBackupCodes)
      : [];

    const codeIndex = backupCodes.indexOf(code.toUpperCase());
    if (codeIndex !== -1) {
      // Remove the used backup code
      backupCodes.splice(codeIndex, 1);
      await this.prisma.user.update({
        where: { id: userId },
        data: { mfaBackupCodes: JSON.stringify(backupCodes) },
      });
      return true;
    }

    return false;
  }

  /**
   * Disable MFA for a user
   */
  async disableMfa(userId: string, code: string): Promise<void> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { mfaSecret: true, mfaEnabled: true },
    });

    if (!user?.mfaEnabled) {
      throw new BadRequestException('MFA is not enabled');
    }

    // Verify the code before disabling
    const isValid = await this.verifyMfaCode(userId, code);
    if (!isValid) {
      throw new ForbiddenException('Invalid verification code');
    }

    await this.prisma.user.update({
      where: { id: userId },
      data: {
        mfaEnabled: false,
        mfaSecret: null,
        mfaBackupCodes: null,
      },
    });
  }

  /**
   * Regenerate backup codes
   */
  async regenerateBackupCodes(userId: string, code: string): Promise<BackupCodesResponse> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { mfaEnabled: true },
    });

    if (!user?.mfaEnabled) {
      throw new BadRequestException('MFA is not enabled');
    }

    // Verify current code
    const isValid = await this.verifyMfaCode(userId, code);
    if (!isValid) {
      throw new ForbiddenException('Invalid verification code');
    }

    // Generate new backup codes
    const backupCodes = this.generateBackupCodes();

    await this.prisma.user.update({
      where: { id: userId },
      data: { mfaBackupCodes: JSON.stringify(backupCodes) },
    });

    return { backupCodes };
  }

  /**
   * Get MFA status for a user
   */
  async getMfaStatus(userId: string): Promise<{ enabled: boolean; backupCodesCount: number }> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { mfaEnabled: true, mfaBackupCodes: true },
    });

    const backupCodes: string[] = user?.mfaBackupCodes
      ? JSON.parse(user.mfaBackupCodes)
      : [];

    return {
      enabled: user?.mfaEnabled ?? false,
      backupCodesCount: backupCodes.length,
    };
  }

  /**
   * Check if user has MFA enabled (for login flow)
   */
  async isMfaEnabled(userId: string): Promise<boolean> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { mfaEnabled: true },
    });
    return user?.mfaEnabled ?? false;
  }

  /**
   * Generate random backup codes
   */
  private generateBackupCodes(count = 10): string[] {
    const codes: string[] = [];
    for (let i = 0; i < count; i++) {
      // Generate 8-character alphanumeric codes
      const code = randomBytes(4)
        .toString('hex')
        .toUpperCase()
        .slice(0, 8);
      codes.push(code);
    }
    return codes;
  }

  /**
   * Format secret for manual entry in authenticator apps
   */
  private formatSecretForManualEntry(secret: string): string {
    // Add spaces every 4 characters for readability
    return secret.match(/.{1,4}/g)?.join(' ') ?? secret;
  }
}

import { Injectable, Logger, NotFoundException, BadRequestException } from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { ChatMessage, Prisma } from '@prisma/client';
import { AiGatewayService } from '../ai-gateway/ai-gateway.service';
import { PromptBuilderService } from './services/prompt-builder.service';
import { AiStreamChunk, AiMessage } from '../ai-gateway/interfaces';
import { ChatMessageDto, ChatStatusDto } from './dto/chat-engine.dto';

/**
 * Chat Engine Service
 *
 * Core service for Quiz2Biz chat functionality.
 * Features:
 * - Project-based chat sessions
 * - 50-message limit enforcement
 * - AI provider integration via AI Gateway
 * - Streaming response support
 * - Message persistence
 */
@Injectable()
export class ChatEngineService {
  private readonly logger = new Logger(ChatEngineService.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly aiGateway: AiGatewayService,
    private readonly promptBuilder: PromptBuilderService,
  ) {}

  /**
   * Get chat status for a project
   */
  async getChatStatus(projectId: string): Promise<ChatStatusDto> {
    const project = await this.prisma.project.findUnique({
      where: { id: projectId },
      select: {
        id: true,
        messageCount: true,
        messageLimit: true,
        qualityScore: true,
      },
    });

    if (!project) {
      throw new NotFoundException(`Project ${projectId} not found`);
    }

    const remaining = Math.max(0, project.messageLimit - project.messageCount);

    return {
      projectId: project.id,
      messageCount: project.messageCount,
      messageLimit: project.messageLimit,
      remainingMessages: remaining,
      limitReached: remaining === 0,
      qualityScore: project.qualityScore ? Number(project.qualityScore) : undefined,
    };
  }

  /**
   * Get messages for a project
   */
  async getMessages(
    projectId: string,
    skip = 0,
    take = 50,
  ): Promise<ChatMessageDto[]> {
    const messages = await this.prisma.chatMessage.findMany({
      where: { projectId },
      orderBy: { createdAt: 'asc' },
      skip,
      take,
    });

    return messages.map((m: ChatMessage) => ({
      id: m.id,
      projectId: m.projectId,
      role: m.role as 'user' | 'assistant' | 'system',
      content: m.content,
      aiProviderId: m.aiProviderId || undefined,
      inputTokens: m.inputTokens || undefined,
      outputTokens: m.outputTokens || undefined,
      latencyMs: m.latencyMs || undefined,
      createdAt: m.createdAt,
    }));
  }

  /**
   * Send a message and get AI response (non-streaming)
   */
  async sendMessage(
    projectId: string,
    userId: string,
    content: string,
    provider?: 'claude' | 'openai',
  ): Promise<ChatMessageDto> {
    // Verify project exists and check limit
    const status = await this.getChatStatus(projectId);
    if (status.limitReached) {
      throw new BadRequestException('Message limit reached for this project');
    }

    // Save user message
    const userMessage = await this.prisma.chatMessage.create({
      data: {
        projectId,
        role: 'user',
        content,
      },
    });

    // Build conversation history for AI
    const history = await this.getConversationHistory(projectId);
    const systemPrompt = await this.promptBuilder.buildSystemPrompt(projectId);

    // Check if approaching limit
    const remaining = status.messageLimit - status.messageCount - 1;
    let promptSuffix = '';
    if (remaining <= 5 && remaining > 0) {
      promptSuffix = this.promptBuilder.buildLimitApproachingPrompt(remaining);
    }

    try {
      // Generate AI response
      const response = await this.aiGateway.generate({
        taskType: 'chat',
        provider,
        messages: history,
        systemPrompt: systemPrompt + promptSuffix,
        projectId,
        userId,
      });

      // Find provider ID from database
      const aiProvider = await this.prisma.aiProvider.findUnique({
        where: { slug: response.provider },
        select: { id: true },
      });

      // Save assistant message
      const assistantMessage = await this.prisma.chatMessage.create({
        data: {
          projectId,
          aiProviderId: aiProvider?.id,
          role: 'assistant',
          content: response.content,
          inputTokens: response.usage.inputTokens,
          outputTokens: response.usage.outputTokens,
          totalTokens: response.usage.totalTokens,
          latencyMs: response.latencyMs,
          metadata: {
            model: response.model,
            cost: response.cost,
            finishReason: response.finishReason,
          } as unknown as Prisma.InputJsonValue,
        },
      });

      // Update project message count and activity
      await this.prisma.project.update({
        where: { id: projectId },
        data: {
          messageCount: { increment: 2 }, // User + assistant
          lastActivityAt: new Date(),
        },
      });

      return {
        id: assistantMessage.id,
        projectId: assistantMessage.projectId,
        role: 'assistant',
        content: assistantMessage.content,
        aiProviderId: assistantMessage.aiProviderId || undefined,
        inputTokens: assistantMessage.inputTokens || undefined,
        outputTokens: assistantMessage.outputTokens || undefined,
        latencyMs: assistantMessage.latencyMs || undefined,
        createdAt: assistantMessage.createdAt,
      };
    } catch (error) {
      this.logger.error(`Failed to generate response: ${error instanceof Error ? error.message : String(error)}`);
      
      // Delete user message on failure
      await this.prisma.chatMessage.delete({ where: { id: userMessage.id } });
      
      throw error;
    }
  }

  /**
   * Send a message and get AI response with streaming
   */
  async *sendMessageStream(
    projectId: string,
    userId: string,
    content: string,
    provider?: 'claude' | 'openai',
  ): AsyncGenerator<AiStreamChunk, void, unknown> {
    // Verify project exists and check limit
    const status = await this.getChatStatus(projectId);
    if (status.limitReached) {
      yield {
        content: '',
        done: true,
        provider: provider || 'claude',
        error: 'Message limit reached for this project',
      };
      return;
    }

    // Save user message
    const userMessage = await this.prisma.chatMessage.create({
      data: {
        projectId,
        role: 'user',
        content,
      },
    });

    // Build conversation history for AI
    const history = await this.getConversationHistory(projectId);
    const systemPrompt = await this.promptBuilder.buildSystemPrompt(projectId);

    // Check if approaching limit
    const remaining = status.messageLimit - status.messageCount - 1;
    let promptSuffix = '';
    if (remaining <= 5 && remaining > 0) {
      promptSuffix = this.promptBuilder.buildLimitApproachingPrompt(remaining);
    }

    // Collect full response for persistence
    let fullContent = '';
    let finalUsage = { inputTokens: 0, outputTokens: 0, totalTokens: 0 };
    let finalCost = { inputCost: 0, outputCost: 0, totalCost: 0, currency: 'USD' };
    let usedProvider: 'claude' | 'openai' | 'gemini' = provider || 'claude';

    try {
      const stream = this.aiGateway.generateStream({
        taskType: 'chat',
        provider,
        messages: history,
        systemPrompt: systemPrompt + promptSuffix,
        projectId,
        userId,
        stream: true,
      });

      for await (const chunk of stream) {
        if (!chunk.done) {
          fullContent += chunk.content;
        } else {
          // Final chunk with usage info
          if (chunk.usage) {finalUsage = chunk.usage;}
          if (chunk.cost) {finalCost = chunk.cost;}
          usedProvider = chunk.provider;
        }

        yield chunk;
      }

      // Find provider ID from database
      const aiProvider = await this.prisma.aiProvider.findUnique({
        where: { slug: usedProvider },
        select: { id: true },
      });

      // Save assistant message
      await this.prisma.chatMessage.create({
        data: {
          projectId,
          aiProviderId: aiProvider?.id,
          role: 'assistant',
          content: fullContent,
          inputTokens: finalUsage.inputTokens,
          outputTokens: finalUsage.outputTokens,
          totalTokens: finalUsage.totalTokens,
          metadata: { cost: finalCost } as Prisma.InputJsonValue,
        },
      });

      // Update project message count and activity
      await this.prisma.project.update({
        where: { id: projectId },
        data: {
          messageCount: { increment: 2 }, // User + assistant
          lastActivityAt: new Date(),
        },
      });
    } catch (error) {
      this.logger.error(`Stream failed: ${error instanceof Error ? error.message : String(error)}`);
      
      // Delete user message on failure
      await this.prisma.chatMessage.delete({ where: { id: userMessage.id } });
      
      yield {
        content: '',
        done: true,
        provider: usedProvider,
        error: error instanceof Error ? error.message : 'Stream failed',
      };
    }
  }

  /**
   * Get conversation history for AI context
   */
  private async getConversationHistory(projectId: string): Promise<AiMessage[]> {
    const messages = await this.prisma.chatMessage.findMany({
      where: { projectId },
      orderBy: { createdAt: 'asc' },
      select: {
        role: true,
        content: true,
      },
      take: 200,
    });

    return messages.map((m: { role: string; content: string }) => ({
      role: m.role as 'user' | 'assistant' | 'system',
      content: m.content,
    }));
  }

  /**
   * Check if limit is reached (helper for controller)
   */
  async checkLimit(projectId: string): Promise<{
    canSend: boolean;
    remaining: number;
    message?: string;
  }> {
    const status = await this.getChatStatus(projectId);
    
    if (status.limitReached) {
      return {
        canSend: false,
        remaining: 0,
        message: this.promptBuilder.buildLimitReachedPrompt(),
      };
    }

    return {
      canSend: true,
      remaining: status.remainingMessages,
    };
  }
}

import {
  Injectable,
  Logger,
  NotFoundException,
  ForbiddenException,
  BadRequestException,
} from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { DecisionStatus, UserRole } from '@prisma/client';
import * as crypto from 'crypto';

/**
 * Approval categories that require two-person rule
 */
export enum ApprovalCategory {
  POLICY_LOCK = 'POLICY_LOCK',
  ADR_APPROVAL = 'ADR_APPROVAL',
  HIGH_RISK_DECISION = 'HIGH_RISK_DECISION',
  SECURITY_EXCEPTION = 'SECURITY_EXCEPTION',
  DATA_ACCESS = 'DATA_ACCESS',
}

/**
 * Approval status for workflow tracking
 */
export enum ApprovalStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED',
  EXPIRED = 'EXPIRED',
}

/**
 * Approval request interface
 */
export interface ApprovalRequest {
  id: string;
  category: ApprovalCategory;
  resourceType: string;
  resourceId: string;
  requesterId: string;
  requesterName?: string;
  approverId?: string;
  approverName?: string;
  status: ApprovalStatus;
  reason: string;
  approverComments?: string;
  requestedAt: Date;
  respondedAt?: Date;
  expiresAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * Create approval request DTO
 */
export interface CreateApprovalRequestDto {
  category: ApprovalCategory;
  resourceType: string;
  resourceId: string;
  reason: string;
  expirationHours?: number;
  metadata?: Record<string, unknown>;
}

/**
 * Respond to approval request DTO
 */
export interface RespondToApprovalDto {
  approvalId: string;
  approved: boolean;
  comments?: string;
}

/**
 * ApprovalWorkflowService - Two-Person Rule Implementation
 *
 * Implements Quiz2Biz two-person rule for high-risk decisions:
 * - Policy locks require second approver
 * - ADR approvals require peer review
 * - Security exceptions require manager approval
 *
 * Key Principles:
 * 1. Requester cannot approve their own request
 * 2. Approver must have appropriate role/permissions
 * 3. Approvals expire after configurable timeout
 * 4. Full audit trail maintained
 */
@Injectable()
export class ApprovalWorkflowService {
  private readonly logger = new Logger(ApprovalWorkflowService.name);

  /** Default expiration time in hours */
  private readonly DEFAULT_EXPIRATION_HOURS = 72;

  /** In-memory storage for approvals (would be DB in production) */
  private approvals: Map<string, ApprovalRequest> = new Map();

  constructor(private readonly prisma: PrismaService) {}

  /**
   * Create a new approval request
   *
   * @param dto - Approval request details
   * @param requesterId - ID of user requesting approval
   * @returns Created approval request
   */
  async createApprovalRequest(
    dto: CreateApprovalRequestDto,
    requesterId: string,
  ): Promise<ApprovalRequest> {
    // Validate resource exists
    await this.validateResource(dto.resourceType, dto.resourceId);

    // Get requester details
    const requester = await this.prisma.user.findUnique({
      where: { id: requesterId },
      select: { id: true, name: true, email: true },
    });

    if (!requester) {
      throw new NotFoundException(`User not found: ${requesterId}`);
    }

    const expirationHours = dto.expirationHours || this.DEFAULT_EXPIRATION_HOURS;
    const expiresAt = new Date();
    expiresAt.setHours(expiresAt.getHours() + expirationHours);

    const approvalRequest: ApprovalRequest = {
      id: this.generateId(),
      category: dto.category,
      resourceType: dto.resourceType,
      resourceId: dto.resourceId,
      requesterId,
      requesterName: requester.name || requester.email,
      status: ApprovalStatus.PENDING,
      reason: dto.reason,
      requestedAt: new Date(),
      expiresAt,
      metadata: dto.metadata,
    };

    // Store approval request
    this.approvals.set(approvalRequest.id, approvalRequest);

    // Create audit log entry
    await this.createAuditEntry(
      'APPROVAL_REQUESTED',
      requesterId,
      dto.resourceType,
      dto.resourceId,
      { category: dto.category, reason: dto.reason },
    );

    this.logger.log(
      `Approval request created: ${approvalRequest.id} for ${dto.resourceType}/${dto.resourceId} by ${requesterId}`,
    );

    return approvalRequest;
  }

  /**
   * Respond to an approval request (approve or reject)
   *
   * TWO-PERSON RULE ENFORCEMENT:
   * - Requester cannot approve their own request
   * - Approver must have appropriate permissions
   *
   * @param dto - Response details
   * @param approverId - ID of user responding to approval
   */
  async respondToApproval(dto: RespondToApprovalDto, approverId: string): Promise<ApprovalRequest> {
    const approval = this.approvals.get(dto.approvalId);

    if (!approval) {
      throw new NotFoundException(`Approval request not found: ${dto.approvalId}`);
    }

    // Check if already responded
    if (approval.status !== ApprovalStatus.PENDING) {
      throw new BadRequestException(`Approval request already ${approval.status.toLowerCase()}`);
    }

    // Check if expired
    if (new Date() > approval.expiresAt) {
      approval.status = ApprovalStatus.EXPIRED;
      this.approvals.set(dto.approvalId, approval);
      throw new BadRequestException('Approval request has expired');
    }

    // TWO-PERSON RULE: Requester cannot approve their own request
    if (approval.requesterId === approverId) {
      throw new ForbiddenException(
        'Two-person rule violation: You cannot approve your own request',
      );
    }

    // Get approver details
    const approver = await this.prisma.user.findUnique({
      where: { id: approverId },
      select: { id: true, name: true, email: true, role: true },
    });

    if (!approver) {
      throw new NotFoundException(`Approver not found: ${approverId}`);
    }

    // Validate approver has permission for this category
    await this.validateApproverPermission(approver, approval.category);

    // Update approval status
    approval.approverId = approverId;
    approval.approverName = approver.name || approver.email;
    approval.status = dto.approved ? ApprovalStatus.APPROVED : ApprovalStatus.REJECTED;
    approval.approverComments = dto.comments;
    approval.respondedAt = new Date();

    this.approvals.set(dto.approvalId, approval);

    // If approved, execute the associated action
    if (dto.approved) {
      await this.executeApprovedAction(approval);
    }

    // Create audit log entry
    await this.createAuditEntry(
      dto.approved ? 'APPROVAL_GRANTED' : 'APPROVAL_REJECTED',
      approverId,
      approval.resourceType,
      approval.resourceId,
      {
        approvalId: dto.approvalId,
        category: approval.category,
        comments: dto.comments,
      },
    );

    this.logger.log(
      `Approval ${dto.approved ? 'granted' : 'rejected'}: ${dto.approvalId} by ${approverId}`,
    );

    return approval;
  }

  /**
   * Get pending approval requests for a user to review
   */
  async getPendingApprovals(userId: string): Promise<ApprovalRequest[]> {
    const pending: ApprovalRequest[] = [];
    const now = new Date();

    for (const approval of this.approvals.values()) {
      // Skip if requester is same as potential approver
      if (approval.requesterId === userId) {
        continue;
      }

      // Skip if not pending
      if (approval.status !== ApprovalStatus.PENDING) {
        continue;
      }

      // Skip if expired
      if (now > approval.expiresAt) {
        approval.status = ApprovalStatus.EXPIRED;
        this.approvals.set(approval.id, approval);
        continue;
      }

      pending.push(approval);
    }

    return pending.sort((a, b) => a.requestedAt.getTime() - b.requestedAt.getTime());
  }

  /**
   * Get approval requests created by a user
   */
  async getMyApprovalRequests(userId: string): Promise<ApprovalRequest[]> {
    const requests: ApprovalRequest[] = [];

    for (const approval of this.approvals.values()) {
      if (approval.requesterId === userId) {
        requests.push(approval);
      }
    }

    return requests.sort((a, b) => b.requestedAt.getTime() - a.requestedAt.getTime());
  }

  /**
   * Get approval request by ID
   */
  async getApprovalById(approvalId: string): Promise<ApprovalRequest> {
    const approval = this.approvals.get(approvalId);

    if (!approval) {
      throw new NotFoundException(`Approval request not found: ${approvalId}`);
    }

    return approval;
  }

  /**
   * Check if a resource has pending or approved approval
   */
  async hasApproval(
    resourceType: string,
    resourceId: string,
    category?: ApprovalCategory,
  ): Promise<{ hasPending: boolean; hasApproved: boolean }> {
    let hasPending = false;
    let hasApproved = false;

    for (const approval of this.approvals.values()) {
      if (
        approval.resourceType === resourceType &&
        approval.resourceId === resourceId &&
        (!category || approval.category === category)
      ) {
        if (approval.status === ApprovalStatus.PENDING) {
          hasPending = true;
        }
        if (approval.status === ApprovalStatus.APPROVED) {
          hasApproved = true;
        }
      }
    }

    return { hasPending, hasApproved };
  }

  /**
   * Request approval for a decision lock (two-person rule)
   */
  async requestDecisionLockApproval(
    decisionId: string,
    requesterId: string,
    reason: string,
  ): Promise<ApprovalRequest> {
    // Validate decision exists and is in DRAFT status
    const decision = await this.prisma.decisionLog.findUnique({
      where: { id: decisionId },
    });

    if (!decision) {
      throw new NotFoundException(`Decision not found: ${decisionId}`);
    }

    if (decision.status !== DecisionStatus.DRAFT) {
      throw new BadRequestException(`Decision is not in DRAFT status: ${decision.status}`);
    }

    return this.createApprovalRequest(
      {
        category: ApprovalCategory.HIGH_RISK_DECISION,
        resourceType: 'DecisionLog',
        resourceId: decisionId,
        reason,
        metadata: { statement: decision.statement },
      },
      requesterId,
    );
  }

  /**
   * Request approval for a policy lock
   */
  async requestPolicyLockApproval(
    policyId: string,
    requesterId: string,
    reason: string,
  ): Promise<ApprovalRequest> {
    return this.createApprovalRequest(
      {
        category: ApprovalCategory.POLICY_LOCK,
        resourceType: 'Policy',
        resourceId: policyId,
        reason,
      },
      requesterId,
    );
  }

  /**
   * Request approval for an ADR
   */
  async requestADRApproval(
    adrId: string,
    requesterId: string,
    reason: string,
    metadata?: Record<string, unknown>,
  ): Promise<ApprovalRequest> {
    return this.createApprovalRequest(
      {
        category: ApprovalCategory.ADR_APPROVAL,
        resourceType: 'ADR',
        resourceId: adrId,
        reason,
        metadata,
      },
      requesterId,
    );
  }

  // ========================================
  // Private helpers
  // ========================================

  /**
   * Validate resource exists
   */
  private async validateResource(resourceType: string, resourceId: string): Promise<void> {
    let exists = false;

    switch (resourceType) {
      case 'DecisionLog':
        exists = !!(await this.prisma.decisionLog.findUnique({
          where: { id: resourceId },
        }));
        break;
      case 'Session':
        exists = !!(await this.prisma.session.findUnique({
          where: { id: resourceId },
        }));
        break;
      case 'Policy':
      case 'ADR':
        // These might not have DB records yet - allow
        exists = true;
        break;
      default:
        exists = true; // Allow unknown resource types
    }

    if (!exists) {
      throw new NotFoundException(`Resource not found: ${resourceType}/${resourceId}`);
    }
  }

  /**
   * Validate approver has permission for the category
   */
  private async validateApproverPermission(
    approver: { id: string; role: string },
    category: ApprovalCategory,
  ): Promise<void> {
    // Role-based permission mapping
    const categoryPermissions: Record<ApprovalCategory, string[]> = {
      [ApprovalCategory.POLICY_LOCK]: ['ADMIN', 'SUPER_ADMIN'],
      [ApprovalCategory.ADR_APPROVAL]: ['DEVELOPER', 'ADMIN', 'SUPER_ADMIN'],
      [ApprovalCategory.HIGH_RISK_DECISION]: ['DEVELOPER', 'ADMIN', 'SUPER_ADMIN'],
      [ApprovalCategory.SECURITY_EXCEPTION]: ['ADMIN', 'SUPER_ADMIN'],
      [ApprovalCategory.DATA_ACCESS]: ['ADMIN', 'SUPER_ADMIN'],
    };

    const allowedRoles = categoryPermissions[category];
    if (!allowedRoles.includes(approver.role)) {
      throw new ForbiddenException(
        `Insufficient permissions to approve ${category}. Required roles: ${allowedRoles.join(', ')}`,
      );
    }
  }

  /**
   * Execute the action associated with an approved request
   */
  private async executeApprovedAction(approval: ApprovalRequest): Promise<void> {
    switch (approval.category) {
      case ApprovalCategory.HIGH_RISK_DECISION:
        if (approval.resourceType === 'DecisionLog') {
          // Lock the decision
          await this.prisma.decisionLog.update({
            where: { id: approval.resourceId },
            data: { status: DecisionStatus.LOCKED },
          });
          this.logger.log(`Decision ${approval.resourceId} locked after two-person approval`);
        }
        break;

      case ApprovalCategory.POLICY_LOCK:
        // Policy lock logic would go here
        this.logger.log(`Policy ${approval.resourceId} locked after approval`);
        break;

      case ApprovalCategory.ADR_APPROVAL:
        // ADR approval logic would go here
        this.logger.log(`ADR ${approval.resourceId} approved`);
        break;

      default:
        // No automatic action for other categories
        break;
    }
  }

  /**
   * Create audit log entry
   */
  private async createAuditEntry(
    action: string,
    userId: string,
    resourceType: string,
    resourceId: string,
    changes?: Record<string, unknown>,
  ): Promise<void> {
    await this.prisma.auditLog.create({
      data: {
        userId,
        action,
        resourceType,
        resourceId,
        changes: changes ? JSON.parse(JSON.stringify(changes)) : {},
      },
    });
  }

  /**
   * Generate unique ID
   */
  private generateId(): string {
    return `apr_${Date.now().toString(36)}_${crypto.randomBytes(6).toString('hex')}`;
  }

  // ========================================
  // Notification Triggers
  // ========================================

  /**
   * Notify approvers when a new approval request is created
   * Called after createApprovalRequest
   */
  async notifyApproversOfRequest(approval: ApprovalRequest): Promise<void> {
    // Get users who can approve this category
    const approvers = await this.getEligibleApprovers(approval.category, approval.requesterId);

    this.logger.log(`Notifying ${approvers.length} eligible approvers for request ${approval.id}`);

    // Log notification event (actual email sending would integrate with NotificationService)
    for (const approver of approvers) {
      await this.createAuditEntry(
        'APPROVAL_NOTIFICATION_SENT',
        approver.id,
        approval.resourceType,
        approval.resourceId,
        {
          approvalId: approval.id,
          notificationType: 'NEW_REQUEST',
          recipient: approver.email,
        },
      );
    }
  }

  /**
   * Notify requester when their approval is approved or rejected
   */
  async notifyRequesterOfResponse(approval: ApprovalRequest): Promise<void> {
    const requester = await this.prisma.user.findUnique({
      where: { id: approval.requesterId },
      select: { id: true, email: true, name: true },
    });

    if (!requester) {
      return;
    }

    this.logger.log(
      `Notifying requester ${requester.email} of ${approval.status} for request ${approval.id}`,
    );

    // Log notification event
    await this.createAuditEntry(
      'APPROVAL_RESPONSE_NOTIFICATION_SENT',
      requester.id,
      approval.resourceType,
      approval.resourceId,
      {
        approvalId: approval.id,
        notificationType: approval.status === ApprovalStatus.APPROVED ? 'APPROVED' : 'REJECTED',
        recipient: requester.email,
        respondedBy: approval.approverId,
      },
    );
  }

  /**
   * Get users eligible to approve a category (excluding requester)
   */
  private async getEligibleApprovers(
    category: ApprovalCategory,
    excludeUserId: string,
  ): Promise<Array<{ id: string; email: string; name: string | null }>> {
    const roleRequirements: Record<ApprovalCategory, string[]> = {
      [ApprovalCategory.POLICY_LOCK]: ['ADMIN', 'SUPER_ADMIN'],
      [ApprovalCategory.ADR_APPROVAL]: ['DEVELOPER', 'ADMIN', 'SUPER_ADMIN'],
      [ApprovalCategory.HIGH_RISK_DECISION]: ['DEVELOPER', 'ADMIN', 'SUPER_ADMIN'],
      [ApprovalCategory.SECURITY_EXCEPTION]: ['ADMIN', 'SUPER_ADMIN'],
      [ApprovalCategory.DATA_ACCESS]: ['ADMIN', 'SUPER_ADMIN'],
    };

    const requiredRoles = roleRequirements[category];

    return this.prisma.user.findMany({
      where: {
        role: { in: requiredRoles as UserRole[] },
        id: { not: excludeUserId },
        deletedAt: null,
      },
      select: { id: true, email: true, name: true },
      take: 1000,
    });
  }

  /**
   * Notify about expiring approval requests (to be called by scheduled job)
   */
  async notifyExpiringApprovals(hoursBeforeExpiry: number = 24): Promise<number> {
    const cutoffTime = new Date();
    cutoffTime.setHours(cutoffTime.getHours() + hoursBeforeExpiry);

    let notified = 0;

    for (const approval of this.approvals.values()) {
      if (
        approval.status === ApprovalStatus.PENDING &&
        approval.expiresAt <= cutoffTime &&
        approval.expiresAt > new Date()
      ) {
        // Notify requester of upcoming expiry
        this.logger.warn(
          `Approval ${approval.id} expiring soon (${approval.expiresAt.toISOString()})`,
        );

        await this.createAuditEntry(
          'APPROVAL_EXPIRY_WARNING_SENT',
          approval.requesterId,
          approval.resourceType,
          approval.resourceId,
          {
            approvalId: approval.id,
            expiresAt: approval.expiresAt.toISOString(),
          },
        );

        notified++;
      }
    }

    return notified;
  }
}

import {
  Injectable,
  Logger,
  NotFoundException,
  ForbiddenException,
  BadRequestException,
} from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { DecisionLog, DecisionStatus, Prisma } from '@prisma/client';
import {
  CreateDecisionDto,
  UpdateDecisionStatusDto,
  SupersedeDecisionDto,
  ListDecisionsDto,
  DecisionResponse,
  DecisionAuditExport,
} from './dto';

/**
 * Decision Log Service
 *
 * Implements Quiz2Biz append-only forensic decision record:
 *
 * Key Principles:
 * 1. Decisions are APPEND-ONLY - once created, content cannot be modified
 * 2. Status workflow: DRAFT -> LOCKED -> (AMENDED via supersession)
 * 3. Locked decisions cannot be modified or deleted
 * 4. To change a locked decision, create a new one that supersedes it
 * 5. Full audit trail maintained for compliance
 *
 * Status Transitions:
 * - DRAFT: Initial state, can be modified until locked
 * - LOCKED: Finalized, cannot be changed, can be superseded
 * - SUPERSEDED: A newer decision replaces this one
 * - AMENDED: Content was amended via supersession
 */
@Injectable()
export class DecisionLogService {
  private readonly logger = new Logger(DecisionLogService.name);

  constructor(private readonly prisma: PrismaService) {}

  /**
   * Create a new decision
   *
   * @param dto - Decision details
   * @param ownerId - ID of user creating the decision
   */
  async createDecision(dto: CreateDecisionDto, ownerId: string): Promise<DecisionResponse> {
    // Validate session exists
    const session = await this.prisma.session.findUnique({
      where: { id: dto.sessionId },
    });

    if (!session) {
      throw new NotFoundException(`Session not found: ${dto.sessionId}`);
    }

    // Create decision with DRAFT status
    const decision = await this.prisma.decisionLog.create({
      data: {
        sessionId: dto.sessionId,
        statement: dto.statement,
        assumptions: dto.assumptions,
        references: dto.references,
        ownerId,
        status: DecisionStatus.DRAFT,
      },
    });

    this.logger.log(`Decision created: ${decision.id} by ${ownerId}`);

    return this.mapToResponse(decision);
  }

  /**
   * Update decision status (DRAFT -> LOCKED only)
   *
   * APPEND-ONLY ENFORCEMENT:
   * - Only status can be changed
   * - Only DRAFT -> LOCKED transition is allowed
   * - Locked decisions cannot be further modified
   *
   * @param dto - Status update details
   * @param userId - ID of user performing the action
   */
  async updateDecisionStatus(
    dto: UpdateDecisionStatusDto,
    userId: string,
  ): Promise<DecisionResponse> {
    const decision = await this.prisma.decisionLog.findUnique({
      where: { id: dto.decisionId },
    });

    if (!decision) {
      throw new NotFoundException(`Decision not found: ${dto.decisionId}`);
    }

    // APPEND-ONLY GUARD: Prevent modification of locked decisions
    if (decision.status !== DecisionStatus.DRAFT) {
      throw new ForbiddenException(
        `Cannot modify decision with status: ${decision.status}. ` +
          `Only DRAFT decisions can be locked. Use supersession to amend locked decisions.`,
      );
    }

    // Only allow DRAFT -> LOCKED transition
    if (dto.status !== DecisionStatus.LOCKED) {
      throw new BadRequestException(`Invalid status transition. Only DRAFT -> LOCKED is allowed.`);
    }

    const updatedDecision = await this.prisma.decisionLog.update({
      where: { id: dto.decisionId },
      data: { status: DecisionStatus.LOCKED },
    });

    this.logger.log(`Decision locked: ${dto.decisionId} by ${userId}`);

    // Create audit log entry
    await this.createAuditEntry(dto.decisionId, 'LOCKED', userId);

    return this.mapToResponse(updatedDecision);
  }

  /**
   * Supersede a locked decision with a new one
   *
   * This is the ONLY way to "amend" a locked decision.
   * Creates a new decision that references the old one.
   * Marks the old decision as SUPERSEDED.
   *
   * @param dto - Supersession details
   * @param ownerId - ID of user creating the supersession
   */
  async supersedeDecision(dto: SupersedeDecisionDto, ownerId: string): Promise<DecisionResponse> {
    const originalDecision = await this.prisma.decisionLog.findUnique({
      where: { id: dto.supersedesDecisionId },
    });

    if (!originalDecision) {
      throw new NotFoundException(`Original decision not found: ${dto.supersedesDecisionId}`);
    }

    // Can only supersede LOCKED decisions
    if (originalDecision.status !== DecisionStatus.LOCKED) {
      throw new BadRequestException(
        `Can only supersede LOCKED decisions. Current status: ${originalDecision.status}`,
      );
    }

    // Use transaction to ensure atomicity
    const result = await this.prisma.$transaction(async (tx: Prisma.TransactionClient) => {
      // Create new decision that supersedes the old one
      const newDecision = await tx.decisionLog.create({
        data: {
          sessionId: originalDecision.sessionId,
          statement: dto.statement,
          assumptions: dto.assumptions,
          references: dto.references,
          ownerId,
          status: DecisionStatus.LOCKED, // New decision is immediately locked
          supersedesDecisionId: dto.supersedesDecisionId,
        },
      });

      // Mark original decision as SUPERSEDED
      await tx.decisionLog.update({
        where: { id: dto.supersedesDecisionId },
        data: { status: DecisionStatus.SUPERSEDED },
      });

      return newDecision;
    });

    this.logger.log(
      `Decision ${dto.supersedesDecisionId} superseded by ${result.id} by ${ownerId}`,
    );

    // Create audit entries
    await this.createAuditEntry(dto.supersedesDecisionId, 'SUPERSEDED', ownerId, {
      supersededBy: result.id,
    });
    await this.createAuditEntry(result.id, 'CREATED_AS_SUPERSESSION', ownerId, {
      supersedes: dto.supersedesDecisionId,
    });

    return this.mapToResponse(result);
  }

  /**
   * Get a single decision by ID
   */
  async getDecision(decisionId: string): Promise<DecisionResponse> {
    const decision = await this.prisma.decisionLog.findUnique({
      where: { id: decisionId },
    });

    if (!decision) {
      throw new NotFoundException(`Decision not found: ${decisionId}`);
    }

    return this.mapToResponse(decision);
  }

  /**
   * List decisions with filters
   */
  async listDecisions(filters: ListDecisionsDto): Promise<DecisionResponse[]> {
    const where: Prisma.DecisionLogWhereInput = {};

    if (filters.sessionId) {
      where.sessionId = filters.sessionId;
    }
    if (filters.ownerId) {
      where.ownerId = filters.ownerId;
    }
    if (filters.status) {
      where.status = filters.status;
    }

    const decisions = await this.prisma.decisionLog.findMany({
      where,
      orderBy: { createdAt: 'desc' },
      take: 1000,
    });

    return decisions.map((d: DecisionLog) => this.mapToResponse(d));
  }

  /**
   * Export decisions for audit compliance
   *
   * Returns all decisions for a session with supersession chain.
   */
  async exportForAudit(sessionId: string): Promise<DecisionAuditExport> {
    const session = await this.prisma.session.findUnique({
      where: { id: sessionId },
    });

    if (!session) {
      throw new NotFoundException(`Session not found: ${sessionId}`);
    }

    const decisions = await this.prisma.decisionLog.findMany({
      where: { sessionId },
      orderBy: { createdAt: 'asc' },
      take: 1000,
    });

    // Build supersession chain
    const supersessionChain: Record<string, string[]> = {};

    decisions.forEach((d: DecisionLog) => {
      if (d.supersedesDecisionId) {
        if (!supersessionChain[d.supersedesDecisionId]) {
          supersessionChain[d.supersedesDecisionId] = [];
        }
        supersessionChain[d.supersedesDecisionId].push(d.id);
      }
    });

    return {
      exportedAt: new Date(),
      sessionId,
      totalDecisions: decisions.length,
      decisions: decisions.map((d: DecisionLog) => this.mapToResponse(d)),
      supersessionChain,
    };
  }

  /**
   * Get the supersession chain for a decision
   *
   * Returns the full history of a decision including all supersessions.
   */
  async getSupersessionChain(decisionId: string): Promise<DecisionResponse[]> {
    const chain: DecisionResponse[] = [];
    let currentId: string | null = decisionId;

    // Walk back through supersession chain
    while (currentId) {
      const decision: {
        id: string;
        sessionId: string;
        statement: string;
        assumptions: string | null;
        references: string | null;
        ownerId: string;
        status: DecisionStatus;
        supersedesDecisionId: string | null;
        createdAt: Date;
      } | null = await this.prisma.decisionLog.findUnique({
        where: { id: currentId },
      });

      if (!decision) {
        break;
      }

      chain.unshift(this.mapToResponse(decision));
      currentId = decision.supersedesDecisionId;
    }

    // Walk forward through supersessions
    const supersessions = await this.prisma.decisionLog.findMany({
      where: { supersedesDecisionId: decisionId },
      orderBy: { createdAt: 'asc' },
      take: 1000,
    });

    supersessions.forEach((d: DecisionLog) => {
      chain.push(this.mapToResponse(d));
    });

    return chain;
  }

  /**
   * Delete a DRAFT decision
   *
   * APPEND-ONLY ENFORCEMENT:
   * - Only DRAFT decisions can be deleted
   * - Locked/Superseded decisions are permanent
   */
  async deleteDecision(decisionId: string, userId: string): Promise<void> {
    const decision = await this.prisma.decisionLog.findUnique({
      where: { id: decisionId },
    });

    if (!decision) {
      throw new NotFoundException(`Decision not found: ${decisionId}`);
    }

    // APPEND-ONLY GUARD: Only drafts can be deleted
    if (decision.status !== DecisionStatus.DRAFT) {
      throw new ForbiddenException(
        `Cannot delete decision with status: ${decision.status}. ` +
          `Only DRAFT decisions can be deleted.`,
      );
    }

    await this.prisma.decisionLog.delete({
      where: { id: decisionId },
    });

    this.logger.log(`Draft decision deleted: ${decisionId} by ${userId}`);
  }

  /**
   * Create audit log entry for decision changes
   */
  private async createAuditEntry(
    decisionId: string,
    action: string,
    userId: string,
    metadata?: Record<string, unknown>,
  ): Promise<void> {
    await this.prisma.auditLog.create({
      data: {
        userId,
        action: `DECISION_${action}`,
        resourceType: 'DecisionLog',
        resourceId: decisionId,
        changes: metadata ? JSON.parse(JSON.stringify(metadata)) : {},
      },
    });
  }

  /**
   * Map database entity to response DTO
   */
  private mapToResponse(decision: {
    id: string;
    sessionId: string;
    statement: string;
    assumptions: string | null;
    references: string | null;
    ownerId: string;
    status: DecisionStatus;
    supersedesDecisionId: string | null;
    createdAt: Date;
  }): DecisionResponse {
    return {
      id: decision.id,
      sessionId: decision.sessionId,
      statement: decision.statement,
      assumptions: decision.assumptions,
      references: decision.references,
      ownerId: decision.ownerId,
      status: decision.status,
      supersedesDecisionId: decision.supersedesDecisionId,
      createdAt: decision.createdAt,
    };
  }
}

import {
  SetMetadata,
  applyDecorators,
  UseGuards,
  Injectable,
  CanActivate,
  ExecutionContext,
  ForbiddenException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { Request } from 'express';
import { ApprovalCategory, ApprovalWorkflowService } from '../approval-workflow.service';

/**
 * Metadata key for approval requirements
 */
export const APPROVAL_REQUIRED_KEY = 'approval_required';

/**
 * Approval requirement options
 */
export interface ApprovalRequirementOptions {
  /** Category of approval required */
  category: ApprovalCategory;

  /** Resource ID parameter name (from request params or body) */
  resourceIdParam?: string;

  /** Resource type for approval tracking */
  resourceType: string;

  /** Whether to allow bypassing if user is admin */
  allowAdminBypass?: boolean;

  /** Custom error message */
  errorMessage?: string;
}

/**
 * @RequireApproval Decorator
 *
 * Enforces two-person rule by requiring prior approval before execution.
 * Used for high-risk operations like:
 * - Policy locks
 * - ADR approvals
 * - Security exceptions
 *
 * Usage:
 * ```typescript
 * @RequireApproval({
 *   category: ApprovalCategory.POLICY_LOCK,
 *   resourceType: 'Policy',
 *   resourceIdParam: 'policyId',
 * })
 * @Post(':policyId/lock')
 * async lockPolicy(@Param('policyId') policyId: string) { ... }
 * ```
 */
export function RequireApproval(options: ApprovalRequirementOptions) {
  return applyDecorators(SetMetadata(APPROVAL_REQUIRED_KEY, options), UseGuards(ApprovalGuard));
}

/**
 * ApprovalGuard - Enforces approval requirements
 *
 * Checks if the resource has an approved approval request
 * before allowing the operation to proceed.
 */
@Injectable()
export class ApprovalGuard implements CanActivate {
  constructor(
    private readonly reflector: Reflector,
    private readonly approvalService: ApprovalWorkflowService,
  ) {}

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const options = this.reflector.get<ApprovalRequirementOptions>(
      APPROVAL_REQUIRED_KEY,
      context.getHandler(),
    );

    if (!options) {
      return true;
    }

    const request = context.switchToHttp().getRequest();
    const user = request.user;

    if (!user) {
      throw new ForbiddenException('Authentication required');
    }

    // Check admin bypass
    if (options.allowAdminBypass && user.role === 'SUPER_ADMIN') {
      return true;
    }

    // Get resource ID from params or body
    const resourceId = this.getResourceId(request, options);

    if (!resourceId) {
      throw new ForbiddenException('Resource ID not found in request');
    }

    // Check if resource has approved approval
    const approvalStatus = await this.approvalService.hasApproval(
      options.resourceType,
      resourceId,
      options.category,
    );

    if (!approvalStatus.hasApproved) {
      if (approvalStatus.hasPending) {
        throw new ForbiddenException(
          options.errorMessage || `This action requires approval. A request is pending review.`,
        );
      }

      throw new ForbiddenException(
        options.errorMessage ||
          `This action requires two-person approval. Please request approval first.`,
      );
    }

    return true;
  }

  /**
   * Extract resource ID from request
   */
  private getResourceId(request: Request, options: ApprovalRequirementOptions): string | null {
    const paramName = options.resourceIdParam || 'id';

    // Check route params
    if (request.params?.[paramName]) {
      const value = request.params[paramName];
      return Array.isArray(value) ? value[0] : value;
    }

    // Check body
    if (request.body?.[paramName]) {
      return String(request.body[paramName]);
    }

    // Check query
    if (request.query?.[paramName]) {
      return String(request.query[paramName] as string | number);
    }

    return null;
  }
}

/**
 * @RequirePolicyApproval - Shorthand decorator for policy locks
 */
export function RequirePolicyApproval(resourceIdParam: string = 'policyId') {
  return RequireApproval({
    category: ApprovalCategory.POLICY_LOCK,
    resourceType: 'Policy',
    resourceIdParam,
    errorMessage: 'Policy lock requires two-person approval',
  });
}

/**
 * @RequireADRApproval - Shorthand decorator for ADR approvals
 */
export function RequireADRApproval(resourceIdParam: string = 'adrId') {
  return RequireApproval({
    category: ApprovalCategory.ADR_APPROVAL,
    resourceType: 'ADR',
    resourceIdParam,
    errorMessage: 'ADR requires peer approval before finalization',
  });
}

/**
 * @RequireDecisionApproval - Shorthand decorator for high-risk decisions
 */
export function RequireDecisionApproval(resourceIdParam: string = 'decisionId') {
  return RequireApproval({
    category: ApprovalCategory.HIGH_RISK_DECISION,
    resourceType: 'DecisionLog',
    resourceIdParam,
    errorMessage: 'High-risk decision requires two-person approval',
  });
}

/**
 * @RequireSecurityExceptionApproval - Shorthand for security exceptions
 */
export function RequireSecurityExceptionApproval(resourceIdParam: string = 'exceptionId') {
  return RequireApproval({
    category: ApprovalCategory.SECURITY_EXCEPTION,
    resourceType: 'SecurityException',
    resourceIdParam,
    allowAdminBypass: false, // Security exceptions should never bypass
    errorMessage: 'Security exception requires explicit approval',
  });
}

/**
 * Document Commerce Controller
 * REST endpoints for document pricing and purchasing
 */

import {
  Controller,
  Get,
  Post,
  Body,
  Param,
  UseGuards,
  HttpCode,
  HttpStatus,
} from '@nestjs/common';
import { JwtAuthGuard } from '../../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../../common/decorators/user.decorator';
import { PricingCalculatorService } from './services/pricing-calculator.service';
import { DocumentPurchaseService } from './services/document-purchase.service';
import {
  PriceCalculationDto,
  PriceCalculationResponseDto,
  CreatePurchaseDto,
  PurchaseResponseDto,
  DocumentPurchaseStatusDto,
  ProjectDocumentsDto,
} from './dto/document-commerce.dto';

interface JwtUser {
  id: string;
  email: string;
}

@Controller('api/v1/documents')
@UseGuards(JwtAuthGuard)
export class DocumentCommerceController {
  constructor(
    private readonly pricingCalculator: PricingCalculatorService,
    private readonly purchaseService: DocumentPurchaseService,
  ) {}

  /**
   * Calculate price for a document at a given quality level
   * POST /api/v1/documents/price
   */
  @Post('price')
  @HttpCode(HttpStatus.OK)
  async calculatePrice(
    @Body() dto: PriceCalculationDto,
  ): Promise<PriceCalculationResponseDto> {
    return this.pricingCalculator.calculatePrice(dto);
  }

  /**
   * Get all documents available for a project
   * GET /api/v1/documents/project/:projectId
   */
  @Get('project/:projectId')
  async getProjectDocuments(
    @Param('projectId') projectId: string,
    @CurrentUser() user: JwtUser,
  ): Promise<ProjectDocumentsDto> {
    return this.pricingCalculator.getProjectDocuments(projectId, user.id);
  }

  /**
   * Create a new document purchase
   * POST /api/v1/documents/purchase
   */
  @Post('purchase')
  @HttpCode(HttpStatus.CREATED)
  async createPurchase(
    @Body() dto: CreatePurchaseDto,
    @CurrentUser() user: JwtUser,
  ): Promise<PurchaseResponseDto> {
    return this.purchaseService.createPurchase(dto, user.id);
  }

  /**
   * Get purchase status
   * GET /api/v1/documents/purchase/:purchaseId
   */
  @Get('purchase/:purchaseId')
  async getPurchaseStatus(
    @Param('purchaseId') purchaseId: string,
    @CurrentUser() user: JwtUser,
  ): Promise<DocumentPurchaseStatusDto> {
    return this.purchaseService.getPurchaseStatus(purchaseId, user.id);
  }

  /**
   * Get all purchases for current user
   * GET /api/v1/documents/purchases
   */
  @Get('purchases')
  async getUserPurchases(
    @CurrentUser() user: JwtUser,
  ): Promise<DocumentPurchaseStatusDto[]> {
    return this.purchaseService.getUserPurchases(user.id);
  }
}

/**
 * Document Purchase Service
 * Handles per-document purchases with Stripe PaymentIntents
 */

import {
  Injectable,
  NotFoundException,
  BadRequestException,
  Logger,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '@libs/database';
import Stripe from 'stripe';
import { PricingCalculatorService } from './pricing-calculator.service';
import {
  CreatePurchaseDto,
  PurchaseResponseDto,
  DocumentPurchaseStatusDto,
} from '../dto/document-commerce.dto';

@Injectable()
export class DocumentPurchaseService {
  private readonly logger = new Logger(DocumentPurchaseService.name);
  private readonly stripe: Stripe;

  constructor(
    private readonly prisma: PrismaService,
    private readonly configService: ConfigService,
    private readonly pricingCalculator: PricingCalculatorService,
  ) {
    const stripeSecretKey = this.configService.get<string>('STRIPE_SECRET_KEY');
    if (!stripeSecretKey) {
      this.logger.warn('STRIPE_SECRET_KEY not configured - payments disabled');
    }
    this.stripe = new Stripe(stripeSecretKey ?? 'sk_test_placeholder', {
      apiVersion: '2024-06-20' as Stripe.LatestApiVersion,
    });
  }

  /**
   * Create a new document purchase with PaymentIntent
   */
  async createPurchase(
    dto: CreatePurchaseDto,
    userId: string,
  ): Promise<PurchaseResponseDto> {
    // Calculate price first
    const priceInfo = await this.pricingCalculator.calculatePrice({
      projectId: dto.projectId,
      documentTypeSlug: dto.documentTypeSlug,
      qualityLevel: dto.qualityLevel,
    });

    // Verify project belongs to user
    const project = await this.prisma.project.findFirst({
      where: { id: dto.projectId, userId },
    });

    if (!project) {
      throw new NotFoundException('Project not found');
    }

    // Get document type
    const documentType = await this.prisma.documentType.findUnique({
      where: { slug: dto.documentTypeSlug },
    });

    if (!documentType) {
      throw new NotFoundException('Document type not found');
    }

    // Check if same document already purchased at same or higher quality
    const existingPurchase = await this.prisma.documentPurchase.findFirst({
      where: {
        projectId: dto.projectId,
        documentTypeId: documentType.id,
        qualityLevel: { gte: dto.qualityLevel },
        status: { in: ['completed', 'processing'] },
      },
    });

    if (existingPurchase) {
      throw new BadRequestException(
        'Document already purchased at this or higher quality level',
      );
    }

    // Get user for Stripe customer
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    // Create or get Stripe customer
    let stripeCustomerId = user.stripeCustomerId;
    if (!stripeCustomerId) {
      try {
        const customer = await this.stripe.customers.create({
          email: user.email,
          name: user.name ?? undefined,
          metadata: { userId: user.id },
        });
        stripeCustomerId = customer.id;

        // Update user with Stripe customer ID
        await this.prisma.user.update({
          where: { id: userId },
          data: { stripeCustomerId },
        });
      } catch (error) {
        this.logger.error('Failed to create Stripe customer', error);
        throw new BadRequestException('Payment service unavailable');
      }
    }

    // Create PaymentIntent
    const amountInCents = Math.round(priceInfo.finalPrice * 100);
    let paymentIntent: Stripe.PaymentIntent;

    try {
      paymentIntent = await this.stripe.paymentIntents.create({
        amount: amountInCents,
        currency: 'usd',
        customer: stripeCustomerId,
        metadata: {
          projectId: dto.projectId,
          documentTypeSlug: dto.documentTypeSlug,
          qualityLevel: dto.qualityLevel.toString(),
          userId,
        },
        description: `${priceInfo.documentTypeName} - ${this.pricingCalculator.getQualityLevelName(dto.qualityLevel)} Quality`,
        automatic_payment_methods: { enabled: true },
      });
    } catch (error) {
      this.logger.error('Failed to create PaymentIntent', error);
      throw new BadRequestException('Payment initialization failed');
    }

    // Create purchase record
    const purchase = await this.prisma.documentPurchase.create({
      data: {
        projectId: dto.projectId,
        documentTypeId: documentType.id,
        userId,
        qualityLevel: dto.qualityLevel,
        amount: priceInfo.finalPrice,
        currency: 'USD',
        stripePaymentIntentId: paymentIntent.id,
        status: 'pending',
      },
    });

    this.logger.log(
      `Created purchase ${purchase.id} for document ${dto.documentTypeSlug} at quality ${dto.qualityLevel}`,
    );

    return {
      purchaseId: purchase.id,
      projectId: dto.projectId,
      documentTypeSlug: dto.documentTypeSlug,
      qualityLevel: dto.qualityLevel,
      amount: priceInfo.finalPrice,
      currency: 'USD',
      clientSecret: paymentIntent.client_secret!,
      status: 'pending',
    };
  }

  /**
   * Get purchase status
   */
  async getPurchaseStatus(
    purchaseId: string,
    userId: string,
  ): Promise<DocumentPurchaseStatusDto> {
    const purchase = await this.prisma.documentPurchase.findFirst({
      where: { id: purchaseId, userId },
      include: {
        documentType: true,
        generatedDocument: true,
      },
    });

    if (!purchase) {
      throw new NotFoundException('Purchase not found');
    }

    return {
      purchaseId: purchase.id,
      projectId: purchase.projectId,
      documentTypeSlug: purchase.documentType.slug,
      documentTypeName: purchase.documentType.name,
      qualityLevel: purchase.qualityLevel,
      amount: purchase.amount.toNumber(),
      currency: purchase.currency,
      status: purchase.status as 'pending' | 'processing' | 'completed' | 'failed',
      documentId: purchase.generatedDocument?.id,
      generatedAt: purchase.generatedDocument?.createdAt,
      downloadUrl: purchase.generatedDocument
        ? `/api/v1/documents/${purchase.generatedDocument.id}/download`
        : undefined,
    };
  }

  /**
   * Get all purchases for a user
   */
  async getUserPurchases(userId: string): Promise<DocumentPurchaseStatusDto[]> {
    const purchases = await this.prisma.documentPurchase.findMany({
      where: { userId },
      include: {
        documentType: true,
        generatedDocument: true,
        project: true,
      },
      orderBy: { createdAt: 'desc' },
      take: 200,
    });

    return purchases.map((p) => ({
      purchaseId: p.id,
      projectId: p.projectId,
      documentTypeSlug: p.documentType.slug,
      documentTypeName: p.documentType.name,
      qualityLevel: p.qualityLevel,
      amount: p.amount.toNumber(),
      currency: p.currency,
      status: p.status as 'pending' | 'processing' | 'completed' | 'failed',
      documentId: p.generatedDocument?.id,
      generatedAt: p.generatedDocument?.createdAt,
      downloadUrl: p.generatedDocument
        ? `/api/v1/documents/${p.generatedDocument.id}/download`
        : undefined,
    }));
  }

  /**
   * Handle Stripe webhook for payment completion
   */
  async handlePaymentSuccess(paymentIntentId: string): Promise<void> {
    const purchase = await this.prisma.documentPurchase.findFirst({
      where: { stripePaymentIntentId: paymentIntentId },
    });

    if (!purchase) {
      this.logger.warn(`No purchase found for PaymentIntent ${paymentIntentId}`);
      return;
    }

    // Update status to processing (document generation will happen)
    await this.prisma.documentPurchase.update({
      where: { id: purchase.id },
      data: { status: 'processing' },
    });

    this.logger.log(`Payment successful for purchase ${purchase.id}, starting generation`);

    // Document generation will be triggered by the document-generation module
    // listening to this status change
  }

  /**
   * Handle Stripe webhook for payment failure
   */
  async handlePaymentFailure(paymentIntentId: string): Promise<void> {
    const purchase = await this.prisma.documentPurchase.findFirst({
      where: { stripePaymentIntentId: paymentIntentId },
    });

    if (!purchase) {
      this.logger.warn(`No purchase found for PaymentIntent ${paymentIntentId}`);
      return;
    }

    await this.prisma.documentPurchase.update({
      where: { id: purchase.id },
      data: { status: 'failed' },
    });

    this.logger.log(`Payment failed for purchase ${purchase.id}`);
  }
}

/**
 * Pricing Calculator Service
 * Implements quality-based pricing: price = basePrice ├ù (1 + qualityLevel)
 * Quality levels: 0=Basic(1x), 1=Standard(2x), 2=Enhanced(3x), 3=Premium(4x), 4=Enterprise(5x)
 */

import { Injectable, NotFoundException, BadRequestException } from '@nestjs/common';
import { PrismaService } from '@libs/database';
import {
  PriceCalculationDto,
  PriceCalculationResponseDto,
  AvailableDocumentDto,
  ProjectDocumentsDto,
} from '../dto/document-commerce.dto';

/** Quality level features for each tier */
const QUALITY_FEATURES: Record<number, string[]> = {
  0: ['Basic content', 'Standard formatting', '~5-10 pages'],
  1: ['Expanded content', 'Professional formatting', 'Basic citations', '~10-15 pages'],
  2: ['Comprehensive content', 'Enhanced formatting', 'Full citations', 'Charts', '~15-25 pages'],
  3: ['Premium content', 'Executive formatting', 'Full citations', 'Charts', 'SWOT', '~25-40 pages'],
  4: ['Enterprise content', 'Board-ready formatting', 'Full citations', 'All visuals', 'Appendices', '~40-60 pages'],
};

/** Quality level names */
const QUALITY_NAMES: Record<number, string> = {
  0: 'Basic',
  1: 'Standard',
  2: 'Enhanced',
  3: 'Premium',
  4: 'Enterprise',
};

/** Base page estimates per quality level */
const BASE_PAGES: Record<number, number> = {
  0: 8,
  1: 12,
  2: 20,
  3: 32,
  4: 50,
};

@Injectable()
export class PricingCalculatorService {
  constructor(private readonly prisma: PrismaService) {}

  /**
   * Calculate price for a document at a given quality level
   * Formula: price = basePrice ├ù (1 + qualityLevel)
   */
  async calculatePrice(dto: PriceCalculationDto): Promise<PriceCalculationResponseDto> {
    // Validate project exists and belongs to user (auth handled in controller)
    const project = await this.prisma.project.findUnique({
      where: { id: dto.projectId },
      include: { projectType: true },
    });

    if (!project) {
      throw new NotFoundException(`Project ${dto.projectId} not found`);
    }

    // Get document type with base price
    const documentType = await this.prisma.documentType.findUnique({
      where: { slug: dto.documentTypeSlug },
    });

    if (!documentType) {
      throw new NotFoundException(`Document type ${dto.documentTypeSlug} not found`);
    }

    // Validate quality level
    if (dto.qualityLevel < 0 || dto.qualityLevel > 4) {
      throw new BadRequestException('Quality level must be between 0 and 4');
    }

    // Calculate multiplier and final price
    const qualityMultiplier = 1 + dto.qualityLevel;
    const basePrice = documentType.basePrice?.toNumber() ?? 49.99;
    const finalPrice = Math.round(basePrice * qualityMultiplier * 100) / 100;

    return {
      projectId: dto.projectId,
      documentTypeSlug: dto.documentTypeSlug,
      documentTypeName: documentType.name,
      basePrice,
      qualityLevel: dto.qualityLevel,
      qualityMultiplier,
      finalPrice,
      currency: 'USD',
      estimatedPages: BASE_PAGES[dto.qualityLevel] ?? 10,
      features: QUALITY_FEATURES[dto.qualityLevel] ?? [],
    };
  }

  /**
   * Get all available documents for a project with pricing info
   */
  async getProjectDocuments(projectId: string, userId: string): Promise<ProjectDocumentsDto> {
    // Get project with facts count
    const project = await this.prisma.project.findFirst({
      where: { id: projectId, userId },
      include: {
        projectType: true,
        _count: { select: { extractedFacts: true } },
      },
    });

    if (!project) {
      throw new NotFoundException(`Project ${projectId} not found`);
    }

    // Get all document types
    const documentTypes = await this.prisma.documentType.findMany({
      where: { isActive: true },
      orderBy: { sortOrder: 'asc' },
      take: 100,
    });

    // Get purchased documents for this project
    const purchases = await this.prisma.documentPurchase.findMany({
      where: { projectId },
      include: { documentType: true, generatedDocument: true },
      take: 200,
      orderBy: { createdAt: 'desc' },
    });

    // Calculate quality score from project
    const qualityScore = project.qualityScore?.toNumber() ?? 0;
    const factCount = project._count.extractedFacts;

    // Build available documents list
    const availableDocuments: AvailableDocumentDto[] = documentTypes.map((dt) => {
      const requiredFacts = this.getRequiredFactCount(dt.slug);
      const isAvailable = factCount >= requiredFacts;

      return {
        slug: dt.slug,
        name: dt.name,
        description: dt.description ?? '',
        category: dt.category ?? 'general',
        basePrice: dt.basePrice?.toNumber() ?? 49.99,
        currency: 'USD',
        estimatedPagesBase: BASE_PAGES[0] ?? 8,
        requiredFactCount: requiredFacts,
        currentFactCount: factCount,
        isAvailable,
        unavailableReason: isAvailable 
          ? undefined 
          : `Need ${requiredFacts - factCount} more facts from chat`,
      };
    });

    // Build purchased documents list
    const purchasedDocuments = purchases.map((p) => ({
      purchaseId: p.id,
      projectId: p.projectId,
      documentTypeSlug: p.documentType.slug,
      documentTypeName: p.documentType.name,
      qualityLevel: p.qualityLevel,
      amount: p.amount.toNumber(),
      currency: p.currency,
      status: p.status as 'pending' | 'processing' | 'completed' | 'failed',
      documentId: p.generatedDocument?.id,
      generatedAt: p.generatedDocument?.createdAt,
      downloadUrl: p.generatedDocument 
        ? `/api/v1/documents/${p.generatedDocument.id}/download` 
        : undefined,
    }));

    return {
      projectId,
      projectName: project.name,
      qualityScore,
      availableDocuments,
      purchasedDocuments,
    };
  }

  /**
   * Get required fact count for document type
   * Different documents need different amounts of data
   */
  private getRequiredFactCount(documentTypeSlug: string): number {
    const requirements: Record<string, number> = {
      'executive-summary': 5,
      'business-plan': 15,
      'financial-projections': 10,
      'market-analysis': 8,
      'pitch-deck': 12,
      'operations-manual': 10,
      'marketing-strategy': 8,
      'tech-assessment': 10,
      'grant-application': 12,
      'investor-memo': 10,
    };
    return requirements[documentTypeSlug] ?? 10;
  }

  /**
   * Get quality level name
   */
  getQualityLevelName(level: number): string {
    return QUALITY_NAMES[level] ?? 'Basic';
  }

  /**
   * Get features for quality level
   */
  getQualityFeatures(level: number): string[] {
    return QUALITY_FEATURES[level] ?? QUALITY_FEATURES[0];
  }
}

// WIP module: references Prisma models/fields not yet in schema
// Excluded from build via tsconfig.build.json
import { Injectable, Logger, NotFoundException, BadRequestException } from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { ConfigService } from '@nestjs/config';
import * as archiver from 'archiver';
import { PassThrough } from 'stream';

export interface BulkDownloadResult {
  filename: string;
  stream: PassThrough;
  totalDocuments: number;
  totalSizeEstimate: number;
}

@Injectable()
export class BulkDownloadService {
  private readonly logger = new Logger(BulkDownloadService.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly configService: ConfigService,
  ) {}

  /**
   * Create a ZIP archive containing all documents for a session
   */
  async createSessionDocumentsZip(
    sessionId: string,
    userId: string,
  ): Promise<BulkDownloadResult> {
    // Verify session ownership
    const session = await this.prisma.session.findFirst({
      where: {
        id: sessionId,
        userId,
      },
      include: {
        questionnaire: { select: { name: true } },
      },
    });

    if (!session) {
      throw new NotFoundException('Session not found');
    }

    // Get all documents for this session
    const documents = await this.prisma.generatedDocument.findMany({
      where: {
        sessionId,
        status: 'COMPLETED',
      },
      select: {
        id: true,
        documentType: true,
        title: true,
        fileUrl: true,
        fileSize: true,
        format: true,
        createdAt: true,
      },
      orderBy: { createdAt: 'desc' },
    });

    if (documents.length === 0) {
      throw new BadRequestException('No documents available for download');
    }

    // Create ZIP filename
    const sanitizedName = (session.questionnaire?.name || 'session')
      .replace(/[^a-zA-Z0-9]/g, '_')
      .substring(0, 50);
    const timestamp = new Date().toISOString().split('T')[0];
    const filename = `${sanitizedName}_documents_${timestamp}.zip`;

    // Create the archive stream
    const passThrough = new PassThrough();
    const archive = archiver('zip', {
      zlib: { level: 6 }, // Balanced compression
    });

    // Handle archive errors
    archive.on('error', (err) => {
      this.logger.error('Archive error', err);
      passThrough.destroy(err);
    });

    // Pipe archive to the pass-through stream
    archive.pipe(passThrough);

    // Add documents to archive
    let totalSize = 0;
    for (const doc of documents) {
      try {
        const content = await this.fetchDocumentContent(doc.fileUrl);
        if (content) {
          const docFilename = this.generateDocumentFilename(doc);
          archive.append(content, { name: docFilename });
          totalSize += Number(doc.fileSize || 0);
        }
      } catch (error) {
        this.logger.warn(`Failed to fetch document ${doc.id}`, error);
        // Continue with other documents
      }
    }

    // Finalize the archive
    archive.finalize();

    return {
      filename,
      stream: passThrough,
      totalDocuments: documents.length,
      totalSizeEstimate: totalSize,
    };
  }

  /**
   * Create a ZIP archive containing selected documents
   */
  async createSelectedDocumentsZip(
    documentIds: string[],
    userId: string,
  ): Promise<BulkDownloadResult> {
    if (documentIds.length === 0) {
      throw new BadRequestException('No documents selected');
    }

    if (documentIds.length > 50) {
      throw new BadRequestException('Maximum 50 documents per download');
    }

    // Get documents and verify ownership
    const documents = await this.prisma.generatedDocument.findMany({
      where: {
        id: { in: documentIds },
        status: 'COMPLETED',
        session: { userId },
      },
      select: {
        id: true,
        documentType: true,
        title: true,
        fileUrl: true,
        fileSize: true,
        format: true,
        createdAt: true,
      },
    });

    if (documents.length === 0) {
      throw new NotFoundException('No documents found');
    }

    // Create ZIP filename
    const timestamp = new Date().toISOString().split('T')[0];
    const filename = `documents_${timestamp}.zip`;

    // Create the archive
    const passThrough = new PassThrough();
    const archive = archiver('zip', { zlib: { level: 6 } });

    archive.on('error', (err) => {
      this.logger.error('Archive error', err);
      passThrough.destroy(err);
    });

    archive.pipe(passThrough);

    let totalSize = 0;
    for (const doc of documents) {
      try {
        const content = await this.fetchDocumentContent(doc.fileUrl);
        if (content) {
          const docFilename = this.generateDocumentFilename(doc);
          archive.append(content, { name: docFilename });
          totalSize += Number(doc.fileSize || 0);
        }
      } catch (error) {
        this.logger.warn(`Failed to fetch document ${doc.id}`, error);
      }
    }

    archive.finalize();

    return {
      filename,
      stream: passThrough,
      totalDocuments: documents.length,
      totalSizeEstimate: totalSize,
    };
  }

  /**
   * Fetch document content from storage URL
   */
  private async fetchDocumentContent(url: string): Promise<Buffer | null> {
    try {
      const response = await fetch(url);
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`);
      }
      const arrayBuffer = await response.arrayBuffer();
      return Buffer.from(arrayBuffer);
    } catch (error) {
      this.logger.error(`Failed to fetch ${url}`, error);
      return null;
    }
  }

  /**
   * Generate a unique filename for a document in the ZIP
   */
  private generateDocumentFilename(doc: {
    title: string;
    documentType: string;
    format: string;
    id: string;
  }): string {
    // Sanitize title
    const sanitizedTitle = doc.title
      .replace(/[^a-zA-Z0-9\s-_]/g, '')
      .replace(/\s+/g, '_')
      .substring(0, 100);

    // Determine extension
    const extension = doc.format?.toLowerCase() || 'pdf';

    // Include short ID to ensure uniqueness
    const shortId = doc.id.substring(0, 8);

    return `${sanitizedTitle}_${shortId}.${extension}`;
  }

  /**
