import { QualityCalibratorService } from '../services/quality-calibrator.service';
import { MarkdownRendererService } from '../services/markdown-renderer.service';
import type { DocumentSection, MarkdownDocument } from '../services/markdown-renderer.service';
import type { ExtractedFact } from '@prisma/client';

export interface GenerationRequest {
  projectId: string;
  documentTypeSlug: string;
  qualityLevel: number;
  userId: string;
}

export interface GenerationResult {
  documentId: string;
  projectId: string;
  documentTypeSlug: string;
  qualityLevel: number;
  title: string;
  content: string;
  markdown: string;
  wordCount: number;
  pageEstimate: number;
  generatedAt: Date;
