import {
  Controller,
  Post,
  Get,
  Body,
  Headers,
  Param,
  Req,
  Query,
  HttpCode,
  HttpStatus,
  BadRequestException,
  ForbiddenException,
  Logger,
  RawBodyRequest,
  UseGuards,
} from '@nestjs/common';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { CurrentUser } from '../auth/decorators/user.decorator';
import { AuthenticatedUser } from '../auth/auth.service';
import { ApiBearerAuth, ApiTags } from '@nestjs/swagger';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '@libs/database';
import { Request } from 'express';
import { PaymentService, SubscriptionTier, SUBSCRIPTION_TIERS } from './payment.service';
import { SubscriptionService } from './subscription.service';
import { BillingService } from './billing.service';
import {
  CreateCheckoutDto,
  CreatePortalSessionDto,
  SubscriptionResponseDto,
  InvoiceResponseDto,
} from './dto/payment.dto';
import Stripe from 'stripe';

/**
 * PaymentController - API endpoints for payment and subscription management
 */
@ApiTags('payment')
@Controller('payment')
export class PaymentController {
  private readonly logger = new Logger(PaymentController.name);
  private readonly webhookSecret: string;

  constructor(
    private paymentService: PaymentService,
    private subscriptionService: SubscriptionService,
    private billingService: BillingService,
    private configService: ConfigService,
    private prisma: PrismaService,
  ) {
    this.webhookSecret = this.configService.get<string>('STRIPE_WEBHOOK_SECRET') || '';
  }

  /**
   * Validate that the authenticated user belongs to the specified organization.
   * Throws ForbiddenException if the user does not have access.
   */
  private async validateOrganizationAccess(
    userId: string,
    organizationId: string,
  ): Promise<void> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { organizationId: true },
    });

    if (!user || user.organizationId !== organizationId) {
      throw new ForbiddenException('You do not have access to this organization');
    }
  }

  /**
   * Get available subscription tiers
   */
  @Get('tiers')
  getTiers(): Record<string, object> {
    return SUBSCRIPTION_TIERS;
  }

  /**
   * Create checkout session for subscription
   */
  @Post('checkout')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('JWT-auth')
  async createCheckout(
    @CurrentUser() user: AuthenticatedUser,
    @Body() dto: CreateCheckoutDto,
  ): Promise<{ sessionId: string; url: string }> {
    await this.validateOrganizationAccess(user.id, dto.organizationId);

    return this.paymentService.createCheckoutSession({
      organizationId: dto.organizationId,
      tier: dto.tier as SubscriptionTier,
      successUrl: dto.successUrl,
      cancelUrl: dto.cancelUrl,
      customerId: dto.customerId,
    });
  }

  /**
   * Create customer portal session
   */
  @Post('portal')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('JWT-auth')
  async createPortalSession(
    @CurrentUser() user: AuthenticatedUser,
    @Body() dto: CreatePortalSessionDto,
  ): Promise<{ url: string }> {
    // Validate the customer belongs to user's organization via subscription lookup
    const dbUser = await this.prisma.user.findUnique({
      where: { id: user.id },
      select: { organizationId: true },
    });

    if (!dbUser?.organizationId) {
      throw new ForbiddenException('User is not associated with an organization');
    }

    const subscription = await this.subscriptionService.getOrganizationSubscription(
      dbUser.organizationId,
    );

    if (subscription.stripeCustomerId !== dto.customerId) {
      throw new ForbiddenException('You do not have access to this billing account');
    }

    const url = await this.paymentService.createPortalSession(dto.customerId, dto.returnUrl);
    return { url };
  }

  /**
   * Get subscription status for an organization
   */
  @Get('subscription/:organizationId')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('JWT-auth')
  async getSubscription(
    @CurrentUser() user: AuthenticatedUser,
    @Param('organizationId') organizationId: string,
  ): Promise<SubscriptionResponseDto> {
    await this.validateOrganizationAccess(user.id, organizationId);
    return this.subscriptionService.getOrganizationSubscription(organizationId);
  }

  /**
   * Get billing history (invoices)
   */
  @Get('invoices/:customerId')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('JWT-auth')
  async getInvoices(
    @CurrentUser() user: AuthenticatedUser,
    @Param('customerId') customerId: string,
    @Query('limit') limit?: string,
  ): Promise<InvoiceResponseDto[]> {
    // Validate user owns this customer via their organization's subscription
    const dbUser = await this.prisma.user.findUnique({
      where: { id: user.id },
      select: { organizationId: true },
    });

    if (!dbUser?.organizationId) {
      throw new ForbiddenException('User is not associated with an organization');
    }

    const subscription = await this.subscriptionService.getOrganizationSubscription(
      dbUser.organizationId,
    );

    if (subscription.stripeCustomerId !== customerId) {
      throw new ForbiddenException('You do not have access to this billing account');
    }

    const parsedLimit = limit ? parseInt(limit, 10) : undefined;
    const safeLimit = Number.isFinite(parsedLimit) ? parsedLimit : undefined;
    return this.billingService.getInvoices(customerId, safeLimit);
  }

  /**
   * Get usage stats and tier limits for an organization
   */
  @Get('usage/:organizationId')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('JWT-auth')
  async getUsage(
    @CurrentUser() user: AuthenticatedUser,
    @Param('organizationId') organizationId: string,
  ): Promise<{
    questionnaires: { used: number; limit: number };
    responses: { used: number; limit: number };
    documents: { used: number; limit: number };
    apiCalls: { used: number; limit: number };
  }> {
    await this.validateOrganizationAccess(user.id, organizationId);

    const [usage, subscription] = await Promise.all([
      this.billingService.getUsageStats(organizationId),
      this.subscriptionService.getOrganizationSubscription(organizationId),
    ]);

    const toLimit = (value: number | string): number => (typeof value === 'number' ? value : 0);

    return {
      questionnaires: {
        used: usage.questionnaires,
        limit: toLimit(subscription.features.questionnaires),
      },
      responses: {
        used: usage.responses,
        limit: toLimit(subscription.features.responses),
      },
      documents: {
        used: usage.documents,
        limit: toLimit(subscription.features.documents),
      },
      apiCalls: {
        used: usage.apiCalls,
        limit: toLimit(subscription.features.apiCalls),
      },
    };
  }

  /**
   * Schedule subscription cancellation at period end
   */
  @Post('cancel/:organizationId')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('JWT-auth')
  async cancelSubscription(
    @CurrentUser() user: AuthenticatedUser,
    @Param('organizationId') organizationId: string,
  ): Promise<{ message: string }> {
    await this.validateOrganizationAccess(user.id, organizationId);

    const subscription = await this.subscriptionService.getOrganizationSubscription(organizationId);

    if (!subscription.stripeSubscriptionId) {
      throw new BadRequestException('No active Stripe subscription found');
    }

    await this.paymentService.cancelSubscription(subscription.stripeSubscriptionId, true);

    return { message: 'Subscription cancellation scheduled for end of billing period' };
  }

  /**
   * Resume a subscription that is set to cancel at period end
   */
  @Post('resume/:organizationId')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('JWT-auth')
  async resumeSubscription(
    @CurrentUser() user: AuthenticatedUser,
    @Param('organizationId') organizationId: string,
  ): Promise<{ message: string }> {
    await this.validateOrganizationAccess(user.id, organizationId);

    const subscription = await this.subscriptionService.getOrganizationSubscription(organizationId);

    if (!subscription.stripeSubscriptionId) {
      throw new BadRequestException('No active Stripe subscription found');
    }

    await this.paymentService.resumeSubscription(subscription.stripeSubscriptionId);

    return { message: 'Subscription resumed successfully' };
  }

  /**
   * Stripe webhook handler
   */
  @Post('webhook')
  @HttpCode(HttpStatus.OK)
  async handleWebhook(
    @Req() req: RawBodyRequest<Request>,
    @Headers('stripe-signature') signature: string,
  ): Promise<{ received: boolean }> {
    if (!this.webhookSecret) {
      throw new BadRequestException('Webhook secret not configured');
    }

    if (!req.rawBody) {
      throw new BadRequestException('Missing raw body for webhook verification');
    }

    let event: Stripe.Event;

    try {
      event = this.paymentService.constructWebhookEvent(req.rawBody, signature, this.webhookSecret);
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Webhook signature verification failed: ${errorMessage}`);
      throw new BadRequestException('Invalid webhook signature');
    }

    // Handle specific event types
    switch (event.type) {
      case 'checkout.session.completed':
        await this.handleCheckoutCompleted(event.data.object);
        break;

      case 'customer.subscription.created':
      case 'customer.subscription.updated':
        await this.handleSubscriptionUpdated(event.data.object);
        break;

      case 'customer.subscription.deleted':
        await this.handleSubscriptionDeleted(event.data.object);
        break;

      case 'invoice.payment_succeeded':
        await this.handleInvoicePaymentSucceeded(event.data.object);
        break;

      case 'invoice.payment_failed':
        await this.handleInvoicePaymentFailed(event.data.object);
        break;

      default:
        this.logger.log(`Unhandled webhook event type: ${event.type}`);
    }

    return { received: true };
  }

  // ==========================================
  // Webhook Event Handlers
  // ==========================================

  private async handleCheckoutCompleted(session: Stripe.Checkout.Session): Promise<void> {
    const organizationId = session.metadata?.organizationId;
    const tier = session.metadata?.tier;

    if (!organizationId || !tier) {
      this.logger.warn(`Checkout completed but missing metadata: ${session.id}`);
      return;
    }

    this.logger.log(`Checkout completed for org ${organizationId}, tier ${tier}`);

    await this.subscriptionService.activateSubscription({
      organizationId,
      stripeCustomerId: session.customer as string,
      stripeSubscriptionId: session.subscription as string,
      tier: tier as SubscriptionTier,
    });
  }

  private async handleSubscriptionUpdated(subscription: Stripe.Subscription): Promise<void> {
    this.logger.log(`Subscription updated: ${subscription.id}, status: ${subscription.status}`);

    const customerId = subscription.customer as string;

    await this.subscriptionService.syncSubscriptionStatus({
      stripeSubscriptionId: subscription.id,
      stripeCustomerId: customerId,
      status: subscription.status,
      currentPeriodEnd: new Date(
        (subscription as { current_period_end?: number }).current_period_end! * 1000,
      ),
      cancelAtPeriodEnd: subscription.cancel_at_period_end,
    });
  }

  private async handleSubscriptionDeleted(subscription: Stripe.Subscription): Promise<void> {
    this.logger.log(`Subscription deleted: ${subscription.id}`);

    await this.subscriptionService.cancelSubscriptionByStripeId(subscription.id);
  }

  private async handleInvoicePaymentSucceeded(invoice: Stripe.Invoice): Promise<void> {
    this.logger.log(`Invoice payment succeeded: ${invoice.id}`);

    await this.billingService.recordPayment({
      stripeInvoiceId: invoice.id,
      stripeCustomerId: invoice.customer as string,
      amount: invoice.amount_paid,
      currency: invoice.currency,
      status: 'paid',
      paidAt: new Date((invoice.status_transitions.paid_at || Date.now() / 1000) * 1000),
    });
  }

  private async handleInvoicePaymentFailed(invoice: Stripe.Invoice): Promise<void> {
    this.logger.warn(`Invoice payment failed: ${invoice.id}`);

    await this.billingService.recordPaymentFailure({
      stripeInvoiceId: invoice.id,
      stripeCustomerId: invoice.customer as string,
      amount: invoice.amount_due,
      currency: invoice.currency,
      failureReason: invoice.last_finalization_error?.message || 'Unknown error',
    });
  }
}

/**
 * Policy Pack Service
 * Main orchestration service for policy generation
 */
import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { PolicyGeneratorService } from './services/policy-generator.service';
import { ControlMappingService } from './services/control-mapping.service';
import { OpaPolicyService } from './services/opa-policy.service';
import { TerraformRulesService } from './services/terraform-rules.service';
import { PolicyExportService } from './services/policy-export.service';
import { PolicyPackBundle, PolicyDocument, OpaPolicy } from './types';
import { GapContext } from '../qpg/types';
import { v4 as uuidv4 } from 'uuid';

@Injectable()
export class PolicyPackService {
  private readonly logger = new Logger(PolicyPackService.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly policyGenerator: PolicyGeneratorService,
    private readonly controlMapping: ControlMappingService,
    private readonly opaPolicy: OpaPolicyService,
    private readonly terraformRules: TerraformRulesService,
    private readonly exportService: PolicyExportService,
  ) {}

  /**
   * Generate complete policy pack from session gaps
   */
  async generatePolicyPack(sessionId: string, gaps: GapContext[]): Promise<PolicyPackBundle> {
    this.logger.log(`Generating policy pack for session: ${sessionId}`);

    // Generate policies for each gap
    const policies: PolicyDocument[] = [];
    const dimensionsCovered = new Set<string>();

    for (const gap of gaps) {
      try {
        const policy = await this.policyGenerator.generatePolicyForGap(gap);
        policies.push(policy);
        dimensionsCovered.add(gap.dimensionKey);
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error);
        this.logger.warn(`Failed to generate policy for gap ${gap.questionId}: ${errorMessage}`);
      }
    }

    // Get OPA policies for covered dimensions
    const opaPolicies: OpaPolicy[] = [];
    for (const dimension of dimensionsCovered) {
      const dimensionPolicies = this.opaPolicy.getPoliciesForDimension(dimension);
      opaPolicies.push(...dimensionPolicies);
    }

    // Get Terraform rules for covered dimensions
    const terraformRulesArr = [];
    for (const dimension of dimensionsCovered) {
      const rules = this.terraformRules.getRulesForDimension(dimension);
      terraformRulesArr.push(...rules);
    }
    const terraformRulesContent = this.terraformRules.generateFeatureFile(terraformRulesArr);

    // Get score at generation
    const session = await this.prisma.session.findUnique({
      where: { id: sessionId },
    });
    const scoreAtGeneration = session?.readinessScore
      ? typeof session.readinessScore === 'number'
        ? session.readinessScore
        : (session.readinessScore.toNumber?.() ?? Number(session.readinessScore))
      : 0;

    const bundle: PolicyPackBundle = {
      id: `pack-${uuidv4()}`,
      name: `Quiz2Biz Policy Pack - ${new Date().toISOString().split('T')[0]}`,
      version: '1.0.0',
      generatedAt: new Date(),
      policies,
      opaPolicies,
      terraformRules: terraformRulesContent,
      readmeContent: '', // Will be generated by export service
      sourceSessionId: sessionId,
      scoreAtGeneration,
    };

    // Generate README
    bundle.readmeContent = this.exportService.generateReadme(bundle);

    this.logger.log(
      `Generated policy pack with ${policies.length} policies, ${opaPolicies.length} OPA policies`,
    );

    return bundle;
  }

  /**
   * Get export structure for download
   */
  getExportStructure(bundle: PolicyPackBundle) {
    return this.exportService.getExportStructure(bundle);
  }

  /**
   * Get control mappings for a dimension
   */
  getControlMappings(dimensionKey: string) {
    return this.controlMapping.getMappingsForDimension(dimensionKey);
  }

  /**
   * Get all OPA policies
   */
  getAllOpaPolicies() {
    return this.opaPolicy.getAllPolicies();
  }

  /**
   * Get all Terraform rules
   */
  getAllTerraformRules() {
    return this.terraformRules.getAllRules();
  }

  /**
   * Generate combined OPA policy file
   */
  generateCombinedOpaFile(policies: OpaPolicy[]) {
    return this.opaPolicy.generateCombinedRegoFile(policies);
  }
}

/**
 * Policy Export Service
 * Exports policy packs as ZIP bundles with README
 */
import { Injectable } from '@nestjs/common';
import { PolicyPackBundle, PolicyDocument } from '../types';

@Injectable()
export class PolicyExportService {

  /**
   * Generate README content for policy pack
   */
  generateReadme(bundle: PolicyPackBundle): string {
    const lines: string[] = [
      `# ${bundle.name}`,
      '',
      `Version: ${bundle.version}`,
      `Generated: ${bundle.generatedAt.toISOString()}`,
      '',
      '## Contents',
      '',
      '### Policies',
      '',
    ];

    for (const policy of bundle.policies) {
      lines.push(`- **${policy.title}** (${policy.type})`);
      lines.push(`  - Dimension: ${policy.dimensionKey}`);
      lines.push(`  - Status: ${policy.status}`);
      lines.push(`  - Standards: ${policy.standards.length}`);
      lines.push('');
    }

    lines.push('### OPA/Rego Policies');
    lines.push('');
    for (const opa of bundle.opaPolicies) {
      lines.push(`- **${opa.name}**: ${opa.description} (${opa.severity})`);
    }
    lines.push('');

    lines.push('### Terraform Compliance Rules');
    lines.push('');
    lines.push('See `terraform/features/` directory for compliance rules.');
    lines.push('');

    lines.push('## Usage');
    lines.push('');
    lines.push('### OPA Policies');
    lines.push('```bash');
    lines.push('# Validate with OPA');
    lines.push('opa eval --data opa-policies/ --input terraform.json "data.quiz2biz"');
    lines.push('```');
    lines.push('');
    lines.push('### Terraform Compliance');
    lines.push('```bash');
    lines.push('# Run terraform-compliance');
    lines.push('terraform plan -out=plan.tfplan');
    lines.push('terraform show -json plan.tfplan > plan.json');
    lines.push('terraform-compliance -f terraform/features/ -p plan.json');
    lines.push('```');
    lines.push('');

    lines.push('## Control Mappings');
    lines.push('');
    lines.push('| Framework | Controls |');
    lines.push('|-----------|----------|');

    const frameworkCounts: Record<string, number> = {};
    for (const policy of bundle.policies) {
      for (const mapping of policy.controlMappings) {
        frameworkCounts[mapping.framework] = (frameworkCounts[mapping.framework] || 0) + 1;
      }
    }
    for (const [framework, count] of Object.entries(frameworkCounts)) {
      lines.push(`| ${framework} | ${count} |`);
    }
    lines.push('');

    if (bundle.sourceSessionId) {
      lines.push('---');
      lines.push('');
      lines.push(`Generated from Quiz2Biz Session: ${bundle.sourceSessionId}`);
      lines.push(`Score at Generation: ${bundle.scoreAtGeneration ?? 'N/A'}%`);
    }

    return lines.join('\n');
  }

  /**
   * Generate policy document as markdown
   */
  generatePolicyMarkdown(policy: PolicyDocument): string {
    const lines: string[] = [
      `# ${policy.title}`,
      '',
      `**Version:** ${policy.version}`,
      `**Type:** ${policy.type}`,
      `**Status:** ${policy.status}`,
      `**Owner:** ${policy.owner}`,
      `**Effective Date:** ${policy.effectiveDate.toISOString().split('T')[0]}`,
      `**Review Date:** ${policy.reviewDate.toISOString().split('T')[0]}`,
      '',
      '## Objective',
      '',
      policy.objective,
      '',
      '## Scope',
      '',
      policy.scope,
      '',
      '## Policy Statements',
      '',
    ];

    for (const stmt of policy.statements) {
      const icon =
        String(stmt.requirement) === 'SHALL'
          ? '­ƒö┤'
          : String(stmt.requirement) === 'SHOULD'
            ? '­ƒƒí'
            : '­ƒƒó';
      lines.push(`${icon} **${stmt.requirement}:** ${stmt.text}`);
      if (stmt.evidenceRequired) {
        lines.push('   - *Evidence required*');
      }
      lines.push('');
    }

    if (policy.standards.length > 0) {
      lines.push('## Standards');
      lines.push('');
      for (const std of policy.standards) {
        lines.push(`### ${std.title}`);
        lines.push('');
        lines.push('#### Requirements');
        lines.push('');
        for (const req of std.requirements) {
          lines.push(`- **${req.id}:** ${req.description}`);
          lines.push(`  - Specification: ${req.specification}`);
          lines.push(`  - Verification: ${req.verificationMethod}`);
        }
        lines.push('');

        if (std.procedures.length > 0) {
          lines.push('#### Procedures');
          lines.push('');
          for (const proc of std.procedures) {
            lines.push(`##### ${proc.title}`);
            lines.push('');
            lines.push(`**Roles:** ${proc.roles.join(', ')}`);
            lines.push(`**Frequency:** ${proc.frequency || 'As needed'}`);
            lines.push('');
            lines.push('**Steps:**');
            for (const step of proc.steps) {
              lines.push(`${step.order}. ${step.description} *(${step.responsibleRole})*`);
            }
            lines.push('');
          }
        }
      }
    }

    if (policy.controlMappings.length > 0) {
      lines.push('## Control Mappings');
      lines.push('');
      lines.push('| Framework | Control ID | Description |');
      lines.push('|-----------|------------|-------------|');
      for (const mapping of policy.controlMappings) {
        lines.push(
          `| ${mapping.framework} | ${mapping.controlId} | ${mapping.controlDescription} |`,
        );
      }
      lines.push('');
    }

    return lines.join('\n');
  }

  /**
   * Generate bundle manifest
   */
  generateManifest(bundle: PolicyPackBundle): string {
    return JSON.stringify(
      {
        id: bundle.id,
        name: bundle.name,
        version: bundle.version,
        generatedAt: bundle.generatedAt.toISOString(),
        sourceSessionId: bundle.sourceSessionId,
        scoreAtGeneration: bundle.scoreAtGeneration,
        contents: {
          policies: bundle.policies.map((p) => ({
            id: p.id,
            title: p.title,
            type: p.type,
            dimension: p.dimensionKey,
          })),
          opaPolicies: bundle.opaPolicies.map((o) => ({
            name: o.name,
            severity: o.severity,
          })),
          hasTerraformRules: !!bundle.terraformRules,
        },
      },
      null,
      2,
    );
  }

  /**
   * Get file structure for ZIP export
   */
  getExportStructure(bundle: PolicyPackBundle): { path: string; content: string }[] {
    const files: { path: string; content: string }[] = [];

    // README
    files.push({
      path: 'README.md',
      content: this.generateReadme(bundle),
    });

    // Manifest
    files.push({
      path: 'manifest.json',
      content: this.generateManifest(bundle),
    });

    // Policies
    for (const policy of bundle.policies) {
      files.push({
        path: `policies/${policy.dimensionKey}/${policy.id}.md`,
        content: this.generatePolicyMarkdown(policy),
      });
      files.push({
        path: `policies/${policy.dimensionKey}/${policy.id}.json`,
        content: JSON.stringify(policy, null, 2),
      });
    }

    // OPA policies
    for (const opa of bundle.opaPolicies) {
      files.push({
        path: `opa-policies/${opa.name}.rego`,
        content: opa.regoCode,
      });
    }

    // Combined OPA policy
    if (bundle.opaPolicies.length > 0) {
      const combinedRego = bundle.opaPolicies.map((o) => o.regoCode).join('\n\n---\n\n');
      files.push({
        path: 'opa-policies/combined.rego',
        content: combinedRego,
      });
    }

    // Terraform rules
    if (bundle.terraformRules) {
      files.push({
        path: 'terraform/features/quiz2biz.feature',
        content: bundle.terraformRules,
      });
    }

    return files;
  }
}

/**
 * Context Builder Service
 * Builds gap context from questionnaire session data
 */
import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { GapContext } from '../types';

@Injectable()
export class ContextBuilderService {
  private readonly logger = new Logger(ContextBuilderService.name);

  constructor(private readonly prisma: PrismaService) {}

  /**
   * Build gap contexts for a session
   * Identifies questions with coverage < 1.0 (gaps)
   */
  async buildGapContexts(sessionId: string): Promise<GapContext[]> {
    this.logger.log(`Building gap contexts for session: ${sessionId}`);

    // Get session with responses and questions
    const session = await this.prisma.session.findUnique({
      where: { id: sessionId },
      include: {
        responses: {
          include: {
            question: {
              include: {
                dimension: true,
              },
            },
          },
        },
      },
    });

    if (!session) {
      this.logger.warn(`Session not found: ${sessionId}`);
      return [];
    }

    const gaps: GapContext[] = [];

    for (const response of session.responses) {
      // Only include responses with coverage < 1.0 (gaps)
      const coverage = response.coverage?.toNumber() ?? 0;
      if (coverage < 1.0) {
        const question = response.question;
        const dimension = question.dimension;

        // Calculate residual risk for this gap
        const severity = question.severity?.toNumber() ?? 0.5;
        const residualRisk = severity * (1 - coverage);

        gaps.push({
          sessionId,
          dimensionKey: dimension?.key ?? 'unknown',
          dimensionName: dimension?.displayName ?? 'Unknown',
          questionId: question.id,
          questionText: question.text,
          currentCoverage: coverage,
          severity,
          residualRisk,
          bestPractice: question.bestPractice ?? '',
          practicalExplainer: question.practicalExplainer ?? '',
          standardRefs: this.parseStandardRefs(question.standardRefs),
          userAnswer: response.value as string | undefined,
          userNotes: response.rationale ?? undefined,
        });
      }
    }

    // Sort by residual risk (highest first)
    gaps.sort((a, b) => b.residualRisk - a.residualRisk);

    this.logger.log(`Found ${gaps.length} gaps for session ${sessionId}`);
    return gaps;
  }

  /**
   * Parse standard references from JSON or comma-separated string
   */
  private parseStandardRefs(refs: string | null | undefined): string[] {
    if (!refs) {
      return [];
    }

    try {
      // Try JSON parse first
      const parsed = JSON.parse(refs);
      if (Array.isArray(parsed)) {
        return parsed;
      }
    } catch {
      // Fall back to comma-separated
      return refs
        .split(',')
        .map((s) => s.trim())
        .filter(Boolean);
    }

    return [];
  }

  /**
   * Get gap summary for a session
   */
  async getGapSummary(sessionId: string): Promise<{
    totalGaps: number;
    byDimension: Record<string, number>;
    highPriorityCount: number;
    totalResidualRisk: number;
  }> {
    const gaps = await this.buildGapContexts(sessionId);

    const byDimension: Record<string, number> = {};
    let highPriorityCount = 0;
    let totalResidualRisk = 0;

    for (const gap of gaps) {
      byDimension[gap.dimensionKey] = (byDimension[gap.dimensionKey] || 0) + 1;
      totalResidualRisk += gap.residualRisk;
      if (gap.residualRisk > 0.15) {
        highPriorityCount++;
      }
    }

    return {
      totalGaps: gaps.length,
      byDimension,
      highPriorityCount,
      totalResidualRisk,
    };
  }
}

/**
 * Prompt Generator Service
 * Generates Quest-Mode prompts from gap context and templates
 */
import { Injectable, Logger } from '@nestjs/common';
import { GapContext, PromptTemplate, QuestModePrompt, PromptTask, TaskCondition } from '../types';
import { v4 as uuidv4 } from 'uuid';

@Injectable()
export class PromptGeneratorService {
  private readonly logger = new Logger(PromptGeneratorService.name);

  /**
   * Generate a Quest-Mode prompt from gap context and template
   */
  async generate(gap: GapContext, template: PromptTemplate): Promise<QuestModePrompt> {
    this.logger.debug(`Generating prompt for gap: ${gap.questionId}`);

    // Build context variables for template interpolation
    const context = this.buildTemplateContext(gap);

    // Generate goal
    const goal = this.interpolate(template.goalTemplate, context);

    // Generate tasks
    const tasks = this.generateTasks(template.taskTemplates, context, gap);

    // Generate acceptance criteria
    const acceptanceCriteria = template.defaultAcceptanceCriteria.map((ac) =>
      this.interpolate(ac, context),
    );

    // Generate constraints
    const constraints = template.defaultConstraints.map((c) => this.interpolate(c, context));

    // Generate deliverables
    const deliverables = template.defaultDeliverables.map((d) => this.interpolate(d, context));

    // Calculate priority (1-5 based on residual risk)
    const priority = this.calculatePriority(gap.residualRisk);

    // Calculate effort estimate (base * severity factor)
    const effortMultiplier = gap.severity > 0.7 ? 1.5 : gap.severity > 0.4 ? 1.2 : 1.0;
    const estimatedEffort = Math.round(template.baseEffortHours * effortMultiplier);

    // Generate tags
    const tags = this.generateTags(gap, template);

    const prompt: QuestModePrompt = {
      id: `prompt-${uuidv4()}`,
      dimensionKey: gap.dimensionKey,
      questionId: gap.questionId,
      goal,
      tasks,
      acceptanceCriteria,
      constraints,
      deliverables,
      priority,
      estimatedEffort,
      evidenceType: template.evidenceType,
      tags,
      generatedAt: new Date(),
    };

    return prompt;
  }

  /**
   * Build context variables for template interpolation
   */
  private buildTemplateContext(gap: GapContext): Record<string, string> {
    return {
      dimensionKey: gap.dimensionKey,
      dimensionName: gap.dimensionName,
      questionId: gap.questionId,
      questionText: gap.questionText,
      currentCoverage: `${Math.round(gap.currentCoverage * 100)}%`,
      severity: gap.severity.toFixed(2),
      residualRisk: gap.residualRisk.toFixed(3),
      bestPractice: gap.bestPractice,
      practicalExplainer: gap.practicalExplainer,
      standardRefs: gap.standardRefs.join(', ') || 'industry best practices',
      userAnswer: gap.userAnswer || 'Not provided',
      userNotes: gap.userNotes || 'None',
    };
  }

  /**
   * Interpolate template string with context variables
   */
  private interpolate(template: string, context: Record<string, string>): string {
    return template.replace(/\{\{(\w+)\}\}/g, (match, key) => {
      return context[key] || match;
    });
  }

  /**
   * Generate tasks from templates, applying conditions
   */
  private generateTasks(
    taskTemplates: PromptTemplate['taskTemplates'],
    context: Record<string, string>,
    gap: GapContext,
  ): PromptTask[] {
    const tasks: PromptTask[] = [];

    for (const tt of taskTemplates) {
      // Check condition if present
      if (tt.condition && !this.evaluateCondition(tt.condition, gap)) {
        continue;
      }

      tasks.push({
        order: tt.order,
        description: this.interpolate(tt.template, context),
      });
    }

    return tasks;
  }

  /**
   * Evaluate task condition
   */
  private evaluateCondition(condition: TaskCondition, gap: GapContext): boolean {
    const value = gap[condition.field as keyof GapContext];
    if (value === undefined) {
      return false;
    }

    switch (condition.operator) {
      case 'eq':
        return value === condition.value;
      case 'ne':
        return value !== condition.value;
      case 'gt':
        return typeof value === 'number' && value > (condition.value as number);
      case 'lt':
        return typeof value === 'number' && value < (condition.value as number);
      case 'contains':
        return typeof value === 'string' && value.includes(condition.value as string);
      default:
        return false;
    }
  }

  /**
   * Calculate priority from residual risk (1-5, 1 = highest)
   */
  private calculatePriority(residualRisk: number): number {
    if (residualRisk > 0.2) {
      return 1;
    } // Critical
    if (residualRisk > 0.15) {
      return 2;
    } // High
    if (residualRisk > 0.1) {
      return 3;
    } // Medium
    if (residualRisk > 0.05) {
      return 4;
    } // Low
    return 5; // Minimal
  }

  /**
   * Generate tags for the prompt
   */
  private generateTags(gap: GapContext, template: PromptTemplate): string[] {
    const tags: string[] = [gap.dimensionKey, template.evidenceType.toLowerCase()];

    // Add priority tag
    const priority = this.calculatePriority(gap.residualRisk);
    if (priority === 1) {
      tags.push('critical');
    } else if (priority === 2) {
      tags.push('high-priority');
    }

    // Add standard refs as tags
    for (const ref of gap.standardRefs.slice(0, 3)) {
      const cleanRef = ref.replace(/[^a-zA-Z0-9]/g, '-').toLowerCase();
      if (cleanRef) {
        tags.push(cleanRef);
      }
    }

    return [...new Set(tags)]; // Remove duplicates
  }

  /**
   * Format prompt as markdown for display/export
   */
  formatAsMarkdown(prompt: QuestModePrompt): string {
    const lines: string[] = [
      `# ${prompt.goal}`,
      '',
      '## Goal',
      prompt.goal,
      '',
      '## Tasks',
      ...prompt.tasks.map((t) => `${t.order}. ${t.description}`),
      '',
      '## Acceptance Criteria',
      ...prompt.acceptanceCriteria.map((ac) => `- [ ] ${ac}`),
      '',
      '## Constraints',
      ...prompt.constraints.map((c) => `- ${c}`),
      '',
      '## Deliverables',
      ...prompt.deliverables.map((d) => `- ${d}`),
      '',
      '---',
      `**Priority:** P${prompt.priority}`,
      `**Estimated Effort:** ${prompt.estimatedEffort}h`,
      `**Evidence Required:** ${prompt.evidenceType}`,
      `**Tags:** ${prompt.tags.join(', ')}`,
    ];

    return lines.join('\n');
  }
}

/**
 * Pure calculation helpers for the Scoring Engine.
 * No service dependencies ÔÇö all functions are stateless.
 */
import { Decimal } from '@prisma/client/runtime/library';
import { CoverageLevel } from '@prisma/client';
import { DimensionResidual } from './dto';
import {
  EPSILON,
  DEFAULT_SEVERITY,
  ScoreSnapshot,
  TrendAnalysis,
  coverageLevelToDecimal,
} from './scoring-types';

// Re-export for convenience
export { coverageLevelToDecimal } from './scoring-types';

/**
 * Build coverage map from responses with optional overrides.
 * Prefers coverageLevel (discrete) over coverage (continuous).
 */
export function buildCoverageMap(
  questions: Array<{
    id: string;
    responses: Array<{
      coverage: Decimal | null;
      coverageLevel?: CoverageLevel | null;
    }>;
  }>,
  overrides?: Array<{ questionId: string; coverage: number }>,
): Map<string, number> {
  const coverageMap = new Map<string, number>();

  questions.forEach((q) => {
    const response = q.responses[0];
    let coverage: number;

    if (response?.coverageLevel) {
      coverage = coverageLevelToDecimal(response.coverageLevel);
    } else if (response?.coverage) {
      coverage = Number(response.coverage);
    } else {
      coverage = 0;
    }

    coverageMap.set(q.id, coverage);
  });

  if (overrides) {
    const { decimalToCoverageLevel } = require('./scoring-types');
    overrides.forEach((override) => {
      if (coverageMap.has(override.questionId)) {
        const level = decimalToCoverageLevel(override.coverage);
        coverageMap.set(override.questionId, coverageLevelToDecimal(level));
      }
    });
  }

  return coverageMap;
}

/**
 * Calculate residual risk for each dimension.
 * R_d = ╬ú(S_i ├ù (1-C_i)) / (╬ú S_i + ╬Á)
 */
export function calculateDimensionResiduals(
  dimensions: Array<{
    key: string;
    displayName: string;
    weight: Decimal;
  }>,
  questions: Array<{
    id: string;
    dimensionKey: string | null;
    severity: Decimal | null;
    responses: Array<{ coverage: Decimal | null }>;
  }>,
  coverageMap: Map<string, number>,
): DimensionResidual[] {
  return dimensions.map((dim) => {
    const dimQuestions = questions.filter((q) => q.dimensionKey === dim.key);

    if (dimQuestions.length === 0) {
      return {
        dimensionKey: dim.key,
        displayName: dim.displayName,
        weight: Number(dim.weight),
        residualRisk: 0,
        weightedContribution: 0,
        questionCount: 0,
        answeredCount: 0,
        averageCoverage: 0,
      };
    }

    let numerator = 0;
    let severitySum = 0;
    let totalCoverage = 0;
    let answeredCount = 0;

    dimQuestions.forEach((q) => {
      const severity = q.severity ? Number(q.severity) : DEFAULT_SEVERITY;
      const coverage = coverageMap.get(q.id) || 0;

      numerator += severity * (1 - coverage);
      severitySum += severity;
      totalCoverage += coverage;

      if (q.responses.length > 0) {
        answeredCount++;
      }
    });

    const residualRisk = numerator / (severitySum + EPSILON);
    const weight = Number(dim.weight);
    const weightedContribution = weight * residualRisk;

    return {
      dimensionKey: dim.key,
      displayName: dim.displayName,
      weight,
      residualRisk: Math.round(residualRisk * 10000) / 10000,
      weightedContribution: Math.round(weightedContribution * 10000) / 10000,
      questionCount: dimQuestions.length,
      answeredCount,
      averageCoverage: Math.round((totalCoverage / dimQuestions.length) * 100) / 100,
    };
  });
}

/** Generate human-readable rationale for question prioritization */
export function generateRationale(
  deltaScore: number,
  _dimensionKey: string,
  dimensionName: string,
  currentCoverage: number,
): string {
  const scoreGain = deltaScore.toFixed(1);
  const coveragePercent = (currentCoverage * 100).toFixed(0);

  if (currentCoverage === 0) {
    return `Answering this ${dimensionName} question could improve your score by up to ${scoreGain} points. This question has no coverage yet.`;
  }

  return `Improving coverage on this ${dimensionName} question from ${coveragePercent}% to 100% could add ${scoreGain} points to your readiness score.`;
}

/** Calculate trend analysis from score history */
export function calculateTrendAnalysis(history: ScoreSnapshot[]): TrendAnalysis {
  if (history.length < 2) {
    return {
      direction: 'STABLE',
      averageChange: 0,
      volatility: 0,
      projectedScore: history[0]?.score ?? 0,
    };
  }

  const changes: number[] = [];
  for (let i = 0; i < history.length - 1; i++) {
    changes.push(history[i].score - history[i + 1].score);
  }

  const averageChange = changes.reduce((sum, c) => sum + c, 0) / changes.length;

  const squaredDiffs = changes.map((c) => Math.pow(c - averageChange, 2));
  const volatility = Math.sqrt(squaredDiffs.reduce((sum, d) => sum + d, 0) / changes.length);

  let direction: 'UP' | 'DOWN' | 'STABLE';
  if (averageChange > 1) {
    direction = 'UP';
  } else if (averageChange < -1) {
    direction = 'DOWN';
  } else {
    direction = 'STABLE';
  }

  const projectedScore = Math.max(0, Math.min(100, history[0].score + averageChange));

  return {
    direction,
    averageChange: Math.round(averageChange * 100) / 100,
    volatility: Math.round(volatility * 100) / 100,
    projectedScore: Math.round(projectedScore * 100) / 100,
  };
}

/** Generate recommendation for dimension improvement */
export function generateDimensionRecommendation(dim: DimensionResidual, gapToAverage: number): string {
  if (gapToAverage < -0.1) {
    return `${dim.displayName} is performing above industry average. Maintain current practices.`;
  }

  if (gapToAverage > 0.2) {
    return `${dim.displayName} has significant gaps. Prioritize ${dim.questionCount - dim.answeredCount} unanswered questions to improve by ${Math.round(gapToAverage * 100)}%.`;
  }

  if (gapToAverage > 0.1) {
    return `${dim.displayName} is slightly below average. Review ${dim.questionCount - dim.answeredCount} remaining questions for quick wins.`;
  }

  return `${dim.displayName} is performing at industry average. Focus on other dimensions for maximum impact.`;
}

/**
 * Scoring Engine Service ÔÇö Orchestrator (thin facade).
 *
 * Implements Quiz2Biz risk-weighted readiness scoring with explicit formulas:
 *   Coverage (per question): C_i Ôêê [0,1]
 *   Dimension Residual Risk: R_d = ╬ú(S_i ├ù (1-C_i)) / (╬ú S_i + ╬Á)
 *   Portfolio Residual Risk: R = ╬ú(W_d ├ù R_d)
 *   Readiness Score: Score = 100 ├ù (1 - R)
 *
 * Delegates calculation helpers to scoring-calculator.ts and
 * benchmark/history analytics to strategies/scoring-analytics.ts.
 */
import { Injectable, Logger, NotFoundException } from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { RedisService } from '@libs/redis';
import { Decimal } from '@prisma/client/runtime/library';
import {
  CalculateScoreDto,
  ReadinessScoreResult,
  NextQuestionsDto,
  NextQuestionsResult,
  PrioritizedQuestion,
  CoverageLevelDto,
} from './dto';

// Re-export types for backward compatibility (spec file imports these from here)
export {
  COVERAGE_LEVEL_VALUES,
  coverageLevelToDecimal,
  decimalToCoverageLevel,
  ScoreSnapshot,
  ScoreHistoryResult,
  TrendAnalysis,
  BenchmarkResult,
  DimensionBenchmarkResult,
} from './scoring-types';

import {
  DEFAULT_SEVERITY,
  EPSILON,
  SCORE_CACHE_TTL,
  ScoreHistoryResult,
  BenchmarkResult,
  DimensionBenchmarkResult,
} from './scoring-types';
import { decimalToCoverageLevel } from './scoring-types';
import {
  buildCoverageMap,
  calculateDimensionResiduals,
  generateRationale,
} from './scoring-calculator';
import { ScoringAnalyticsService } from './strategies/scoring-analytics';

@Injectable()
export class ScoringEngineService {
  private readonly logger = new Logger(ScoringEngineService.name);
  private readonly analytics: ScoringAnalyticsService;

  constructor(
    private readonly prisma: PrismaService,
    private readonly redis: RedisService,
  ) {
    this.analytics = new ScoringAnalyticsService(prisma);
  }

  /**
   * Calculate the complete readiness score for a session.
   * Uses parameterized queries throughout for security.
   */
  async calculateScore(dto: CalculateScoreDto): Promise<ReadinessScoreResult> {
    const startTime = Date.now();
    const { sessionId, coverageOverrides } = dto;

    const session = await this.prisma.session.findUnique({
      where: { id: sessionId },
      include: { questionnaire: true },
    });

    if (!session) {
      throw new NotFoundException(`Session not found: ${sessionId}`);
    }

    const previousScore = session.readinessScore ? Number(session.readinessScore) : null;

    // Fetch dimensions filtered by session's project type when available
    const dimensionWhere: { isActive: boolean; projectTypeId?: string | null } = { isActive: true };
    if (session.projectTypeId) {
      dimensionWhere.projectTypeId = session.projectTypeId;
    }
    const dimensions = await this.prisma.dimensionCatalog.findMany({
      where: dimensionWhere,
      orderBy: { orderIndex: 'asc' },
      take: 10000,
    });

    // Fetch questions for this questionnaire filtered by session persona
    const questions = await this.prisma.question.findMany({
      where: {
        section: { questionnaireId: session.questionnaireId },
        ...(session.persona && { persona: session.persona }),
      },
      include: {
        responses: { where: { sessionId }, take: 1 },
        dimension: true,
      },
      take: 10000,
    });

    const coverageMap = buildCoverageMap(questions, coverageOverrides);
    const dimensionResults = calculateDimensionResiduals(dimensions, questions, coverageMap);

    const portfolioResidual = dimensionResults.reduce((sum, dim) => sum + dim.weightedContribution, 0);
    const score = Math.max(0, Math.min(100, 100 * (1 - portfolioResidual)));

    const totalQuestions = questions.length;
    const answeredQuestions = questions.filter((q) => q.responses.length > 0).length;
    const completionPercentage = totalQuestions > 0 ? (answeredQuestions / totalQuestions) * 100 : 0;

    // Determine trend
    let trend: 'UP' | 'DOWN' | 'STABLE' | 'FIRST';
    if (previousScore === null) {
      trend = 'FIRST';
    } else if (score > previousScore + 0.5) {
      trend = 'UP';
    } else if (score < previousScore - 0.5) {
      trend = 'DOWN';
    } else {
      trend = 'STABLE';
    }

    await this.prisma.session.update({
      where: { id: sessionId },
      data: {
        readinessScore: new Decimal(score.toFixed(2)),
        lastScoreCalculation: new Date(),
      },
    });

    const result: ReadinessScoreResult = {
      sessionId,
      score: Math.round(score * 100) / 100,
      portfolioResidual: Math.round(portfolioResidual * 10000) / 10000,
      dimensions: dimensionResults,
      totalQuestions,
      answeredQuestions,
      completionPercentage: Math.round(completionPercentage * 10) / 10,
      calculatedAt: new Date(),
      trend,
    };

    await this.saveScoreSnapshot(sessionId, result);
    await this.cacheScore(sessionId, result);

    const elapsed = Date.now() - startTime;
    this.logger.log(`Score calculated for session ${sessionId}: ${score.toFixed(2)} in ${elapsed}ms`);

    return result;
  }

  /**
   * Get prioritized next questions using NQS algorithm.
   * ╬öScore_i = 100 ├ù W_d(i) ├ù S_i / (╬ú S_j + ╬Á)
   */
  async getNextQuestions(dto: NextQuestionsDto): Promise<NextQuestionsResult> {
    const { sessionId, limit = 5 } = dto;

    let currentResult = await this.getCachedScore(sessionId);
    if (!currentResult) {
      currentResult = await this.calculateScore({ sessionId });
    }

    const session = await this.prisma.session.findUnique({
      where: { id: sessionId },
      select: { persona: true },
    });

    const questions = await this.prisma.question.findMany({
      where: {
        section: { questionnaire: { sessions: { some: { id: sessionId } } } },
        dimensionKey: { not: null },
        ...(session?.persona && { persona: session.persona }),
      },
      include: {
        responses: { where: { sessionId }, take: 1 },
        dimension: true,
      },
      take: 10000,
    });

    const dimensions = await this.prisma.dimensionCatalog.findMany({
      where: { isActive: true },
      take: 10000,
    });
    const dimensionWeightMap = new Map(dimensions.map((d) => [d.key, Number(d.weight)]));

    const dimensionSeveritySum = new Map<string, number>();
    questions.forEach((q) => {
      if (q.dimensionKey) {
        const current = dimensionSeveritySum.get(q.dimensionKey) || 0;
        dimensionSeveritySum.set(
          q.dimensionKey,
          current + (q.severity ? Number(q.severity) : DEFAULT_SEVERITY),
        );
      }
    });

    const prioritizedQuestions: PrioritizedQuestion[] = [];

    for (const question of questions) {
      const response = question.responses[0];
      const currentCoverage: number = response?.coverage ? Number(response.coverage) : 0;

      if (currentCoverage >= 1.0) {
        continue;
      }

      const severity: number = question.severity ? Number(question.severity) : DEFAULT_SEVERITY;
      const dimensionKey: string = question.dimensionKey || 'unknown';
      const dimensionWeight: number = Number(dimensionWeightMap.get(dimensionKey) ?? 0);
      const severitySum: number = Number(dimensionSeveritySum.get(dimensionKey) ?? 1);

      const deltaScore: number =
        (100 * dimensionWeight * severity * (1 - currentCoverage)) / (severitySum + EPSILON);

      prioritizedQuestions.push({
        questionId: question.id,
        text: question.text,
        dimensionKey,
        dimensionName: question.dimension?.displayName || dimensionKey,
        severity,
        currentCoverage,
        currentCoverageLevel: decimalToCoverageLevel(currentCoverage) as CoverageLevelDto,
        expectedScoreLift: Math.round(deltaScore * 100) / 100,
        rationale: generateRationale(
          deltaScore,
          dimensionKey,
          question.dimension?.displayName || dimensionKey,
          currentCoverage,
        ),
        rank: 0,
      });
    }

    prioritizedQuestions.sort((a, b) => b.expectedScoreLift - a.expectedScoreLift);
    const topQuestions = prioritizedQuestions.slice(0, limit).map((q, i) => ({ ...q, rank: i + 1 }));

    const totalPotentialLift = topQuestions.reduce((sum, q) => sum + q.expectedScoreLift, 0);
    const maxPotentialScore = Math.min(100, currentResult.score + totalPotentialLift);

    return {
      sessionId,
      currentScore: currentResult.score,
      questions: topQuestions,
      maxPotentialScore: Math.round(maxPotentialScore * 100) / 100,
    };
  }

  /** Invalidate cached score for a session */
  async invalidateScoreCache(sessionId: string): Promise<void> {
    try {
      const cacheKey = `score:${sessionId}`;
      await this.redis.del(cacheKey);
    } catch (error) {
      this.logger.warn(`Failed to invalidate score cache for session ${sessionId}`, error);
    }
  }

  /** Calculate score for multiple sessions (batch, controlled concurrency) */
  async calculateBatchScores(sessionIds: string[]): Promise<Map<string, ReadinessScoreResult>> {
    const results = new Map<string, ReadinessScoreResult>();
    const batchSize = 5;

    for (let i = 0; i < sessionIds.length; i += batchSize) {
      const batch = sessionIds.slice(i, i + batchSize);
      const batchResults = await Promise.all(
        batch.map((id) =>
          this.calculateScore({ sessionId: id }).catch((error) => {
            this.logger.error(`Failed to calculate score for ${id}`, error);
            return null;
          }),
        ),
      );

      batchResults.forEach((result, index) => {
        if (result) {
          results.set(batch[index], result);
        }
      });
    }

    return results;
  }

  // === Delegated analytics methods ===

  async getScoreHistory(sessionId: string, limit?: number): Promise<ScoreHistoryResult> {
    return this.analytics.getScoreHistory(sessionId, limit);
  }

  async getIndustryBenchmark(sessionId: string, industryCode?: string): Promise<BenchmarkResult> {
    return this.analytics.getIndustryBenchmark(sessionId, industryCode);
  }

  async getDimensionBenchmarks(sessionId: string): Promise<DimensionBenchmarkResult[]> {
    const currentResult = await this.calculateScore({ sessionId });
    return this.analytics.getDimensionBenchmarks(currentResult);
  }

  // === Cache & persistence helpers ===

  private async cacheScore(sessionId: string, result: ReadinessScoreResult): Promise<void> {
    try {
      const cacheKey = `score:${sessionId}`;
      await this.redis.set(cacheKey, JSON.stringify(result), SCORE_CACHE_TTL);
    } catch (error) {
      this.logger.warn(`Failed to cache score for session ${sessionId}`, error);
    }
  }

  private async getCachedScore(sessionId: string): Promise<ReadinessScoreResult | null> {
    try {
      const cacheKey = `score:${sessionId}`;
      const cached = await this.redis.get(cacheKey);
      if (cached) {
        return JSON.parse(cached) as ReadinessScoreResult;
      }
    } catch (error) {
      this.logger.warn(`Failed to retrieve cached score for session ${sessionId}`, error);
    }
    return null;
  }

  private async saveScoreSnapshot(sessionId: string, result: ReadinessScoreResult): Promise<void> {
    try {
      await this.prisma.scoreSnapshot.create({
        data: {
          sessionId,
          score: new Decimal(result.score.toFixed(2)),
          portfolioResidual: new Decimal(result.portfolioResidual.toFixed(6)),
          completionPercentage: new Decimal(result.completionPercentage.toFixed(2)),
          dimensionBreakdown: result.dimensions.map((d) => ({
            dimensionKey: d.dimensionKey,
            residualRisk: d.residualRisk,
            weight: d.weight,
            answeredCount: d.answeredCount,
            questionCount: d.questionCount,
          })),
        },
      });
    } catch (error) {
      this.logger.warn(`Failed to save score snapshot for session ${sessionId}`, error);
    }
  }
}

/**
 * Scoring Analytics ÔÇö benchmark comparisons, score history, and trend analysis.
 * Instantiated internally by ScoringEngineService (not via DI).
 */
import { NotFoundException } from '@nestjs/common';
import { PrismaService } from '@libs/database';
import { DimensionResidual, ReadinessScoreResult } from '../dto';
import {
  DEFAULT_SEVERITY,
  ScoreSnapshot,
  ScoreHistoryResult,
  BenchmarkResult,
  DimensionBenchmarkResult,
} from '../scoring-types';
import { calculateTrendAnalysis, generateDimensionRecommendation } from '../scoring-calculator';

export class ScoringAnalyticsService {
  constructor(private readonly prisma: PrismaService) {}

  /**
   * Get score history for a session.
   * Returns historical score snapshots for trend analysis.
   */
  async getScoreHistory(sessionId: string, limit: number = 10): Promise<ScoreHistoryResult> {
    const session = await this.prisma.session.findUnique({
      where: { id: sessionId },
      select: {
        id: true,
        readinessScore: true,
        startedAt: true,
        lastScoreCalculation: true,
      },
    });

    if (!session) {
      throw new NotFoundException(`Session not found: ${sessionId}`);
    }

    const currentScore = session.readinessScore ? Number(session.readinessScore) : 0;

    const snapshots = await this.prisma.scoreSnapshot.findMany({
      where: { sessionId },
      orderBy: { createdAt: 'desc' },
      take: limit,
    });

    const history: ScoreSnapshot[] =
      snapshots.length > 0
        ? snapshots.map((s) => ({
            timestamp: s.createdAt,
            score: Number(s.score),
            portfolioResidual: Number(s.portfolioResidual),
            completionPercentage: Number(s.completionPercentage),
          }))
        : [
            {
              timestamp: session.lastScoreCalculation || session.startedAt,
              score: currentScore,
              portfolioResidual: 0,
              completionPercentage: 0,
            },
          ];

    const trend = calculateTrendAnalysis(history);

    return { sessionId, currentScore, history, trend };
  }

  /**
   * Get industry benchmark comparison.
   * Compares session score against industry averages.
   */
  async getIndustryBenchmark(sessionId: string, industryCode?: string): Promise<BenchmarkResult> {
    const session = await this.prisma.session.findUnique({
      where: { id: sessionId },
      include: { questionnaire: true },
    });

    if (!session) {
      throw new NotFoundException(`Session not found: ${sessionId}`);
    }

    const currentScore = session.readinessScore ? Number(session.readinessScore) : 0;
    const industry =
      industryCode ||
      ((session.questionnaire?.metadata as Record<string, unknown>)?.industry as string) ||
      'general';

    const stats = await this.prisma.$queryRaw<
      Array<{
        avg_score: number;
        min_score: number;
        max_score: number;
        count: bigint;
        percentile_25: number;
        percentile_50: number;
        percentile_75: number;
      }>
    >`
      WITH industry_sessions AS (
          SELECT s.readiness_score
          FROM sessions s
          JOIN questionnaires q ON s.questionnaire_id = q.id
          WHERE s.readiness_score IS NOT NULL
          AND s.status = 'COMPLETED'
          AND (
              q.metadata->>'industry' = ${industry}
              OR ${industry} = 'general'
          )
      )
      SELECT 
          COALESCE(AVG(readiness_score), 0) as avg_score,
          COALESCE(MIN(readiness_score), 0) as min_score,
          COALESCE(MAX(readiness_score), 0) as max_score,
          COUNT(*) as count,
          COALESCE(PERCENTILE_CONT(0.25) WITHIN GROUP (ORDER BY readiness_score), 0) as percentile_25,
          COALESCE(PERCENTILE_CONT(0.50) WITHIN GROUP (ORDER BY readiness_score), 0) as percentile_50,
          COALESCE(PERCENTILE_CONT(0.75) WITHIN GROUP (ORDER BY readiness_score), 0) as percentile_75
      FROM industry_sessions
    `;

    const benchmarkStats = stats[0] || {
      avg_score: 50,
      min_score: 0,
      max_score: 100,
      count: BigInt(0),
      percentile_25: 25,
      percentile_50: 50,
      percentile_75: 75,
    };

    const percentileRank = await this.calculatePercentileRank(currentScore, industry);

    let performanceCategory: 'LEADING' | 'ABOVE_AVERAGE' | 'AVERAGE' | 'BELOW_AVERAGE' | 'LAGGING';
    if (currentScore >= Number(benchmarkStats.percentile_75)) {
      performanceCategory = 'LEADING';
    } else if (currentScore >= Number(benchmarkStats.percentile_50)) {
      performanceCategory = 'ABOVE_AVERAGE';
    } else if (currentScore >= Number(benchmarkStats.percentile_25)) {
      performanceCategory = 'AVERAGE';
    } else if (currentScore >= Number(benchmarkStats.min_score)) {
      performanceCategory = 'BELOW_AVERAGE';
    } else {
      performanceCategory = 'LAGGING';
    }

    return {
      sessionId,
      currentScore,
      industry,
      benchmark: {
        average: Math.round(Number(benchmarkStats.avg_score) * 100) / 100,
        median: Math.round(Number(benchmarkStats.percentile_50) * 100) / 100,
        min: Math.round(Number(benchmarkStats.min_score) * 100) / 100,
        max: Math.round(Number(benchmarkStats.max_score) * 100) / 100,
        percentile25: Math.round(Number(benchmarkStats.percentile_25) * 100) / 100,
        percentile75: Math.round(Number(benchmarkStats.percentile_75) * 100) / 100,
        sampleSize: Number(benchmarkStats.count),
      },
      percentileRank,
      performanceCategory,
      gapToMedian: Math.round((currentScore - Number(benchmarkStats.percentile_50)) * 100) / 100,
      gapToLeading: Math.round((Number(benchmarkStats.percentile_75) - currentScore) * 100) / 100,
    };
  }

  /**
   * Get dimension-level benchmark comparison.
   * Caller must provide current scoring result (avoids circular dependency).
   */
  async getDimensionBenchmarks(currentResult: ReadinessScoreResult): Promise<DimensionBenchmarkResult[]> {
    const dimensionAverages = await this.prisma.$queryRaw<
      Array<{
        dimension_key: string;
        avg_residual: number;
        count: bigint;
      }>
    >`
      WITH completed_responses AS (
          SELECT
              q.dimension_key,
              q.severity,
              r.coverage,
              r.session_id
          FROM responses r
          JOIN questions q ON r.question_id = q.id
          JOIN sessions s ON r.session_id = s.id
          WHERE s.status = 'COMPLETED'
          AND s.readiness_score IS NOT NULL
          AND q.dimension_key IS NOT NULL
      ),
      dimension_residuals AS (
          SELECT
              dimension_key,
              session_id,
              CASE WHEN SUM(COALESCE(severity, ${DEFAULT_SEVERITY})) > 0
                  THEN SUM(COALESCE(severity, ${DEFAULT_SEVERITY}) * (1 - COALESCE(coverage, 0)))
                       / SUM(COALESCE(severity, ${DEFAULT_SEVERITY}))
                  ELSE 0
              END as residual_risk
          FROM completed_responses
          GROUP BY dimension_key, session_id
      )
      SELECT
          dimension_key,
          AVG(residual_risk) as avg_residual,
          COUNT(DISTINCT session_id) as count
      FROM dimension_residuals
      GROUP BY dimension_key
    `;

    const benchmarkMap = new Map<string, number>(
      dimensionAverages.map((d: { dimension_key: string; avg_residual: number }) => [
        d.dimension_key,
        Number(d.avg_residual),
      ]),
    );

    return currentResult.dimensions.map((dim: DimensionResidual) => {
      const industryAvgResidual = Number(benchmarkMap.get(dim.dimensionKey) ?? 0.5);
      const gapToAverage = dim.residualRisk - industryAvgResidual;

      return {
        dimensionKey: dim.dimensionKey,
        displayName: dim.displayName,
        currentResidual: dim.residualRisk,
        industryAverageResidual: Math.round(industryAvgResidual * 10000) / 10000,
        gapToAverage: Math.round(gapToAverage * 10000) / 10000,
        performance: gapToAverage < -0.1 ? ('ABOVE' as const) : gapToAverage > 0.1 ? ('BELOW' as const) : ('AVERAGE' as const),
        recommendation: generateDimensionRecommendation(dim, gapToAverage),
      };
    });
  }

  /** Calculate percentile rank for a score within an industry */
  private async calculatePercentileRank(score: number, industry: string): Promise<number> {
    const result = await this.prisma.$queryRaw<Array<{ percentile_rank: number }>>`
      WITH industry_sessions AS (
          SELECT s.readiness_score
          FROM sessions s
          JOIN questionnaires q ON s.questionnaire_id = q.id
          WHERE s.readiness_score IS NOT NULL
          AND s.status = 'COMPLETED'
          AND (
              q.metadata->>'industry' = ${industry}
              OR ${industry} = 'general'
          )
      )
      SELECT 
          COALESCE(
              (COUNT(*) FILTER (WHERE readiness_score <= ${score})::float / 
              NULLIF(COUNT(*), 0) * 100),
              50
          ) as percentile_rank
      FROM industry_sessions
    `;

    return Math.round((result[0]?.percentile_rank ?? 50) * 10) / 10;
  }
}

/**
 * SessionMutationService ÔÇö write operations for sessions.
 * Extracted from SessionService to reduce file size.
 */
import {
  BadRequestException,
  ForbiddenException,
  NotFoundException,
} from '@nestjs/common';
import { SessionStatus, Prisma, Question } from '@prisma/client';
import { PrismaService } from '@libs/database';
import { QuestionnaireService, QuestionResponse } from '../../questionnaire/questionnaire.service';
import { AdaptiveLogicService } from '../../adaptive-logic/adaptive-logic.service';
import { ScoringEngineService } from '../../scoring-engine/scoring-engine.service';
import { CreateSessionDto } from '../dto/create-session.dto';
import { SubmitResponseDto } from '../dto/submit-response.dto';
import {
  SessionResponse,
  SubmitResponseResult,
  ContinueSessionResponse,
  READINESS_SCORE_THRESHOLD,
} from '../session-types';
import {
  getSessionWithValidation,
  isReadinessGatedSession,
  mapToSessionResponse,
  mapQuestionToResponse,
  calculateProgress,
  validateResponse,
  findNextUnansweredQuestion,
} from '../session-helpers';
import type { SessionQueryService } from './session-query.service';

export class SessionMutationService {
  private queryService!: SessionQueryService;

  constructor(
    private readonly prisma: PrismaService,
    private readonly questionnaireService: QuestionnaireService,
    private readonly adaptiveLogicService: AdaptiveLogicService,
    private readonly scoringEngineService: ScoringEngineService,
  ) {}

  /** Called by SessionService after both sub-services are instantiated */
  setQueryService(qs: SessionQueryService): void {
    this.queryService = qs;
  }

  async create(userId: string, dto: CreateSessionDto): Promise<SessionResponse> {
    const questionnaire = await this.questionnaireService.findById(dto.questionnaireId);
    const personaQuestions = dto.persona
      ? await this.questionnaireService.getQuestionsForPersona(dto.questionnaireId, dto.persona)
      : null;
    const totalQuestions = personaQuestions
      ? personaQuestions.length
      : await this.questionnaireService.getTotalQuestionCount(dto.questionnaireId);

    const firstPersonaQuestion = personaQuestions?.[0];
    const firstSection = questionnaire.sections[0];
    const firstQuestion = firstSection?.questions?.[0];
    const initialQuestionId = firstPersonaQuestion?.id ?? firstQuestion?.id;
    const initialSectionId = firstPersonaQuestion?.sectionId ?? firstSection?.id;

    const session = await this.prisma.session.create({
      data: {
        userId,
        questionnaireId: dto.questionnaireId,
        questionnaireVersion: questionnaire.version,
        projectTypeId: dto.projectTypeId,
        ideaCaptureId: dto.ideaCaptureId,
        persona: dto.persona,
        industry: dto.industry,
        status: SessionStatus.IN_PROGRESS,
        progress: { percentage: 0, answered: 0, total: totalQuestions },
        currentSectionId: initialSectionId,
        currentQuestionId: initialQuestionId,
        adaptiveState: {
          activeQuestionIds: [],
          skippedQuestionIds: [],
          branchHistory: [],
        },
      },
      include: {
        currentSection: true,
        projectType: { select: { name: true, slug: true } },
      },
    });
    return mapToSessionResponse(session, totalQuestions);
  }

  async submitResponse(
    sessionId: string,
    userId: string,
    dto: SubmitResponseDto,
  ): Promise<SubmitResponseResult> {
    const session = await getSessionWithValidation(this.prisma, sessionId, userId);
    if (session.status === SessionStatus.COMPLETED) {
      throw new BadRequestException('Session is already completed');
    }

    const question = await this.questionnaireService.getQuestionById(dto.questionId);
    if (!question) {
      throw new NotFoundException('Question not found');
    }
    const validation = validateResponse(question, dto.value);

    const response = await this.prisma.response.upsert({
      where: { sessionId_questionId: { sessionId, questionId: dto.questionId } },
      create: {
        sessionId,
        questionId: dto.questionId,
        value: JSON.parse(JSON.stringify(dto.value)),
        isValid: validation.isValid,
        validationErrors: validation.errors ? { errors: validation.errors } : Prisma.JsonNull,
        timeSpentSeconds: dto.timeSpentSeconds,
      },
      update: {
        value: JSON.parse(JSON.stringify(dto.value)),
        isValid: validation.isValid,
        validationErrors: validation.errors ? { errors: validation.errors } : Prisma.JsonNull,
        timeSpentSeconds: dto.timeSpentSeconds,
        revision: { increment: 1 },
      },
    });

    const allResponses = await this.prisma.response.findMany({
      where: { sessionId },
      take: 1000,
    });
    const responseMap = new Map(allResponses.map((r) => [r.questionId, r.value]));
    const visibleQuestions = await this.adaptiveLogicService.getVisibleQuestions(
      session.questionnaireId,
      responseMap,
    );

    // Recalculate score after every response
    await this.scoringEngineService.invalidateScoreCache(sessionId);
    const scoreResult = await this.scoringEngineService.calculateScore({ sessionId });

    // NQS: pick the next highest-impact question
    let nqsNext:
      | { questionId: string; text: string; dimensionKey: string; expectedScoreLift: number }
      | undefined;
    const nqsResult = await this.scoringEngineService.getNextQuestions({ sessionId, limit: 1 });
    if (nqsResult.questions.length > 0) {
      const topQ = nqsResult.questions[0];
      nqsNext = {
        questionId: topQ.questionId,
        text: topQ.text,
        dimensionKey: topQ.dimensionKey,
        expectedScoreLift: topQ.expectedScoreLift,
      };
    }

    const nqsQuestion = nqsNext
      ? visibleQuestions.find((q) => q.id === nqsNext.questionId)
      : null;
    const nextQuestion =
      nqsQuestion ?? findNextUnansweredQuestion(visibleQuestions, dto.questionId, responseMap);
    const progress = calculateProgress(allResponses.length, visibleQuestions.length);

    await this.prisma.session.update({
      where: { id: sessionId },
      data: {
        currentQuestionId: nextQuestion?.id,
        currentSectionId: nextQuestion?.sectionId,
        lastActivityAt: new Date(),
        progress: {
          percentage: progress.percentage,
          answered: progress.answeredQuestions,
          total: progress.totalQuestions,
        },
      },
    });

    return {
      responseId: response.id,
      questionId: dto.questionId,
      value: dto.value,
      validationResult: validation,
      readinessScore: scoreResult.score,
      nextQuestionByNQS: nqsNext,
      progress,
      createdAt: response.answeredAt,
    };
  }

  async completeSession(sessionId: string, userId: string): Promise<SessionResponse> {
    const session = await getSessionWithValidation(this.prisma, sessionId, userId);
    if (session.status === SessionStatus.COMPLETED) {
      throw new BadRequestException('Session is already completed');
    }
    const scoreResult = await this.scoringEngineService.calculateScore({ sessionId });
    const requiresGate = await isReadinessGatedSession(this.prisma, session);
    if (requiresGate && scoreResult.score < READINESS_SCORE_THRESHOLD) {
      throw new BadRequestException(
        `Readiness score is ${scoreResult.score.toFixed(1)}%. ` +
          `A minimum score of ${READINESS_SCORE_THRESHOLD}% is required to complete this assessment. ` +
          `Please continue answering questions to improve coverage.`,
      );
    }
    const updatedSession = await this.prisma.session.update({
      where: { id: sessionId },
      data: { status: SessionStatus.COMPLETED, completedAt: new Date() },
      include: { currentSection: true, questionnaire: true },
    });
    const totalQuestions = await this.questionnaireService.getTotalQuestionCount(
      session.questionnaireId,
      session.persona ?? undefined,
    );
    return mapToSessionResponse(updatedSession, totalQuestions);
  }

  async continueSession(
    sessionId: string,
    userId: string,
    questionCount: number = 1,
  ): Promise<ContinueSessionResponse> {
    const session = await this.prisma.session.findUnique({
      where: { id: sessionId },
      include: {
        currentSection: true,
        questionnaire: { include: { sections: { orderBy: { orderIndex: 'asc' } } } },
      },
    });
    if (!session) {throw new NotFoundException('Session not found');}
    if (session.userId !== userId) {throw new ForbiddenException('Access denied to this session');}

    const isComplete = session.status === SessionStatus.COMPLETED;
    const responses = await this.prisma.response.findMany({
      where: { sessionId },
      take: 1000,
      orderBy: { answeredAt: 'desc' },
    });
    const responseMap = new Map(responses.map((r) => [r.questionId, r.value]));
    const visibleQuestions = await this.adaptiveLogicService.getVisibleQuestions(
      session.questionnaireId,
      responseMap,
    );
    const adaptiveState = session.adaptiveState as {
      skippedQuestionIds?: string[];
      branchHistory?: string[];
    };
    const totalQuestionsInQuestionnaire = await this.questionnaireService.getTotalQuestionCount(
      session.questionnaireId,
      session.persona ?? undefined,
    );
    const skippedCount = totalQuestionsInQuestionnaire - visibleQuestions.length;

    // Find next unanswered questions
    const nextQuestions = this.findNextUnansweredBatch(
      visibleQuestions, session.currentQuestionId, responseMap, isComplete, questionCount,
    );

    // Section completion
    const allSections = session.questionnaire.sections;
    const { completedSectionsCount } =
      this.buildSectionCompletionStatus(allSections, visibleQuestions, responseMap);
    const progress = calculateProgress(responses.length, visibleQuestions.length, {
      totalSections: allSections.length,
      completedSections: completedSectionsCount,
    });

    // Current section info
    const currentSectionInfo = this.buildCurrentSectionInfo(
      session.currentSection, visibleQuestions, responseMap,
    );

    // Readiness score
    let readinessScore: number | undefined;
    if (responses.length > 0) {
      try {
        const scoreResult = await this.scoringEngineService.calculateScore({ sessionId });
        readinessScore = scoreResult.score;
      } catch { /* Score calculation may fail if no dimensions mapped */ }
    }

    const unansweredRequired = visibleQuestions.filter((q) => q.isRequired && !responseMap.has(q.id));
    const requiresGate = await isReadinessGatedSession(this.prisma, session);
    const meetsReadinessGate = !requiresGate || (readinessScore ?? 0) >= READINESS_SCORE_THRESHOLD;
    const canComplete = unansweredRequired.length === 0 && responses.length > 0 && meetsReadinessGate;

    const sessionResponse: SessionResponse = {
      id: session.id,
      questionnaireId: session.questionnaireId,
      userId: session.userId,
      status: session.status,
      persona: session.persona ?? undefined,
      industry: session.industry ?? undefined,
      readinessScore: readinessScore ?? (session.readinessScore ? Number(session.readinessScore) : undefined),
      progress,
      currentSection: session.currentSection
        ? { id: session.currentSection.id, name: session.currentSection.name }
        : undefined,
      createdAt: session.startedAt,
      lastActivityAt: session.lastActivityAt,
    };

    if (!isComplete) {
      await this.prisma.session.update({ where: { id: sessionId }, data: { lastActivityAt: new Date() } });
    }

    return {
      session: sessionResponse, nextQuestions, currentSection: currentSectionInfo,
      overallProgress: progress, readinessScore,
      adaptiveState: {
        visibleQuestionCount: visibleQuestions.length,
        skippedQuestionCount: skippedCount,
        appliedRules: adaptiveState.branchHistory || [],
      },
      isComplete, canComplete,
    };
  }

  async cloneSession(
    sourceSessionId: string,
    userId: string,
    options?: { copyResponses?: boolean; industry?: string },
  ): Promise<SessionResponse> {
    const sourceSession = await getSessionWithValidation(this.prisma, sourceSessionId, userId);
    const dto: CreateSessionDto = {
      questionnaireId: sourceSession.questionnaireId,
      persona: sourceSession.persona ?? undefined,
      industry: options?.industry ?? sourceSession.industry ?? undefined,
    };
    const newSession = await this.create(userId, dto);

    if (options?.copyResponses) {
      const responses = await this.prisma.response.findMany({
        where: { sessionId: sourceSessionId },
        take: 1000,
      });
      await this.prisma.response.createMany({
        data: responses.map((r) => ({
          sessionId: newSession.id,
          questionId: r.questionId,
          value: r.value ?? Prisma.JsonNull,
          isValid: r.isValid,
          validationErrors: r.validationErrors ?? Prisma.JsonNull,
        })),
      });
      const totalQuestions = await this.questionnaireService.getTotalQuestionCount(
        sourceSession.questionnaireId,
        sourceSession.persona ?? undefined,
      );
      const progress = calculateProgress(responses.length, totalQuestions);
      await this.prisma.session.update({
        where: { id: newSession.id },
        data: {
          progress: {
            percentage: progress.percentage,
            answered: progress.answeredQuestions,
            total: progress.totalQuestions,
          },
        },
      });
    }
    return this.queryService.findById(newSession.id, userId);
  }

  async archiveSession(sessionId: string, userId: string): Promise<void> {
    await getSessionWithValidation(this.prisma, sessionId, userId);
    await this.prisma.session.update({
      where: { id: sessionId },
      data: { status: SessionStatus.ABANDONED },
    });
  }

  async restoreSession(sessionId: string, userId: string): Promise<SessionResponse> {
    const session = await getSessionWithValidation(this.prisma, sessionId, userId);
    if (session.status !== SessionStatus.ABANDONED) {
      throw new BadRequestException('Only archived sessions can be restored');
    }
    const updatedSession = await this.prisma.session.update({
      where: { id: sessionId },
      data: { status: SessionStatus.IN_PROGRESS },
      include: { currentSection: true },
    });
    const totalQuestions = await this.questionnaireService.getTotalQuestionCount(
      session.questionnaireId,
      session.persona ?? undefined,
    );
    return mapToSessionResponse(updatedSession, totalQuestions);
  }

  async bulkDeleteSessions(
    userId: string,
    sessionIds: string[],
  ): Promise<{ deleted: number; failed: string[] }> {
    const result = { deleted: 0, failed: [] as string[] };
    for (const sessionId of sessionIds) {
      try {
        await getSessionWithValidation(this.prisma, sessionId, userId);
        await this.prisma.response.deleteMany({ where: { sessionId } });
        await this.prisma.session.delete({ where: { id: sessionId } });
        result.deleted++;
      } catch {
        result.failed.push(sessionId);
      }
    }
    return result;
  }

  /**
   * Find next batch of unanswered questions starting from current position.
   */
  private findNextUnansweredBatch(
    visibleQuestions: Question[],
    currentQuestionId: string | null,
    responseMap: Map<string, unknown>,
    isComplete: boolean,
    questionCount: number,
  ): QuestionResponse[] {
    const result: QuestionResponse[] = [];
    if (isComplete || !currentQuestionId) {
      return result;
    }
    const currentIndex = visibleQuestions.findIndex((q) => q.id === currentQuestionId);
    for (
      let i = Math.max(0, currentIndex);
      i < visibleQuestions.length && result.length < questionCount;
      i++
    ) {
      if (!responseMap.has(visibleQuestions[i].id)) {
        result.push(mapQuestionToResponse(visibleQuestions[i]));
      }
    }
    if (result.length < questionCount) {
      for (let i = 0; i < currentIndex && result.length < questionCount; i++) {
        if (!responseMap.has(visibleQuestions[i].id)) {
          result.push(mapQuestionToResponse(visibleQuestions[i]));
        }
      }
    }
    return result;
  }

  /**
   * Build section completion status for all sections.
   */
  private buildSectionCompletionStatus(
    allSections: { id: string }[],
    visibleQuestions: { id: string; sectionId: string }[],
    responseMap: Map<string, unknown>,
  ): { sectionCompletionStatus: { sectionId: string; total: number; answered: number; isComplete: boolean }[]; completedSectionsCount: number } {
    const sectionCompletionStatus = allSections.map((section) => {
      const sq = visibleQuestions.filter((q) => q.sectionId === section.id);
      const sa = sq.filter((q) => responseMap.has(q.id)).length;
      return { sectionId: section.id, total: sq.length, answered: sa, isComplete: sq.length > 0 && sa === sq.length };
    });
    const completedSectionsCount = sectionCompletionStatus.filter((s) => s.isComplete).length;
    return { sectionCompletionStatus, completedSectionsCount };
  }

  /**
   * Build current section info for the session response.
   */
  private buildCurrentSectionInfo(
    currentSection: { id: string; name: string } | null,
    visibleQuestions: { id: string; sectionId: string }[],
    responseMap: Map<string, unknown>,
  ): { id: string; name: string; description: string | undefined; progress: number; questionsInSection: number; answeredInSection: number } {
    if (!currentSection) {
      return { id: '', name: '', description: undefined, progress: 0, questionsInSection: 0, answeredInSection: 0 };
    }
    const sq = visibleQuestions.filter((q) => q.sectionId === currentSection.id);
    const sa = sq.filter((q) => responseMap.has(q.id)).length;
    return {
      id: currentSection.id,
      name: currentSection.name,
      description: (currentSection as { description?: string | null }).description ?? undefined,
      progress: sq.length > 0 ? Math.round((sa / sq.length) * 100) : 0,
      questionsInSection: sq.length,
      answeredInSection: sa,
    };
  }
}

/**
 * SessionQueryService ÔÇö read-only session operations.
 * Extracted from SessionService to reduce file size.
 */
import { BadRequestException, NotFoundException, ForbiddenException } from '@nestjs/common';
import { SessionStatus } from '@prisma/client';
import { PrismaService } from '@libs/database';
import { QuestionnaireService, QuestionResponse } from '../../questionnaire/questionnaire.service';
import { AdaptiveLogicService } from '../../adaptive-logic/adaptive-logic.service';
import { PaginationDto } from '@libs/shared';
import {
  SessionResponse,
  NextQuestionResponse,
  SessionAnalytics,
  UserSessionStats,
  SessionExport,
} from '../session-types';
import {
  getSessionWithValidation,
  mapToSessionResponse,
  mapQuestionToResponse,
  calculateProgress,
} from '../session-helpers';

export class SessionQueryService {
  constructor(
    private readonly prisma: PrismaService,
    private readonly questionnaireService: QuestionnaireService,
    private readonly adaptiveLogicService: AdaptiveLogicService,
  ) {}

  async findById(sessionId: string, userId: string): Promise<SessionResponse> {
    const session = await this.prisma.session.findUnique({
      where: { id: sessionId },
      include: {
        currentSection: true,
        questionnaire: true,
        projectType: { select: { name: true, slug: true } },
      },
    });
    if (!session) {
      throw new NotFoundException('Session not found');
    }
    if (session.userId !== userId) {
      throw new ForbiddenException('Access denied to this session');
    }
    const totalQuestions = await this.questionnaireService.getTotalQuestionCount(
      session.questionnaireId,
      session.persona ?? undefined,
    );
    return mapToSessionResponse(session, totalQuestions);
  }

  async findAllByUser(
    userId: string,
    pagination: PaginationDto,
    status?: SessionStatus,
  ): Promise<{ items: SessionResponse[]; total: number }> {
    const where = { userId, ...(status && { status }) };
    const [sessions, total] = await Promise.all([
      this.prisma.session.findMany({
        where,
        skip: pagination.skip,
        take: pagination.limit,
        orderBy: { startedAt: 'desc' },
        include: {
          currentSection: true,
          questionnaire: true,
          projectType: { select: { name: true, slug: true } },
        },
      }),
      this.prisma.session.count({ where }),
    ]);
    const items = await Promise.all(
      sessions.map(async (session) => {
        const totalQuestions = await this.questionnaireService.getTotalQuestionCount(
          session.questionnaireId,
          session.persona ?? undefined,
        );
        return mapToSessionResponse(session, totalQuestions);
      }),
    );
    return { items, total };
  }

  async getNextQuestion(
    sessionId: string,
    userId: string,
    count: number = 1,
  ): Promise<NextQuestionResponse> {
    const session = await getSessionWithValidation(this.prisma, sessionId, userId);
    if (session.status === SessionStatus.COMPLETED) {
      throw new BadRequestException('Session is already completed');
    }

    const responses = await this.prisma.response.findMany({
      where: { sessionId },
      take: 1000,
    });
    const responseMap = new Map(responses.map((r) => [r.questionId, r.value]));

    if (!session.currentQuestionId) {
      throw new NotFoundException('No current question set for this session');
    }
    const currentQuestion = await this.questionnaireService.getQuestionById(
      session.currentQuestionId,
    );
    if (!currentQuestion) {
      throw new NotFoundException('Current question not found');
    }

    const visibleQuestions = await this.adaptiveLogicService.getVisibleQuestions(
      session.questionnaireId,
      responseMap,
    );

    const nextQuestions: QuestionResponse[] = [];
    const currentIndex = visibleQuestions.findIndex((q) => q.id === session.currentQuestionId);
    for (let i = currentIndex; i < visibleQuestions.length && nextQuestions.length < count; i++) {
      const question = visibleQuestions[i];
      if (question && !responseMap.has(question.id)) {
        nextQuestions.push(mapQuestionToResponse(question));
      }
    }

    const progress = calculateProgress(responses.length, visibleQuestions.length);
    const section = await this.prisma.section.findUnique({
      where: { id: currentQuestion.sectionId },
    });
    const sectionQuestions = visibleQuestions.filter(
      (q) => q.sectionId === currentQuestion.sectionId,
    );
    const sectionAnswered = sectionQuestions.filter((q) => responseMap.has(q.id)).length;
    const sectionProgress =
      sectionQuestions.length > 0
        ? Math.round((sectionAnswered / sectionQuestions.length) * 100)
        : 0;

    return {
      questions: nextQuestions,
      section: { id: section!.id, name: section!.name, progress: sectionProgress },
      overallProgress: progress,
    };
  }

  async getSessionAnalytics(sessionId: string, userId: string): Promise<SessionAnalytics> {
    const session = await getSessionWithValidation(this.prisma, sessionId, userId);
    const responses = await this.prisma.response.findMany({
      where: { sessionId },
      take: 1000,
      include: {
        question: { include: { section: true, dimension: true } },
      },
    });

    // Time statistics
    const timesSpent = responses
      .filter((r) => r.timeSpentSeconds !== null)
      .map((r) => Number(r.timeSpentSeconds));
    const totalTimeSpent = timesSpent.reduce((sum, t) => sum + t, 0);
    const avgTimePerQuestion = timesSpent.length > 0 ? totalTimeSpent / timesSpent.length : 0;

    // Section data
    const sections = await this.prisma.section.findMany({
      where: { questionnaireId: session.questionnaireId },
      take: 1000,
      include: { _count: { select: { questions: true } } },
    });
    const sectionQuestionCounts = new Map(sections.map((s) => [s.name, s._count.questions]));

    const bySection: Record<string, { answered: number; total: number; avgTime: number }> = {};
    const sectionTimes: Record<string, number[]> = {};
    responses.forEach((r) => {
      const sectionName = r.question.section?.name || 'Unknown';
      if (!bySection[sectionName]) {
        bySection[sectionName] = {
          answered: 0,
          total: sectionQuestionCounts.get(sectionName) ?? 0,
          avgTime: 0,
        };
        sectionTimes[sectionName] = [];
      }
      bySection[sectionName].answered++;
      if (r.timeSpentSeconds) {
        sectionTimes[sectionName].push(Number(r.timeSpentSeconds));
      }
    });
    for (const s of sections) {
      if (!bySection[s.name]) {
        bySection[s.name] = { answered: 0, total: s._count.questions, avgTime: 0 };
      }
    }
    Object.keys(bySection).forEach((section) => {
      const times = sectionTimes[section] || [];
      bySection[section].avgTime =
        times.length > 0 ? times.reduce((a, b) => a + b, 0) / times.length : 0;
    });

    // Dimension data
    const byDimension: Record<string, { answered: number; coverage: number }> = {};
    responses.forEach((r) => {
      const dimKey = r.question.dimension?.key || 'unknown';
      if (!byDimension[dimKey]) {
        byDimension[dimKey] = { answered: 0, coverage: 0 };
      }
      byDimension[dimKey].answered++;
      if (r.coverage) {
        byDimension[dimKey].coverage += Number(r.coverage);
      }
    });
    Object.keys(byDimension).forEach((dim) => {
      if (byDimension[dim].answered > 0) {
        byDimension[dim].coverage /= byDimension[dim].answered;
      }
    });

    const validResponses = responses.filter((r) => r.isValid).length;
    const totalQuestions = await this.questionnaireService.getTotalQuestionCount(
      session.questionnaireId,
      session.persona ?? undefined,
    );
    const completionRate =
      totalQuestions > 0 ? Math.round((responses.length / totalQuestions) * 100) : 0;

    return {
      sessionId,
      totalResponses: responses.length,
      validResponses,
      invalidResponses: responses.length - validResponses,
      totalTimeSpent,
      averageTimePerQuestion: Math.round(avgTimePerQuestion),
      bySection,
      byDimension,
      completionRate,
      analyzedAt: new Date(),
    };
  }

  async getUserSessionStats(userId: string): Promise<UserSessionStats> {
    const sessions = await this.prisma.session.findMany({
      where: { userId },
      take: 1000,
      select: {
        id: true,
        status: true,
        startedAt: true,
        completedAt: true,
        readinessScore: true,
      },
    });
    const completed = sessions.filter((s) => s.status === SessionStatus.COMPLETED);
    const inProgress = sessions.filter(
      (s) => String(s.status) === String(SessionStatus.IN_PROGRESS),
    );
    const archived = sessions.filter(
      (s) => String(s.status) === String(SessionStatus.ABANDONED),
    );
    const scores = completed
      .filter((s) => s.readinessScore !== null)
      .map((s) => Number(s.readinessScore));
    const avgScore = scores.length > 0 ? scores.reduce((a, b) => a + b, 0) / scores.length : 0;
    const highestScore = scores.length > 0 ? Math.max(...scores) : 0;
    const lowestScore = scores.length > 0 ? Math.min(...scores) : 0;

    const completionTimes = completed
      .filter((s) => s.completedAt && s.startedAt)
      .map((s) => s.completedAt!.getTime() - s.startedAt.getTime());
    const avgCompletionTime =
      completionTimes.length > 0
        ? completionTimes.reduce((a, b) => a + b, 0) / completionTimes.length
        : 0;

    return {
      userId,
      totalSessions: sessions.length,
      completedSessions: completed.length,
      inProgressSessions: inProgress.length,
      archivedSessions: archived.length,
      averageScore: Math.round(avgScore * 100) / 100,
      highestScore: Math.round(highestScore * 100) / 100,
      lowestScore: Math.round(lowestScore * 100) / 100,
      averageCompletionTimeMs: Math.round(avgCompletionTime),
      scoreImprovement:
        scores.length >= 2
          ? Math.round((scores[scores.length - 1] - scores[0]) * 100) / 100
          : 0,
      analyzedAt: new Date(),
    };
  }

  async exportSession(sessionId: string, userId: string): Promise<SessionExport> {
    const session = await this.prisma.session.findUnique({
      where: { id: sessionId },
      include: {
        questionnaire: { select: { id: true, name: true, version: true } },
        responses: true,
      },
    });
    if (!session) {
      throw new NotFoundException('Session not found');
    }
    if (session.userId !== userId) {
      throw new ForbiddenException('Access denied');
    }
    return {
      exportVersion: '1.0',
      exportedAt: new Date(),
      session: {
        id: session.id,
        questionnaireId: session.questionnaireId,
        questionnaireName: session.questionnaire.name,
        questionnaireVersion: session.questionnaireVersion,
        status: session.status,
        industry: session.industry,
        startedAt: session.startedAt,
        completedAt: session.completedAt,
        readinessScore: session.readinessScore ? Number(session.readinessScore) : null,
        progress: session.progress as Record<string, unknown>,
      },
      responses: session.responses.map((r) => ({
        questionId: r.questionId,
        value: r.value,
        coverage: r.coverage ? Number(r.coverage) : null,
        isValid: r.isValid,
        answeredAt: r.answeredAt,
        timeSpentSeconds: r.timeSpentSeconds,
      })),
    };
  }
}
